-- Poems batch 465
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-22','邊城寓題','薛能','唐','御定全唐诗','yuding','','[]','孤蹇複飄零，天涯若墮螢。東風吹痼疾，暖日極青冥。',48,'御定全唐詩/json/560.json','["孤蹇複飄零，天涯若墮螢。東風吹痼疾，暖日極青冥。", "蠶市歸農醉，漁舟釣客醒。論邦苦不早，只此負王庭。"]'),
('yuding-23','春日江居寓懷','薛能','唐','御定全唐诗','yuding','','[]','歸興乍離邊，蘭橈複錦川。斫春槎枿樹，消雪土膏田。',48,'御定全唐詩/json/560.json','["歸興乍離邊，蘭橈複錦川。斫春槎枿樹，消雪土膏田。", "岸暖尋新菜，舟寒著舊綿。臨邛若個是，欲向酒家眠。"]'),
('yuding-24','邊城作','薛能','唐','御定全唐诗','yuding','','[]','行止象分符，監州是戲儒。管排蠻戶遠，出箐鳥巢孤。',48,'御定全唐詩/json/560.json','["行止象分符，監州是戲儒。管排蠻戶遠，出箐鳥巢孤。", "北向秦何在，南來蜀已無。懷沙悔不及，只有便乘桴。"]'),
('yuding-25','聞李夷遇下第東歸因以寄贈','薛能','唐','御定全唐诗','yuding','','[]','囊中書是居山寫，海畔家貧乞食還。吾子莫愁登第晚，',40,'御定全唐詩/json/560.json','["囊中書是居山寫，海畔家貧乞食還。吾子莫愁登第晚，", "從此樂章休敘戰，漢兵無陣亦無蠻。"]'),
('yuding-26','留題','薛能','唐','御定全唐诗','yuding','','[]','茶興複詩心，一甌還一吟。壓春甘蔗冷，喧雨荔枝深。',48,'御定全唐詩/json/560.json','["茶興複詩心，一甌還一吟。壓春甘蔗冷，喧雨荔枝深。", "驟去無遺恨，幽棲已遍尋。蛾眉不可到，高處望千岑。"]'),
('yuding-27','春日北歸舟中有懷','薛能','唐','御定全唐诗','yuding','','[]','盡日繞盤飧，歸舟向蜀門。雨幹楊柳渡，山熱杏花村。',48,'御定全唐詩/json/560.json','["盡日繞盤飧，歸舟向蜀門。雨幹楊柳渡，山熱杏花村。", "淨鏡空山曉，孤燈極浦昏。邊城不是意，回首未終恩。"]'),
('yuding-28','初發嘉州寓題','薛能','唐','御定全唐诗','yuding','','[]','勞我是犍為，南征又北移。唯聞杜鵑夜，不見海棠時。',48,'御定全唐詩/json/560.json','["勞我是犍為，南征又北移。唯聞杜鵑夜，不見海棠時。", "在闇曾無負，含靈合有知。州人若愛樹，莫損召南詩。"]'),
('yuding-29','題漢州西湖','薛能','唐','御定全唐诗','yuding','','[]','西湖天下名，可以濯吾纓。況是攜家賞，從妨半驛程。',72,'御定全唐詩/json/560.json','["西湖天下名，可以濯吾纓。況是攜家賞，從妨半驛程。", "嘗茶春味渴，斷酒晚懷清。盡得幽人趣，猶嫌守吏迎。", "重餐逢角暮，百事喜詩成。坐阻湘江謫，誰為話政聲。"]'),
('yuding-30','自廣漢遊三學山','薛能','唐','御定全唐诗','yuding','','[]','殘陽終日望棲賢，歸路攜家得訪禪。世缺一來應薄命，',40,'御定全唐詩/json/560.json','["殘陽終日望棲賢，歸路攜家得訪禪。世缺一來應薄命，", "猿鳥可知僧可會，此心常似有香煙。"]'),
('yuding-31','三學山開照寺','薛能','唐','御定全唐诗','yuding','','[]','盡室遍相將，中方上下方。夜深楠樹遠，春氣陌林香。',48,'御定全唐詩/json/560.json','["盡室遍相將，中方上下方。夜深楠樹遠，春氣陌林香。", "聖跡留岩險，靈燈出混茫。何因將慧劍，割愛事空王。"]'),
('yuding-32','雨霽北歸留題三學山','薛能','唐','御定全唐诗','yuding','','[]','遠樹平川半夕陽，錦城遙辨立危牆。閑思勝事多遺恨，',40,'御定全唐詩/json/560.json','["遠樹平川半夕陽，錦城遙辨立危牆。閑思勝事多遺恨，", "靈龕一望終何得，謬有人情滿蜀鄉。"]'),
('yuding-33','行次靈龕驛寄西蜀尚書','薛能','唐','御定全唐诗','yuding','','[]','北客推車指蜀門，幹陽知已近臨坤。從辭府郭常回首，',40,'御定全唐詩/json/560.json','["北客推車指蜀門，幹陽知已近臨坤。從辭府郭常回首，", "雷公解劚沖天氣，白日何辜遣戴盆。"]'),
('yuding-34','雨霽宿望喜驛','薛能','唐','御定全唐诗','yuding','','[]','風雷一罷思何清，江水依然浩浩聲。飛鳥旋生啼鳥在，',40,'御定全唐詩/json/560.json','["風雷一罷思何清，江水依然浩浩聲。飛鳥旋生啼鳥在，", "閑想更逢知舊否，館前楊柳種初成。"]'),
('yuding-35','籌筆驛','薛能','唐','御定全唐诗','yuding','','[]','葛相終宜馬革還，未開天意便開山。生欺仲達徒增氣，',40,'御定全唐詩/json/560.json','["葛相終宜馬革還，未開天意便開山。生欺仲達徒增氣，", "當初若欲酬三顧，何不無為似有鰥。"]'),
('yuding-36','通仙洞','薛能','唐','御定全唐诗','yuding','','[]','高龕險欲摧，百尺洞門開。白日仙何在，清風客暫來。',48,'御定全唐詩/json/560.json','["高龕險欲摧，百尺洞門開。白日仙何在，清風客暫來。", "臨崖松直上，避石水低回。賈掾曾空去，題詩豈易哉。"]'),
('yuding-37','嘉陵驛見賈島舊題','薛能','唐','御定全唐诗','yuding','','[]','賈子命堪悲，唐人獨解詩。左遷今已矣，清絕更無之。',48,'御定全唐詩/json/560.json','["賈子命堪悲，唐人獨解詩。左遷今已矣，清絕更無之。", "畢竟吾猶許，商量眾莫疑。嘉陵四十字，一一是天資。"]'),
('yuding-38','嘉陵驛','薛能','唐','御定全唐诗','yuding','','[]','江濤千疊閣千層，銜尾相隨盡室登。稠樹蔽山聞杜宇，',40,'御定全唐詩/json/560.json','["江濤千疊閣千層，銜尾相隨盡室登。稠樹蔽山聞杜宇，", "如此幸非名利切，益州來日合攜僧。"]'),
('yuding-39','嘉陵驛','薛能','唐','御定全唐诗','yuding','','[]','盡室可招魂，蠻餘出蜀門。雹涼隨雨氣，江熱傍山根。',48,'御定全唐詩/json/560.json','["盡室可招魂，蠻餘出蜀門。雹涼隨雨氣，江熱傍山根。", "蠶月繰絲路，農時碌碡村。幹將磨欲盡，無位可酬恩。"]'),
('yuding-40','西縣途中二十韻','薛能','唐','御定全唐诗','yuding','','[]','野客誤桑麻，從軍帶鏌鋣。豈論之白帝，未合過黃花。',264,'御定全唐詩/json/560.json','["野客誤桑麻，從軍帶鏌鋣。豈論之白帝，未合過黃花。", "落日投江縣，征塵漱齒牙。蜀音連井絡，秦分隔褒斜。", "硤路商逢使，山郵雀啅蛇。憶歸臨角黍，良遇得新瓜。", "食久庭陰轉，行多屐齒窪。氣清岩下瀑，煙漫雨餘畬。", "黃鳥當蠶候，稀蒿雜麥查。汗涼風似雪，漿度蜜如沙。", "野色生肥芋，鄉儀搗散茶。梯航經杜宇，烽候徹苴咩。", "逗石流何險，通關運固賒。葛侯真竭澤，劉主合亡家。", "陷彼貪功吠，貽為黷武誇。陣圖誰許可，廟貌我揄揶。", "閒事休征漢，斯行且詠巴。音繁來有鐸，軏盡去無車。", "溢目看風景，清懷嘯月華。焰樵烹紫筍，腰簟憩烏紗。", "杞國憂尋悟，臨邛渴自加。移文莫有誚，必不滯天涯。"]'),
('yuding-41','西縣作','薛能','唐','御定全唐诗','yuding','','[]','三年西蜀去如沉，西縣西來出萬岑。樹石向聞清漢浪，',40,'御定全唐詩/json/560.json','["三年西蜀去如沉，西縣西來出萬岑。樹石向聞清漢浪，", "從此漸知光景異，錦都回首盡愁吟。"]'),
('yuding-42','分山嶺望靈寶峰','薛能','唐','御定全唐诗','yuding','','[]','千尋萬仞峰，靈寶號何從。盛立同吾道，貪程阻聖蹤。',48,'御定全唐詩/json/560.json','["千尋萬仞峰，靈寶號何從。盛立同吾道，貪程阻聖蹤。", "嶺奇應有藥，壁峭盡無松。那得休於是，蹉跎亦臥龍。"]'),
('yuding-43','水簾吟','薛能','唐','御定全唐诗','yuding','','[]','萬滴相隨萬響兼，路塵天產盡旁沾。源從顥氣何因絕，',40,'御定全唐詩/json/560.json','["萬滴相隨萬響兼，路塵天產盡旁沾。源從顥氣何因絕，", "嘉名已極終難稱，別是風流不是簾。"]'),
('yuding-44','褒斜道中','薛能','唐','御定全唐诗','yuding','','[]','十驛褒斜到處慵，眼前常似接靈蹤。江遙旋入旁來水，',40,'御定全唐詩/json/560.json','["十驛褒斜到處慵，眼前常似接靈蹤。江遙旋入旁來水，", "行吟卻笑公車役，夜發星馳半不逢。"]'),
('yuding-45','褒城驛有故元相公舊題詩，因仰歎而作','薛能','唐','御定全唐诗','yuding','','[]','鄂相頃題應好池，題雲萬竹與千梨。我來已變當初地，',40,'御定全唐詩/json/560.json','["鄂相頃題應好池，題雲萬竹與千梨。我來已變當初地，", "閑吟四壁堪搔首，頻見青蘋白鷺鷥。"]'),
('yuding-46','題褒城驛池','薛能','唐','御定全唐诗','yuding','','[]','池館通秦檻向衢，舊聞佳賞此踟躕。清涼不散亭猶在，',40,'御定全唐詩/json/560.json','["池館通秦檻向衢，舊聞佳賞此踟躕。清涼不散亭猶在，", "西川吟吏偏思葺，只恐歸尋水亦枯。"]'),
('yuding-47','送崔學士赴東川','薛能','唐','御定全唐诗','yuding','','[]','羽人仙籍冠浮丘，欲作酂侯且蜀侯，導騎已多行劍閣，',40,'御定全唐詩/json/560.json','["羽人仙籍冠浮丘，欲作酂侯且蜀侯，導騎已多行劍閣，", "唯有夜樽歡莫厭，廟堂他日少閒遊。"]'),
('yuding-48','海棠','薛能','唐','御定全唐诗','yuding','','[]','酷烈複離披，玄功莫我知。青苔浮落處，暮柳間開時。',120,'御定全唐詩/json/560.json','["酷烈複離披，玄功莫我知。青苔浮落處，暮柳間開時。", "帶醉遊人插，連陰被叟移。晨前清露濕，晏後惡風吹。", "香少傳何許，妍多畫半遺。島蘇漣水脈，庭綻粒松枝。", "偶泛因沉硯，閑飄欲亂棋。繞山生玉壘，和郡遍坤維。", "負賞慚休飲，牽吟分失饑。明年應不見，留此贈巴兒。"]'),
('yuding-49','詠夾徑菊','薛能','唐','御定全唐诗','yuding','','[]','夾徑盡黃英，不通人並行。幾曾相對綻，元自兩行生。',72,'御定全唐詩/json/560.json','["夾徑盡黃英，不通人並行。幾曾相對綻，元自兩行生。", "叢比高低等，香連左右並。畔搖風勢斷，中夾日華明。", "間隔蛩吟隔，交橫蝶亂橫。頻應泛桑落，摘處近前楹。"]'),
('yuding-50','碧鮮亭春題竹','薛能','唐','御定全唐诗','yuding','','[]','竹少竹更重，碧鮮疆更名。有欄常憑立，無徑獨穿行。',48,'御定全唐詩/json/560.json','["竹少竹更重，碧鮮疆更名。有欄常憑立，無徑獨穿行。", "夕月陰何亂，春風葉盡輕。已聞圖畫客，兼寫薛先生。"]'),
('yuding-51','行徑','薛能','唐','御定全唐诗','yuding','','[]','盤徑入依依，旋驚幽鳥飛。尋多苔色古，踏碎籜聲微。',48,'御定全唐詩/json/560.json','["盤徑入依依，旋驚幽鳥飛。尋多苔色古，踏碎籜聲微。", "鞭節橫妨戶，枝梢動拂衣。前溪聞到處，應接釣魚磯。"]'),
('yuding-52','新柳','薛能','唐','御定全唐诗','yuding','','[]','輕輕須重不須輕，眾木難成獨早成。柔性定勝剛性立，',40,'御定全唐詩/json/560.json','["輕輕須重不須輕，眾木難成獨早成。柔性定勝剛性立，", "誰道少逢知己用，將軍因此建雄名。"]'),
('yuding-53','牡丹四首','薛能','唐','御定全唐诗','yuding','','[]','異色稟陶甄，常疑主者偏。眾芳殊不類，一笑獨奢妍。',392,'御定全唐詩/json/560.json','["異色稟陶甄，常疑主者偏。眾芳殊不類，一笑獨奢妍。", "顆折羞含懶，叢虛隱陷圓。亞心堆勝被，美色豔於蓮。", "品格如寒食，精光似少年。種堪收子子，價合易賢賢。", "迥秀應無妒，奇香稱有仙。深陰宜映幕，富貴助開筵。", "蜀水爭能染，巫山未可憐。數難忘次第，立困戀傍邊。", "逐日愁風雨，和星祝夜天。且從留盡賞，離此便歸田。", "萬朵照初筵，狂游憶少年。曉光如曲水，顏色似西川。", "白向庚辛受，朱從造化研。眾開成伴侶，相笑極神仙。", "見焰甯勞火，聞香不帶煙。自高輕月桂，非偶賤池蓮。", "影接雕盤動，叢遭惡草偏。招歡憂事阻，就臥覺情牽。", "四面宜綈錦，當頭稱管弦。泊來鶯定憶，粉擾蝶何顛。", "蘇息承朝露，滋榮仰霽天。壓欄多盡好，敵國貴宜然。", "未落須迷醉，因茲任病纏。人誰知極物，空負感麟篇。", "去年零落暮春時，淚濕紅箋怨別離。常恐便隨巫峽散，", "欲就欄邊安枕席，夜深閑共說相思。", "牡丹愁為牡丹饑，自惜多情欲瘦羸。濃豔冷香初蓋後，", "京國別來誰占玩，此花光景屬吾詩。"]'),
('yuding-54','使院栽葦','薛能','唐','御定全唐诗','yuding','','[]','戛戛複差差，一叢千萬枝。格如僧住處，栽得吏閒時。',48,'御定全唐詩/json/560.json','["戛戛複差差，一叢千萬枝。格如僧住處，栽得吏閒時。", "筍自廳中出，根從府外移。從軍無宿例，空想夜風吹。"]'),
('yuding-55','失鶴二首','薛能','唐','御定全唐诗','yuding','','[]','偶背雕籠與我違，四方端佇竟忘歸。誰家白日雲間見，',80,'御定全唐詩/json/560.json','["偶背雕籠與我違，四方端佇竟忘歸。誰家白日雲間見，", "憑人轉覺多相誤，盡道皤然作令威。", "華表翹風未可期，變丁投衛兩堪疑。應緣失路防人損，", "不然直道高空外，白水青山屬臘師。"]'),
('yuding-56','答賈支使寄鶴','薛能','唐','御定全唐诗','yuding','','[]','瑞羽奇姿踉蹌形，稱為仙馭過清冥。何年厚祿曾居衛，',40,'御定全唐詩/json/560.json','["瑞羽奇姿踉蹌形，稱為仙馭過清冥。何年厚祿曾居衛，", "勞君贈我清歌侶，將去田園夜坐聽。"]'),
('yuding-57','陳州刺史寄鶴','薛能','唐','御定全唐诗','yuding','','[]','臨風高視聳奇形，渡海沖天想盡經。因得羽儀來合浦，',40,'御定全唐詩/json/560.json','["臨風高視聳奇形，渡海沖天想盡經。因得羽儀來合浦，", "南守欲知多少重，撫毛千萬喚丁丁。"]'),
('yuding-58','孔雀','薛能','唐','御定全唐诗','yuding','','[]','偶有功名正俗才，靈禽何事降瑤台。天仙黼黻毛應是，',40,'御定全唐詩/json/560.json','["偶有功名正俗才，靈禽何事降瑤台。天仙黼黻毛應是，", "佳人為我和衫拍，遣作傞傞送一杯。"]'),
('yuding-59','鄜州進白野鵲','薛能','唐','御定全唐诗','yuding','','[]','輕毛疊雪翅開霜，紅觜能深練尾長。名應玉符朝北闕，',40,'御定全唐詩/json/560.json','["輕毛疊雪翅開霜，紅觜能深練尾長。名應玉符朝北闕，", "從此定知棲息處，月宮瓊樹是仙鄉。"]'),
('yuding-60','早蟬','薛能','唐','御定全唐诗','yuding','','[]','不見上庭樹，日高聲忽吟。他人豈無耳，遠客自關心。',48,'御定全唐詩/json/560.json','["不見上庭樹，日高聲忽吟。他人豈無耳，遠客自關心。", "暫落還因雨，橫飛亦向林。分明去年意，從此漸聞砧。"]'),
('yuding-61','申湖','薛能','唐','御定全唐诗','yuding','','[]','昔年依峽寺，每日見申湖。下淚重來此，知心一已無。',96,'御定全唐詩/json/560.json','["昔年依峽寺，每日見申湖。下淚重來此，知心一已無。", "雨霖舟色暗，岸拔木形枯。舊境深相惱，新春宛不殊。", "方來尋熟侶，起去恨驚鳧。忍事花何笑，喧吟瀑正粗。", "堪憂從宦到，倍遣曩懷孤。上馬終回首，傍人怪感籲。"]'),
('yuding-62','謝劉相寄天柱茶','薛能','唐','御定全唐诗','yuding','','[]','兩串春團敵夜光，名題天柱印維揚。偷嫌曼倩桃無味，',40,'御定全唐詩/json/560.json','["兩串春團敵夜光，名題天柱印維揚。偷嫌曼倩桃無味，", "粗官寄與真拋卻，賴有詩情合得嘗。"]'),
('yuding-63','題後集','薛能','唐','御定全唐诗','yuding','','[]','詩源何代失澄清，處處狂波汙後生。常感道孤吟有淚，',40,'御定全唐詩/json/560.json','["詩源何代失澄清，處處狂波汙後生。常感道孤吟有淚，", "縱到緱山也無益，四方聯絡盡蛙聲。"]'),
('yuding-64','秋晚送無可上人','薛能','唐','御定全唐诗','yuding','','[]','半夜覺松雨，照書燈悄然。河聲才淅瀝，舊業近潺湲。',48,'御定全唐詩/json/560.json','["半夜覺松雨，照書燈悄然。河聲才淅瀝，舊業近潺湲。", "坐滴寒更盡，吟驚宿鶴遷。相思不相見，日短複愁牽。"]'),
('yuding-65','贈源寂禪師','薛能','唐','御定全唐诗','yuding','','[]','瓶缽鎮隨腰，怡然處寂寥。門禪從北祖，僧格似南朝。',48,'御定全唐詩/json/560.json','["瓶缽鎮隨腰，怡然處寂寥。門禪從北祖，僧格似南朝。", "性近徒相許，緣多愧未銷。何傳能法慧，此岸要津橋。"]'),
('yuding-66','贈禪師','薛能','唐','御定全唐诗','yuding','','[]','嗜欲本無性，此生長在禪。九州空有路，一室獨多年。',48,'御定全唐詩/json/560.json','["嗜欲本無性，此生長在禪。九州空有路，一室獨多年。", "鳴磬微塵落，移瓶濕地圓。相尋偶同宿，星月坐忘眠。"]'),
('yuding-67','夏日青龍寺尋僧二首','薛能','唐','御定全唐诗','yuding','','[]','帝裏欲何待，人間無闕遺。不能安舊隱，都屬擾明時。',96,'御定全唐詩/json/560.json','["帝裏欲何待，人間無闕遺。不能安舊隱，都屬擾明時。", "違理須齊辱，雄圖豈藉知。縱橫悉已誤，斯語是吾師。", "得官殊未喜，失計是忘愁。不是無心速，焉能有自由。", "涼風盈夏扇，蜀茗半形甌。笑向權門客，應難見道流。"]'),
('yuding-68','寄題巨源禪師','薛能','唐','御定全唐诗','yuding','','[]','風雨禪思外，應殘木槿花。何年別鄉土，一衲代袈裟。',48,'御定全唐詩/json/560.json','["風雨禪思外，應殘木槿花。何年別鄉土，一衲代袈裟。", "日氣侵瓶暖，雷聲動枕斜。還當掃樓影，天晚自煎茶。"]'),
('yuding-69','題河中亭子','薛能','唐','御定全唐诗','yuding','','[]','河擘雙流島在中，島中亭上正南空，蒲根舊浸臨關道，',40,'御定全唐詩/json/560.json','["河擘雙流島在中，島中亭上正南空，蒲根舊浸臨關道，", "無窮勝事應須宿，霜白蒹葭月在東。"]'),
('yuding-70','逢友人邊游回','薛能','唐','御定全唐诗','yuding','','[]','遊子新從絕塞回，自言曾上李陵台。',32,'御定全唐詩/json/560.json','["遊子新從絕塞回，自言曾上李陵台。", "尊前語盡北風起，秋色蕭條胡雁來。"]'),
('yuding-71','春雨','薛能','唐','御定全唐诗','yuding','','[]','電闊照潺潺，驚流往復還。遠聲如有洞，迷色似無山。',72,'御定全唐詩/json/560.json','["電闊照潺潺，驚流往復還。遠聲如有洞，迷色似無山。", "利物乾坤內，並風竹樹間。靜思來朔漠，愁望滿柴關。", "迸濕消塵慮，吹風觸疾顏。誰知草茅徑，沾此尚虛閑。"]'),
('yuding-72','夏雨','薛能','唐','御定全唐诗','yuding','','[]','何處發天涯，風雷一道賒。去聲隨地急，殘勢傍樓斜。',48,'御定全唐詩/json/560.json','["何處發天涯，風雷一道賒。去聲隨地急，殘勢傍樓斜。", "透樹垂紅葉，沾塵帶落花。瀟湘無限思，閑看下蒹葭。"]'),
('yuding-73','秋夜山中述事','薛能','唐','御定全唐诗','yuding','','[]','初宵門未掩，獨坐對霜空。極目故鄉月，滿溪寒草風。',48,'御定全唐詩/json/560.json','["初宵門未掩，獨坐對霜空。極目故鄉月，滿溪寒草風。", "樵聲當嶺上，僧語在雲中。正恨歸期晚，蕭蕭聞塞鴻。"]'),
('yuding-74','長安道','薛能','唐','御定全唐诗','yuding','','[]','汲汲複營營，東西連兩京。關繻古若在，山嶽累應成。',72,'御定全唐詩/json/560.json','["汲汲複營營，東西連兩京。關繻古若在，山嶽累應成。", "各自有身事，不相知姓名。交馳兼眾類，分散入重城。", "此去應無盡，萬方人旋生。空餘片言苦，來往覓劉楨。"]'),
('yuding-75','酬泗州韋中丞埇上日寄贈兼次本韻','薛能','唐','御定全唐诗','yuding','','[]','魯儒相悟欲成空，學盡文章不見功。官自掖垣飄海上，',40,'御定全唐詩/json/560.json','["魯儒相悟欲成空，學盡文章不見功。官自掖垣飄海上，", "何意杜陵懷寶客，也隨迷路出關東。"]'),
('yuding-76','泛觴池','薛能','唐','御定全唐诗','yuding','','[]','通咽遠華樽，泛觴名自君。淨看籌見影，輕動酒生紋。',48,'御定全唐詩/json/560.json','["通咽遠華樽，泛觴名自君。淨看籌見影，輕動酒生紋。", "細滴隨杯落，來聲就浦分。便應半酣後，清冷漱兼雲。"]'),
('yuding-0','荔枝詩','薛能','唐','御定全唐诗','yuding','','[]','顆如松子色如櫻，未識蹉跎欲半生。',32,'御定全唐詩/json/561.json','["顆如松子色如櫻，未識蹉跎欲半生。", "歲杪監州曾見樹，時新入座久聞名。"]'),
('yuding-1','丁巳上元日放三雉','薛能','唐','御定全唐诗','yuding','','[]','嬰網雖皆困，褰籠喜共歸。無心期爾報，相見莫驚飛。',24,'御定全唐詩/json/561.json','["嬰網雖皆困，褰籠喜共歸。無心期爾報，相見莫驚飛。"]'),
('yuding-2','寓題','薛能','唐','御定全唐诗','yuding','','[]','王澤猶來雅在新，尚詞微事可愁人。',32,'御定全唐詩/json/561.json','["王澤猶來雅在新，尚詞微事可愁人。", "淫哇滿眼關雎弱，猶賀清朝有此身。"]'),
('yuding-3','望蜀亭','薛能','唐','御定全唐诗','yuding','','[]','樹簇煙迷蜀國深，嶺頭分界戀登臨。',32,'御定全唐詩/json/561.json','["樹簇煙迷蜀國深，嶺頭分界戀登臨。", "前軒一望無他處，從此西川只在心。"]'),
('yuding-4','遊嘉州後溪','薛能','唐','御定全唐诗','yuding','','[]','山屐經過滿徑蹤，隔溪遙見夕陽舂。',32,'御定全唐詩/json/561.json','["山屐經過滿徑蹤，隔溪遙見夕陽舂。", "當時諸葛成何事，只合終身作臥龍。"]'),
('yuding-5','自諷','薛能','唐','御定全唐诗','yuding','','[]','千題萬詠過三旬，忘食貪魔作瘦人。',32,'御定全唐詩/json/561.json','["千題萬詠過三旬，忘食貪魔作瘦人。", "行處便吟君莫笑，就中詩病不任春。"]'),
('yuding-6','乞假歸題候館','薛能','唐','御定全唐诗','yuding','','[]','僕帶雕弓馬似飛，老萊衣上著戎衣。',32,'御定全唐詩/json/561.json','["僕帶雕弓馬似飛，老萊衣上著戎衣。", "郵亭不暇吟山水，塞外經年皆未歸。"]'),
('yuding-7','監郡犍為將歸使府登樓寓題','薛能','唐','御定全唐诗','yuding','','[]','幾日監臨向蜀春，錯拋歌酒強憂人。',32,'御定全唐詩/json/561.json','["幾日監臨向蜀春，錯拋歌酒強憂人。", "江樓一望西歸去，不負嘉州只負身。"]'),
('yuding-8','過象耳山二首','薛能','唐','御定全唐诗','yuding','','[]','一色青松幾萬栽，異香熏路帶花開。',64,'御定全唐詩/json/561.json','["一色青松幾萬栽，異香熏路帶花開。", "山門欲別心潛願，更到蜀中還到來。", "到處逢山便欲登，自疑身作住來僧。", "徒行至此三千里，不是有緣應不能。"]'),
('yuding-9','聖燈','薛能','唐','御定全唐诗','yuding','','[]','莽莽空中稍稍燈，坐看迷濁變清澄。',32,'御定全唐詩/json/561.json','["莽莽空中稍稍燈，坐看迷濁變清澄。", "須知火盡煙無益，一夜欄邊說向僧。"]'),
('yuding-10','過昌利觀有懷','薛能','唐','御定全唐诗','yuding','','[]','萬仞雲峰八石泉，李君仙後更誰仙。',32,'御定全唐詩/json/561.json','["萬仞雲峰八石泉，李君仙後更誰仙。", "我來駐馬人何問，老柏無多不種田。"]'),
('yuding-11','蜀路','薛能','唐','御定全唐诗','yuding','','[]','劍閣緣雲拂鬥魁，疾風生樹過龍媒。',32,'御定全唐詩/json/561.json','["劍閣緣雲拂鬥魁，疾風生樹過龍媒。", "前程憩罷知無益，但是駑蹄亦到來。"]'),
('yuding-12','山下偶作','薛能','唐','御定全唐诗','yuding','','[]','零雨沾山百草香，樹梢高頂盡斜陽。',32,'御定全唐詩/json/561.json','["零雨沾山百草香，樹梢高頂盡斜陽。", "橫流巨石皆堪住，何事無僧有石房。"]'),
('yuding-13','伏牛山','薛能','唐','御定全唐诗','yuding','','[]','虎蹲峰狀屈名牛，落日連村好望秋。',32,'御定全唐詩/json/561.json','["虎蹲峰狀屈名牛，落日連村好望秋。", "不為時危耕不得，一黎風雨便歸休。"]'),
('yuding-14','老圃堂','薛能','唐','御定全唐诗','yuding','','[]','邵平瓜地接吾廬，穀雨幹時偶自鋤。',32,'御定全唐詩/json/561.json','["邵平瓜地接吾廬，穀雨幹時偶自鋤。", "昨日春風欺不在，就床吹落讀殘書。"]'),
('yuding-15','春題','薛能','唐','御定全唐诗','yuding','','[]','柳莫搖搖花莫開，此心因病亦成灰。',32,'御定全唐詩/json/561.json','["柳莫搖搖花莫開，此心因病亦成灰。", "人生只有家園樂，及取春農歸去來。"]'),
('yuding-16','並州寓懷','薛能','唐','御定全唐诗','yuding','','[]','人多知遇獨難求，人負知音獨愛酬。',32,'御定全唐詩/json/561.json','["人多知遇獨難求，人負知音獨愛酬。", "常恐此心無樂處，枉稱年少在並州。"]'),
('yuding-17','中秋旅舍','薛能','唐','御定全唐诗','yuding','','[]','雲卷庭虛月逗空，一方秋草盡鳴蟲。',32,'御定全唐詩/json/561.json','["雲卷庭虛月逗空，一方秋草盡鳴蟲。", "是時兄弟正南北，黃葉滿階來去風。"]'),
('yuding-18','符亭二首','薛能','唐','御定全唐诗','yuding','','[]','符亭之地雅離群，萬古懸泉一旦新。',64,'御定全唐詩/json/561.json','["符亭之地雅離群，萬古懸泉一旦新。", "若念農桑也如此，縣人應得似行人。", "山如巫峽煙雲好，路似嘉祥水木清。", "大抵遊人總應愛，就中難說是詩情。"]'),
('yuding-19','秋夜聽任郎中琴','薛能','唐','御定全唐诗','yuding','','[]','十指宮商膝上秋，七條絲動雨修修。',32,'御定全唐詩/json/561.json','["十指宮商膝上秋，七條絲動雨修修。", "空堂半夜孤燈冷，彈著鄉心欲白頭。"]'),
('yuding-20','留別關東舊游','薛能','唐','御定全唐诗','yuding','','[]','我去君留十載中，未曾相見及花紅。',32,'御定全唐詩/json/561.json','["我去君留十載中，未曾相見及花紅。", "他時住得君應老，長短看花心不同。"]'),
('yuding-21','贈出塞客','薛能','唐','御定全唐诗','yuding','','[]','出郊征騎逐飛埃，此別惟愁春未回。',32,'御定全唐詩/json/561.json','["出郊征騎逐飛埃，此別惟愁春未回。", "寒葉夕陽投宿意，蘆關門向遠河開。"]'),
('yuding-22','秋溪獨坐','薛能','唐','御定全唐诗','yuding','','[]','黃葉分飛砧上下，白雲零落馬東西。',32,'御定全唐詩/json/561.json','["黃葉分飛砧上下，白雲零落馬東西。", "人生萬意此端坐，日暮水深流出溪。"]'),
('yuding-23','蒲中霽後晚望','薛能','唐','御定全唐诗','yuding','','[]','河邊霽色無人見，身帶春風立岸頭。',32,'御定全唐詩/json/561.json','["河邊霽色無人見，身帶春風立岸頭。", "濁水茫茫有何意，日斜還向古蒲州。"]'),
('yuding-24','宋氏林亭','薛能','唐','御定全唐诗','yuding','','[]','地濕莎青雨後天，桃花紅近竹林邊。',32,'御定全唐詩/json/561.json','["地濕莎青雨後天，桃花紅近竹林邊。", "行人本是農桑客，記得春深欲種田。"]'),
('yuding-25','雲花寺寓居贈海岸上人','薛能','唐','御定全唐诗','yuding','','[]','暫寄空門未是歸，上方林榭獨儒衣。',32,'御定全唐詩/json/561.json','["暫寄空門未是歸，上方林榭獨儒衣。", "吾師不語應相怪，頻惹街塵入寺飛。"]'),
('yuding-26','關中秋夕','薛能','唐','御定全唐诗','yuding','','[]','簟濕秋庭嶽在煙，露光明滑竹蒼然。',32,'御定全唐詩/json/561.json','["簟濕秋庭嶽在煙，露光明滑竹蒼然。", "何人意緒還相似，鶴宿松枝月半天。"]'),
('yuding-27','西縣道中有短亭，岩穴飛泉隔江灑至，因成二首','薛能','唐','御定全唐诗','yuding','','[]','風涼津濕共微微，隔岸泉沖石竅飛。',64,'御定全唐詩/json/561.json','["風涼津濕共微微，隔岸泉沖石竅飛。", "爭得巨靈從野性，舊鄉無此擘將歸。", "一瀑三峰赤日天，路人才見便翛然。", "誰能夜向山根宿，涼月初生的有仙。"]'),
('yuding-28','省試夜','薛能','唐','御定全唐诗','yuding','','[]','白蓮千朵照廊明，一片承平雅頌聲。',32,'御定全唐詩/json/561.json','["白蓮千朵照廊明，一片承平雅頌聲。", "更報第三條燭盡，文昌風景畫難成。"]'),
('yuding-29','過驪山','薛能','唐','御定全唐诗','yuding','','[]','丹雘蒼蒼簇背山，路塵應滿舊簾間。',32,'御定全唐詩/json/561.json','["丹雘蒼蒼簇背山，路塵應滿舊簾間。", "玄宗不是偏行樂，只為當時四海閑。"]'),
('yuding-30','曲江醉題','薛能','唐','御定全唐诗','yuding','','[]','閑身行止屬年華，馬上懷中盡落花。',32,'御定全唐詩/json/561.json','["閑身行止屬年華，馬上懷中盡落花。", "狂遍曲江還醉臥，覺來人靜日西斜。"]'),
('yuding-31','參軍廳新池','薛能','唐','御定全唐诗','yuding','','[]','簾外無塵勝物外，牆根有竹似山根。',32,'御定全唐詩/json/561.json','["簾外無塵勝物外，牆根有竹似山根。", "流泉不至客來久，坐見新池落舊痕。"]'),
('yuding-32','太原使院晚出','薛能','唐','御定全唐诗','yuding','','[]','青門無路入清朝，濫作將軍最下僚。',32,'御定全唐詩/json/561.json','["青門無路入清朝，濫作將軍最下僚。", "同舍盡歸身獨在，晚風開印葉蕭蕭。"]'),
('yuding-33','寒食日曲江','薛能','唐','御定全唐诗','yuding','','[]','曲水池邊青草岸，春風林下落花杯。',32,'御定全唐詩/json/561.json','["曲水池邊青草岸，春風林下落花杯。", "都門此日是寒食，人去看多身獨來。"]'),
('yuding-34','盩厔官舍新竹','薛能','唐','御定全唐诗','yuding','','[]','心覺清涼體似吹，滿風輕撼葉垂垂。',32,'御定全唐詩/json/561.json','["心覺清涼體似吹，滿風輕撼葉垂垂。", "無端種在幽閒地，眾鳥嫌寒鳳未知。"]'),
('yuding-35','京中客舍聞箏','薛能','唐','御定全唐诗','yuding','','[]','十二三弦共五音，每聲如截遠人心。',32,'御定全唐詩/json/561.json','["十二三弦共五音，每聲如截遠人心。", "當時向秀聞鄰笛，不是離家歲月深。"]'),
('yuding-36','銅雀台','薛能','唐','御定全唐诗','yuding','','[]','魏帝當時銅雀台，黃花深映棘叢開。',32,'御定全唐詩/json/561.json','["魏帝當時銅雀台，黃花深映棘叢開。", "人生富貴須回首，此地豈無歌舞來。"]'),
('yuding-37','壽安水館','薛能','唐','御定全唐诗','yuding','','[]','地接山林兼有石，天懸星月更無雲。',32,'御定全唐詩/json/561.json','["地接山林兼有石，天懸星月更無雲。", "驚鷗上樹滿池水，瀺灂一聲中夜聞。"]'),
('yuding-38','雨後早發永甯','薛能','唐','御定全唐诗','yuding','','[]','春霖朝罷客西東，雨足泥聲路未通。',32,'御定全唐詩/json/561.json','["春霖朝罷客西東，雨足泥聲路未通。", "獨愛千峰最高處，一峰初日白雲中。"]'),
('yuding-39','宿仙游寺望月生峰','薛能','唐','御定全唐诗','yuding','','[]','公門身入洞門行，出阱離籠似有情。',32,'御定全唐詩/json/561.json','["公門身入洞門行，出阱離籠似有情。", "僧語夜涼雲樹黑，月生峰上月初生。"]'),
('yuding-40','秋題','薛能','唐','御定全唐诗','yuding','','[]','獨坐東南見曉星，白雲微透泬寥清。',32,'御定全唐詩/json/561.json','["獨坐東南見曉星，白雲微透泬寥清。", "磷磷甃石堪僧坐，一葉梧桐落半庭。"]'),
('yuding-41','和友人寄懷','薛能','唐','御定全唐诗','yuding','','[]','從來行樂近來希，蘧瑗知言與我違。',32,'御定全唐詩/json/561.json','["從來行樂近來希，蘧瑗知言與我違。", "自是衰心不如舊，非關四十九年非。"]'),
('yuding-42','子夜','薛能','唐','御定全唐诗','yuding','','[]','嫖姚家宴敵吳王，子夜歌聲滿畫堂。',32,'御定全唐詩/json/561.json','["嫖姚家宴敵吳王，子夜歌聲滿畫堂。", "此日相逢眉翠盡，女真行李乞齋糧。"]'),
('yuding-43','雁和韋侍禦','薛能','唐','御定全唐诗','yuding','','[]','肅肅雍雍義有餘，九天鶯鳳莫相疏。',32,'御定全唐詩/json/561.json','["肅肅雍雍義有餘，九天鶯鳳莫相疏。", "唯應靜向山窗過，激發英雄夜讀書。"]'),
('yuding-44','和府帥相公','薛能','唐','御定全唐诗','yuding','','[]','竹映高牆似傍山，鄒陽歸後令威還。',32,'御定全唐詩/json/561.json','["竹映高牆似傍山，鄒陽歸後令威還。", "君看將相才多少，兩首詩成七步間。"]'),
('yuding-45','又和留山雞','薛能','唐','御定全唐诗','yuding','','[]','五色文勝百鳥王，相思兼絕寄芸香。',32,'御定全唐詩/json/561.json','["五色文勝百鳥王，相思兼絕寄芸香。", "由來不是池中物，雞樹歸時即取將。"]'),
('yuding-46','舟中酬楊中丞春早見寄','薛能','唐','御定全唐诗','yuding','','[]','錦樓春望憶丹楹，更遇高情說早鶯。',32,'御定全唐詩/json/561.json','["錦樓春望憶丹楹，更遇高情說早鶯。", "江上境寒吟不得，濕風梅雨滿船輕。"]'),
('yuding-47','寒食日題','薛能','唐','御定全唐诗','yuding','','[]','美人寒食事春風，折盡青青賞盡紅。',32,'御定全唐詩/json/561.json','["美人寒食事春風，折盡青青賞盡紅。", "夜半無燈還有睡，秋千懸在月明中。"]'),
('yuding-48','杏花','薛能','唐','御定全唐诗','yuding','','[]','活色生香第一流，手中移得近青樓。',32,'御定全唐詩/json/561.json','["活色生香第一流，手中移得近青樓。", "誰知豔性終相負，亂向春風笑不休。"]'),
('yuding-49','黃蜀葵','薛能','唐','御定全唐诗','yuding','','[]','嬌黃新嫩欲題詩，盡日含毫有所思。',32,'御定全唐詩/json/561.json','["嬌黃新嫩欲題詩，盡日含毫有所思。", "記得玉人初病起，道家妝束厭禳時。"]'),
('yuding-50','春詠','薛能','唐','御定全唐诗','yuding','','[]','春來還似去年時，手把花枝唱竹枝。',32,'御定全唐詩/json/561.json','["春來還似去年時，手把花枝唱竹枝。", "狂瘦未曾餐有味，不緣中酒卻緣詩。"]'),
('yuding-51','贈歡娘','薛能','唐','御定全唐诗','yuding','','[]','一束龍吟細竹枝，青娥擎在手中吹。',32,'御定全唐詩/json/561.json','["一束龍吟細竹枝，青娥擎在手中吹。", "當時縱使雙成在，不得如伊是小時。"]'),
('yuding-52','戲瞻相','薛能','唐','御定全唐诗','yuding','','[]','失意蹉跎到舊遊，見吹楊柳便遮羞。',32,'御定全唐詩/json/561.json','["失意蹉跎到舊遊，見吹楊柳便遮羞。", "瞻相趙女休相拽，不及人前詐擺頭。"]'),
('yuding-53','贈解詩歌人','薛能','唐','御定全唐诗','yuding','','[]','同有詩情自合親，不須歌調更含嚬。',32,'御定全唐詩/json/561.json','["同有詩情自合親，不須歌調更含嚬。", "朝天禦史非韓壽，莫竊香來帶累人。"]'),
('yuding-54','贈韋氏歌人二首','薛能','唐','御定全唐诗','yuding','','[]','弦管聲凝發唱高，幾人心地暗傷刀。',64,'御定全唐詩/json/561.json','["弦管聲凝發唱高，幾人心地暗傷刀。", "思量更有何堪比，王母新開一樹桃。", "一曲新聲慘畫堂，可能心事憶周郎。", "朝來為客頻開口，綻盡桃花幾許香。"]'),
('yuding-55','加階','薛能','唐','御定全唐诗','yuding','','[]','二年中散似稽康，此日無功換寵光。',32,'御定全唐詩/json/561.json','["二年中散似稽康，此日無功換寵光。", "唯有一般酬聖主，勝於東晉是文章。"]'),
('yuding-56','野園','薛能','唐','御定全唐诗','yuding','','[]','野園無鼓又無旗，鞍馬傳杯用柳枝。',32,'御定全唐詩/json/561.json','["野園無鼓又無旗，鞍馬傳杯用柳枝。", "嬌養翠娥無怕懼，插人頭上任風吹。"]'),
('yuding-57','郊亭','薛能','唐','御定全唐诗','yuding','','[]','郊亭宴罷欲回車，滿郭傳呼調角初。',32,'御定全唐詩/json/561.json','["郊亭宴罷欲回車，滿郭傳呼調角初。", "尚擁笙歌歸未得，笑娥扶著醉尚書。"]'),
('yuding-58','老僧','薛能','唐','御定全唐诗','yuding','','[]','清瘦形容八十餘，匏懸籬落似村居。',32,'御定全唐詩/json/561.json','["清瘦形容八十餘，匏懸籬落似村居。", "勸師莫羨人間有，幸是元無免破除。"]'),
('yuding-59','僧窗','薛能','唐','御定全唐诗','yuding','','[]','不悟時機滯有餘，近來為事更乖疏。',32,'御定全唐詩/json/561.json','["不悟時機滯有餘，近來為事更乖疏。", "朱輪皂蓋蹉跎盡，猶愛明窗好讀書。"]'),
('yuding-60','題平等院','薛能','唐','御定全唐诗','yuding','','[]','十裏城中一院僧，各持巾缽事南能。',32,'御定全唐詩/json/561.json','["十裏城中一院僧，各持巾缽事南能。", "還應笑我功名客，未解嫌官學大乘。"]'),
('yuding-61','影燈夜二首','薛能','唐','御定全唐诗','yuding','','[]','偃王燈塔古徐州，二十年來樂事休。',64,'御定全唐詩/json/561.json','["偃王燈塔古徐州，二十年來樂事休。", "此日將軍心似海，四更身領萬人遊。", "十萬軍城百萬燈，酥油香暖夜如烝。紅妝滿地煙光好，只恐笙歌引上升。"]'),
('yuding-62','許州旌節到作','薛能','唐','御定全唐诗','yuding','','[]','兩地旌旗擁一身，半緣傷舊半榮新。',32,'御定全唐詩/json/561.json','["兩地旌旗擁一身，半緣傷舊半榮新。", "州人若憶將軍面，寫取雕堂報國真。"]'),
('yuding-63','重遊通波亭','薛能','唐','御定全唐诗','yuding','','[]','十年拋擲故園花，最憶紅桃竹外斜。',32,'御定全唐詩/json/561.json','["十年拋擲故園花，最憶紅桃竹外斜。", "此日郊亭心乍喜，敗榆芳草似還家。"]'),
('yuding-64','戲舸','薛能','唐','御定全唐诗','yuding','','[]','遠舸衝開一路萍，岸傍偷上小茅亭。',32,'御定全唐詩/json/561.json','["遠舸衝開一路萍，岸傍偷上小茅亭。", "遊人莫覓杯盤分，此地才應聚德星。"]'),
('yuding-65','偶題','薛能','唐','御定全唐诗','yuding','','[]','到處吟兼上馬吟，總無愁恨自傷心。',32,'御定全唐詩/json/561.json','["到處吟兼上馬吟，總無愁恨自傷心。", "無端夢得鈞天樂，盡覺宮商不是音。"]'),
('yuding-66','折楊柳十首','薛能','唐','御定全唐诗','yuding','','[]','華清高樹出離宮，南陌柔條帶暖風。',320,'御定全唐詩/json/561.json','["華清高樹出離宮，南陌柔條帶暖風。", "誰見輕陰是良夜，瀑泉聲畔月明中。", "洛橋晴影覆江船，羌笛秋聲濕塞煙。", "閑想習池公宴罷，水蒲風絮夕陽天。", "嫩綠輕懸似綴旒，路人遙見隔宮樓。", "誰能更近丹墀種，解播皇風入九州。", "暖風晴日斷浮埃，廢路新條發釣台。", "處處輕陰可惆悵，後人攀處古人栽。", "潭上江邊嫋嫋垂，日高風靜絮相隨。", "青樓一樹無人見，正是女郎眠覺時。", "汴水高懸百萬條，風清兩岸一時搖。", "隋家力盡虛栽得，無限春風屬聖朝。", "和風煙樹九重城，夾路春陰十萬營。", "唯向邊頭不堪望，一株憔悴少人行。", "窗外齊垂旭日初，樓邊輕暖好風徐。", "遊人莫道栽無益，桃李清陰卻不如。", "眾木猶寒獨早青，禦溝橋畔曲江亭。", "陶家舊日應如此，一院春條綠繞廳。", "帳偃纓垂細複繁，令人心想石家園。", "風條月影皆堪重，何事侯門愛樹萱。"]'),
('yuding-67','柳枝四首','薛能','唐','御定全唐诗','yuding','','[]','數首新詩帶恨成，柳絲牽我我傷情。',128,'御定全唐詩/json/561.json','["數首新詩帶恨成，柳絲牽我我傷情。", "柔娥幸有腰支穩，試踏吹聲作唱聲。", "高出軍營遠映橋，賊兵曾斫火曾燒。", "風流性在終難改，依舊春來萬萬條。", "縣依陶令想嫌迂，營畔將軍即大粗。", "此日與君除萬恨，數篇風調更應無。", "狂似纖腰嫩勝綿，自多情態竟誰憐。", "遊人不折還堪恨，拋向橋邊與路邊。"]'),
('yuding-68','柳枝詞五首','薛能','唐','御定全唐诗','yuding','','[]','朝陽晴照綠楊煙，一別通波十七年。',160,'御定全唐詩/json/561.json','["朝陽晴照綠楊煙，一別通波十七年。", "應有舊枝無處覓，萬株風裏卓旌旃。", "晴垂芳態吐牙新，雨擺輕條濕面春。", "別有出牆高數尺，不知搖動是何人。", "暖梳簪朵事登樓，因掛垂楊立地愁。", "牽斷綠絲攀不得，半空懸著玉搔頭。", "西園高樹後庭根，處處尋芳有折痕。", "終憶舊游桃葉舍，一株斜映竹籬門。", "劉白蘇台總近時，當初章句是誰推。", "纖腰舞盡春楊柳，未有儂家一首詩。"]'),
('yuding-69','吳姬十首','薛能','唐','御定全唐诗','yuding','','[]','夜鎖重門晝亦監，眼波嬌利瘦岩岩。',320,'御定全唐詩/json/561.json','["夜鎖重門晝亦監，眼波嬌利瘦岩岩。", "偏憐不怕傍人笑，自把春羅等舞衫。", "龍麝熏多骨亦香，因經寒食好風光。", "何人畫得天生態，枕破施朱隔宿妝。", "滴滴春霖透荔枝，筆題箋動手中垂。", "天陰不得君王召，嚬著青蛾作小詩。", "鈿合重盛繡結深，昭陽初幸賜同心。", "君知一夜恩多少，明日宣教放德音。", "退紅香汗濕輕紗，高卷蚊廚獨臥斜。", "嬌淚半垂珠不破，恨君瞋折後庭花。", "取次衣裳盡帶珠，別添龍腦裛羅襦。", "年來寄與鄉中伴，殺盡春蠶稅亦無。", "畫燭燒蘭暖複迷，殿幃深密下銀泥。", "開門欲作侵晨散，已是明朝日向西。", "樓臺重疊滿天雲，殷殷鳴鼉世上聞。", "此日楊花初似雪，女兒弦管弄參軍。", "冠剪黃綃帔紫羅，薄施鉛粉畫青娥。", "因將素手誇纖巧，從此椒房寵更多。", "身是三千第一名，內家叢裏獨分明。", "芙蓉殿上中元日，水拍銀台弄化生。"]'),
('yuding-70','題於公花園','薛能','唐','御定全唐诗','yuding','','[]','含桃莊主後園深，繁實初成靜掃陰。',32,'御定全唐詩/json/561.json','["含桃莊主後園深，繁實初成靜掃陰。", "若使明年花可待，應須惱破事花心。"]'),
('yuding-71','登城','薛能','唐','御定全唐诗','yuding','','[]','偶作閑身上古城，路人遙望不相驚。',32,'御定全唐詩/json/561.json','["偶作閑身上古城，路人遙望不相驚。", "無端將吏逡巡至，又作都頭一隊行。"]'),
('yuding-72','好客','薛能','唐','御定全唐诗','yuding','','[]','好客連宵在醉鄉，蠟煙紅暖勝春光。',32,'御定全唐詩/json/561.json','["好客連宵在醉鄉，蠟煙紅暖勝春光。", "誰人肯信山僧語，寒雨唯煎治氣湯。"]'),
('yuding-73','贈普恭禪師','薛能','唐','御定全唐诗','yuding','','[]','一日迢迢每一餐，我心難伏我無難。',32,'御定全唐詩/json/561.json','["一日迢迢每一餐，我心難伏我無難。", "南簷十月繩床暖，背卷真經向日看。"]'),
('yuding-74','贈無表禪師','薛能','唐','御定全唐诗','yuding','','[]','笠戴圓陰楚地棕，磬敲清鄉蜀山銅。',32,'御定全唐詩/json/561.json','["笠戴圓陰楚地棕，磬敲清鄉蜀山銅。", "秋來說偈寅朝殿，爽爽楊枝滿手風。"]'),
('yuding-75','彭門偶題','薛能','唐','御定全唐诗','yuding','','[]','淮王西舍固非夫，柳惲偏州未是都。',32,'御定全唐詩/json/561.json','["淮王西舍固非夫，柳惲偏州未是都。", "直到春秋諸列國，擁旄才子也應無。"]'),
('yuding-76','嘲趙璘','薛能','唐','御定全唐诗','yuding','','[]','巡關每傍摴蒲局，望月還登乞巧樓。',32,'御定全唐詩/json/561.json','["巡關每傍摴蒲局，望月還登乞巧樓。", "第一莫教嬌太過，緣人衣帶上人頭。"]'),
('yuding-77','句','薛能','唐','御定全唐诗','yuding','','[]','百首如一首，卷初如卷終。（《北夢瑣言》：能以詩自負，',84,'御定全唐詩/json/561.json','["百首如一首，卷初如卷終。（《北夢瑣言》：能以詩自負，", "坐久僕頭出，語多僧齒寒。", "西塞長雲盡，南湖片月斜。", "李白終無取，陶潛固不刊。", "我身若在開元日，爭遣名為李翰林。（寄符郎中，"]'),
('yuding-0','早春','劉威','唐','御定全唐诗','yuding','','[]','曉來庭戶外，草樹似依依。一夜東風起，萬山春色歸。',48,'御定全唐詩/json/562.json','["曉來庭戶外，草樹似依依。一夜東風起，萬山春色歸。", "冰消泉派動，日暖露珠晞。已醞看花酒，嬌鶯莫預飛。"]'),
('yuding-1','傷春感懷','劉威','唐','御定全唐诗','yuding','','[]','花飛惜不得，年長更堪悲。春盡有歸日，老來無去時。',48,'御定全唐詩/json/562.json','["花飛惜不得，年長更堪悲。春盡有歸日，老來無去時。", "風前千片雪，鏡裏數莖絲。腸斷青山暮，獨攀楊柳枝。"]'),
('yuding-2','閏三月','劉威','唐','御定全唐诗','yuding','','[]','三年皆一閏，此閏勝常時。莫怪花開晚，都緣春盡遲。',48,'御定全唐詩/json/562.json','["三年皆一閏，此閏勝常時。莫怪花開晚，都緣春盡遲。", "節分炎氣近，律應蕙風移。夢得成蝴蝶，芳菲幸不遺。"]'),
('yuding-3','早秋遊湖上亭','劉威','唐','御定全唐诗','yuding','','[]','危亭秋尚早，野思已無窮。竹葉一尊酒，荷香四座風。',48,'御定全唐詩/json/562.json','["危亭秋尚早，野思已無窮。竹葉一尊酒，荷香四座風。", "曉煙孤嶼外，歸鳥夕陽中。漸愛湖光冷，移舟月滿空。"]'),
('yuding-4','宿漁家','劉威','唐','御定全唐诗','yuding','','[]','竹屋清江上，風煙四五家。水園分芰葉，鄰界認蘆花。',48,'御定全唐詩/json/562.json','["竹屋清江上，風煙四五家。水園分芰葉，鄰界認蘆花。", "雨到魚翻浪，洲回鳥傍沙。月明何處去，片片席帆斜。"]'),
('yuding-5','旅中早秋','劉威','唐','御定全唐诗','yuding','','[]','金威生止水，爽氣遍遙空。草色蕭條路，槐花零落風。',48,'御定全唐詩/json/562.json','["金威生止水，爽氣遍遙空。草色蕭條路，槐花零落風。", "夜來萬里月，覺後一聲鴻。莫問前程事，颯然沙上蓬。"]'),
('yuding-6','早秋西歸有懷','劉威','唐','御定全唐诗','yuding','','[]','求歸方有計，惜別更堪愁。上馬江城暮，出郊山戍秋。',48,'御定全唐詩/json/562.json','["求歸方有計，惜別更堪愁。上馬江城暮，出郊山戍秋。", "暗銷何限事，白盡去年頭。莫怪頻惆悵，異鄉難再遊。"]'),
('yuding-7','冬夜旅懷','劉威','唐','御定全唐诗','yuding','','[]','寒窗危竹枕，月過半床陰。嫩葉不歸夢，晴蟲成苦吟。',48,'御定全唐詩/json/562.json','["寒窗危竹枕，月過半床陰。嫩葉不歸夢，晴蟲成苦吟。", "酒無通夜力，事滿五更心。寂寞誰相似，殘燈與素琴。"]'),
('yuding-8','塞上作','劉威','唐','御定全唐诗','yuding','','[]','蕭蕭隴水側，落日客愁中。古塞一聲笛，長沙千里風。',48,'御定全唐詩/json/562.json','["蕭蕭隴水側，落日客愁中。古塞一聲笛，長沙千里風。", "鳥無棲息處，人愛戰爭功。數夜城頭月，彎彎如引弓。"]'),
('yuding-9','秋日寄陳景孚秀才','劉威','唐','御定全唐诗','yuding','','[]','征車日已遠，物候尚淒淒。風葉青桐落，露花紅槿低。',48,'御定全唐詩/json/562.json','["征車日已遠，物候尚淒淒。風葉青桐落，露花紅槿低。", "心隨秦國遠，夢到楚山迷。卻恨銜蘆雁，秋飛不向西。"]'),
('yuding-10','冬日送友人西歸','劉威','唐','御定全唐诗','yuding','','[]','北風吹別思，杳杳度雲山。滿望是歸處，一生猶未閑。',48,'御定全唐詩/json/562.json','["北風吹別思，杳杳度雲山。滿望是歸處，一生猶未閑。", "知音方見譽，浮宦久相關。空有心如月，同居千里還。"]'),
('yuding-11','感寓','劉威','唐','御定全唐诗','yuding','','[]','海竭山移歲月深，分明齊得世人心。顏回徒恨少成古，',40,'御定全唐詩/json/562.json','["海竭山移歲月深，分明齊得世人心。顏回徒恨少成古，", "他年免似驪山鬼，信有蓬萊不可尋。"]'),
('yuding-12','七夕','劉威','唐','御定全唐诗','yuding','','[]','烏鵲橋成上界通，千秋靈會此宵同。雲收喜氣星樓曉，',40,'御定全唐詩/json/562.json','["烏鵲橋成上界通，千秋靈會此宵同。雲收喜氣星樓曉，", "采盤花閣無窮意，只在遊絲一縷中。"]'),
('yuding-13','晚春陪王員外東塘游宴','劉威','唐','御定全唐诗','yuding','','[]','水綠山青春日長，政成因暇泛回塘。初移柳岸笙歌合，',40,'御定全唐詩/json/562.json','["水綠山青春日長，政成因暇泛回塘。初移柳岸笙歌合，", "一聲畫角嚴城暮，雲雨分時滿路光。"]'),
('yuding-14','游東湖黃處士園林','劉威','唐','御定全唐诗','yuding','','[]','偶向東湖更向東，數聲雞犬翠微中。遙知楊柳是門處，',40,'御定全唐詩/json/562.json','["偶向東湖更向東，數聲雞犬翠微中。遙知楊柳是門處，", "物情多與閑相稱，所恨求安計不同。"]'),
('yuding-15','題許子正處士新池','劉威','唐','御定全唐诗','yuding','','[]','坐愛風塵日已西，功成得與化工齊。巧分孤島思何遠，',40,'御定全唐詩/json/562.json','["坐愛風塵日已西，功成得與化工齊。巧分孤島思何遠，", "那堪更到芙蓉拆，晚夕香聯桃李蹊。"]'),
('yuding-16','旅懷','劉威','唐','御定全唐诗','yuding','','[]','物態人心漸渺茫，十年徒學釣滄浪。老將何面還吾土，',40,'御定全唐詩/json/562.json','["物態人心漸渺茫，十年徒學釣滄浪。老將何面還吾土，", "無名無位卻無事，醉落烏紗臥夕陽。"]'),
('yuding-17','早秋歸','劉威','唐','御定全唐诗','yuding','','[]','數口飄零身未回，夢魂遙斷越王台。家書欲寄雁飛遠，',40,'御定全唐詩/json/562.json','["數口飄零身未回，夢魂遙斷越王台。家書欲寄雁飛遠，", "茫茫歸路在何處，砧杵一聲心已摧。"]'),
('yuding-18','歐陽示新詩因貽四韻','劉威','唐','御定全唐诗','yuding','','[]','沖戛瑤瓊得至音，數篇清越應南金。都由苦思無休日，',40,'御定全唐詩/json/562.json','["沖戛瑤瓊得至音，數篇清越應南金。都由苦思無休日，", "欲知字字驚神鬼，一氣秋時試夜吟。"]'),
('yuding-19','尉遲將軍','劉威','唐','御定全唐诗','yuding','','[]','天仗擁門希授鉞，重臣入夢豈安金。江河定後威風在，',40,'御定全唐詩/json/562.json','["天仗擁門希授鉞，重臣入夢豈安金。江河定後威風在，", "明妃若遇英雄世，青塚何由怨陸沉。"]'),
('yuding-20','贈歐陽秀才','劉威','唐','御定全唐诗','yuding','','[]','桐上知音日下身，道光誰不仰清塵。偶來水館逢為客，',40,'御定全唐詩/json/562.json','["桐上知音日下身，道光誰不仰清塵。偶來水館逢為客，", "權門要路應行遍，閑伴山夫一夜貧。"]'),
('yuding-21','贈道者','劉威','唐','御定全唐诗','yuding','','[]','五雲深處有真仙，歲月催多卻少年。入郭不知今世事，',40,'御定全唐詩/json/562.json','["五雲深處有真仙，歲月催多卻少年。入郭不知今世事，", "時向人間深夜坐，鬼神長在藥囊邊。"]'),
('yuding-22','贈道者','劉威','唐','御定全唐诗','yuding','','[]','道帔輕裾三島雲，綠髯長占鏡中春。高風已駕祥鸞馭，',40,'御定全唐詩/json/562.json','["道帔輕裾三島雲，綠髯長占鏡中春。高風已駕祥鸞馭，", "儒生也愛長生術，不見人間大笑人。"]'),
('yuding-23','遣懷寄歐陽秀才','劉威','唐','御定全唐诗','yuding','','[]','地上江河天上烏，百年流轉只須臾。平生閑過日將日，',40,'御定全唐詩/json/562.json','["地上江河天上烏，百年流轉只須臾。平生閑過日將日，", "古來晚達人何限，莫笑空枝猶望蘇。"]'),
('yuding-24','送元秀才入道','劉威','唐','御定全唐诗','yuding','','[]','不教榮樂損天機，願逐鸞皇次第飛。明月滿時開道帔，',40,'御定全唐詩/json/562.json','["不教榮樂損天機，願逐鸞皇次第飛。明月滿時開道帔，", "空有緘題報親愛，一千年後始西歸。"]'),
('yuding-25','三閭大夫','劉威','唐','御定全唐诗','yuding','','[]','三閭一去湘山老，煙水悠悠痛古今。青史已書殷鑒在，',40,'御定全唐詩/json/562.json','["三閭一去湘山老，煙水悠悠痛古今。青史已書殷鑒在，", "再引離騷見微旨，肯教漁父會升沈。"]'),
('yuding-26','傷曾秀才馬','劉威','唐','御定全唐诗','yuding','','[]','買得龍媒越水濆，輕桃細杏色初分。秋歸未過陽關日，',40,'御定全唐詩/json/562.json','["買得龍媒越水濆，輕桃細杏色初分。秋歸未過陽關日，", "臨軒振策休惆悵，坐致煙霄只在君。"]'),
('yuding-27','噴玉泉冥會詩八首：白衣叟途中吟二首','李玖','唐','御定全唐诗','yuding','','[]','春草萋萋春水綠，野棠開盡飄香玉。',56,'御定全唐詩/json/562.json','["春草萋萋春水綠，野棠開盡飄香玉。", "繡嶺宮前鶴發人，猶唱開元太平曲。", "厭世逃名者，誰能答姓名。曾聞王樂否，眷取路傍情。"]'),
('yuding-28','噴玉泉冥會詩八首：白衣叟述甘棠館西楹詩','李玖','唐','御定全唐诗','yuding','','[]','浮雲淒慘日微明，沉痛將軍負罪名。白晝叫閽無近戚，',40,'御定全唐詩/json/562.json','["浮雲淒慘日微明，沉痛將軍負罪名。白晝叫閽無近戚，", "六合茫茫皆漢土，此身無處哭田橫。"]'),
('yuding-29','噴玉泉冥會詩八首：白衣叟噴玉泉感舊遊書懷','李玖','唐','御定全唐诗','yuding','','[]','樹色川光向晚晴，舊曾遊處事分明。鼠穿月榭荊榛合，',40,'御定全唐詩/json/562.json','["樹色川光向晚晴，舊曾遊處事分明。鼠穿月榭荊榛合，", "傷心穀口東流水，猶噴當時寒玉聲。"]'),
('yuding-30','噴玉泉冥會詩八首：四丈夫同賦','李玖','唐','御定全唐诗','yuding','','[]','鳥啼鶯語思何窮，一世榮華一夢中。李固有冤藏蠹簡，',160,'御定全唐詩/json/562.json','["鳥啼鶯語思何窮，一世榮華一夢中。李固有冤藏蠹簡，", "春月不知人事改，閑垂光影照洿宮。", "桃蹊李徑盡荒涼，訪舊尋新益自傷。雖有衣衾藏李固，", "天爵竟為人爵誤，誰能高叫問蒼蒼。", "落花寂寂草綿綿，雲影山光盡宛然。壞室基摧新石鼠，", "惆悵林間中夜月，孤光曾照讀書筵。", "新荊棘路舊衡門，又駐高車會一尊。寒骨未沾新雨露，", "珍重昔年金谷友，共來泉際話幽魂。"]'),
('yuding-31','下第歸宜春酬黃頗餞別','潘唐','唐','御定全唐诗','yuding','','[]','聖代澄清雨露均，獨懷惆悵出咸秦。承明未薦相如賦，',40,'御定全唐詩/json/562.json','["聖代澄清雨露均，獨懷惆悵出咸秦。承明未薦相如賦，", "一從此地曾攜手，益羨江頭桃李春。"]'),
('yuding-0','題泐潭','裴休','唐','御定全唐诗','yuding','','[]','泐潭形勝地，祖塔在雲湄。浩劫有窮日，真風無墜時。',48,'御定全唐詩/json/563.json','["泐潭形勝地，祖塔在雲湄。浩劫有窮日，真風無墜時。", "歲華空自老，消息竟誰知。到此輕塵慮，功名自可遺。"]'),
('yuding-1','贈黃蘖山僧希運','裴休','唐','御定全唐诗','yuding','','[]','曾傳達士心中印，額有圓珠七尺身。掛錫十年棲蜀水，',40,'御定全唐詩/json/563.json','["曾傳達士心中印，額有圓珠七尺身。掛錫十年棲蜀水，", "擬欲事師為弟子，不知將法付何人。"]'),
('yuding-2','登望京樓賦','令狐綯','唐','御定全唐诗','yuding','','[]','夷門一鎮五經秋，未得朝天不免愁。',32,'御定全唐詩/json/563.json','["夷門一鎮五經秋，未得朝天不免愁。", "因上此樓望京國，便名樓作望京樓。"]'),
('yuding-3','享太廟樂章','夏侯孜','唐','御定全唐诗','yuding','','[]','於鑠令主，聖祚重昌。興起教義，申明典章。',40,'御定全唐詩/json/563.json','["於鑠令主，聖祚重昌。興起教義，申明典章。", "俗尚素樸，人皆樂康。積德可報，流慶無疆。"]'),
('yuding-4','和重陽錫宴禦制詩','魏謨','唐','御定全唐诗','yuding','','[]','四方無事去，宸豫杪秋來。八水寒光起，千山霽色開。',24,'御定全唐詩/json/563.json','["四方無事去，宸豫杪秋來。八水寒光起，千山霽色開。"]'),
('yuding-5','賀王僕射放榜','周墀','唐','御定全唐诗','yuding','','[]','文場三化魯儒生，三十餘年振重名。曾忝木雞誇羽翼，',40,'御定全唐詩/json/563.json','["文場三化魯儒生，三十餘年振重名。曾忝木雞誇羽翼，", "欲到龍門看風雨，關防不許暫離營。"]'),
('yuding-6','酬李常侍立秋日奉詔祭嶽見寄','周墀','唐','御定全唐诗','yuding','','[]','秋祠靈嶽奉尊罍，風過深林古柏開。蓮掌月高珪幣列，',40,'御定全唐詩/json/563.json','["秋祠靈嶽奉尊罍，風過深林古柏開。蓮掌月高珪幣列，", "豈是瑣才能祀事，洪農太守主張來。"]'),
('yuding-7','寄華州周侍郎立秋日奉詔祭岳詩','李景讓','唐','御定全唐诗','yuding','','[]','關河豁靜曉雲開，承詔秋祠太守來。山霽蓮花添翠黛，',40,'御定全唐詩/json/563.json','["關河豁靜曉雲開，承詔秋祠太守來。山霽蓮花添翠黛，", "往歲今朝幾時事，謝君非重我非才。"]'),
('yuding-8','句','李景讓','唐','御定全唐诗','yuding','','[]','成都十萬戶，拋若一鴻毛。',12,'御定全唐詩/json/563.json','["成都十萬戶，拋若一鴻毛。"]'),
('yuding-9','續夢中十韻','鄭顥','唐','御定全唐诗','yuding','','[]','間歲流虹節，歸軒出禁扃。奔波陶畏景，蕭灑夢殊庭。',120,'御定全唐詩/json/563.json','["間歲流虹節，歸軒出禁扃。奔波陶畏景，蕭灑夢殊庭。", "境象非曾到，崇嚴昔未經。日斜烏斂翼，風動鶴飄翎。", "異苑人爭集，涼臺筆不停。石門霧露白，玉殿莓苔青。", "若匪災先兆，何緣思入冥。禦爐虛仗馬，華蓋負雲亭。", "白日成千古，金縢閟九齡。小臣哀絕筆，湖上泣青萍。"]'),
('yuding-10','揚州送人','劉綺莊','唐','御定全唐诗','yuding','','[]','桂楫木蘭舟，楓江竹箭流。故人從此去，望遠不勝愁。',48,'御定全唐詩/json/563.json','["桂楫木蘭舟，楓江竹箭流。故人從此去，望遠不勝愁。", "落日低帆影，歸風引棹謳。思君折楊柳，淚盡武昌樓。"]'),
('yuding-11','置酒','劉綺莊','唐','御定全唐诗','yuding','','[]','酒熟人須飲，春還鬢已秋。願逢千日醉，得逭百年愁。',48,'御定全唐詩/json/563.json','["酒熟人須飲，春還鬢已秋。願逢千日醉，得逭百年愁。", "卒卒周姬旦，棲棲魯孔丘。平生能幾日，不及且遨遊。"]'),
('yuding-12','重陽宴東觀山亭和從事盧順之','張固','唐','御定全唐诗','yuding','','[]','亂山青翠郡城東，爽節憑高一望通。交友會時絲管合，',40,'御定全唐詩/json/563.json','["亂山青翠郡城東，爽節憑高一望通。交友會時絲管合，", "高詠已勞潘嶽思，醉歡慚道自車公。"]'),
('yuding-13','獨秀山','張固','唐','御定全唐诗','yuding','','[]','孤峰不與眾山儔，直入青雲勢未休。',32,'御定全唐詩/json/563.json','["孤峰不與眾山儔，直入青雲勢未休。", "曾得乾坤融結意，擎天一柱在南州。"]'),
('yuding-14','長門怨','劉皋','唐','御定全唐诗','yuding','','[]','營營孤思通，寂寂長門夜。妾妒亦知非，君恩那不借。',48,'御定全唐詩/json/563.json','["營營孤思通，寂寂長門夜。妾妒亦知非，君恩那不借。", "攜琴就玉階，調悲聲未諧。將心寄明月，流影入君懷。"]'),
('yuding-15','宿日觀東房詩','李質','唐','御定全唐诗','yuding','','[]','曾入桃溪路，仙源信少雙。洞霞飄素練，蘚壁畫陰窗。',48,'御定全唐詩/json/563.json','["曾入桃溪路，仙源信少雙。洞霞飄素練，蘚壁畫陰窗。", "古木愁撐月，危峰欲墮江。自吟空向寂，誰共倒秋缸。"]'),
('yuding-16','贈副戎','南卓','唐','御定全唐诗','yuding','','[]','翱翔曾在玉京天，墮落江南路幾千。',32,'御定全唐詩/json/563.json','["翱翔曾在玉京天，墮落江南路幾千。", "從事不須輕縣宰，滿身猶帶禦爐煙。"]'),
('yuding-17','命妓盛小叢歌餞崔侍禦還闕','李訥','唐','御定全唐诗','yuding','','[]','繡衣奔命去情多，南國佳人斂翠娥。',32,'御定全唐詩/json/563.json','["繡衣奔命去情多，南國佳人斂翠娥。", "曾向教坊聽國樂，為君重唱盛叢歌。"]'),
('yuding-18','李尚書命妓歌餞有作奉酬','崔元範','唐','御定全唐诗','yuding','','[]','羊公留宴峴山亭，洛浦高歌五夜情。',32,'御定全唐詩/json/563.json','["羊公留宴峴山亭，洛浦高歌五夜情。", "獨向柏台為老吏，可憐林木響餘聲。"]'),
('yuding-19','和李尚書命妓歌餞崔侍禦','楊知至','唐','御定全唐诗','yuding','','[]','燕趙能歌有幾人，為花回雪似含顰。',32,'御定全唐詩/json/563.json','["燕趙能歌有幾人，為花回雪似含顰。", "聲隨禦史西歸去，誰伴文翁怨九春。"]'),
('yuding-20','覆落後呈同年','楊知至','唐','御定全唐诗','yuding','','[]','由來梁雁與冥鴻，不合翩翩向碧空。寒谷謾勞鄒氏律，',40,'御定全唐詩/json/563.json','["由來梁雁與冥鴻，不合翩翩向碧空。寒谷謾勞鄒氏律，", "二月春光正搖盪，無因得醉杏園中。"]'),
('yuding-21','送韋覲謫潘州','李明遠','唐','御定全唐诗','yuding','','[]','北鳥飛不到，南人誰去遊。天涯浮瘴水，嶺外向潘州。',48,'御定全唐詩/json/563.json','["北鳥飛不到，南人誰去遊。天涯浮瘴水，嶺外向潘州。", "草木春秋暮，猿猱日夜愁。定知遷客淚，應只對君流。"]'),
('yuding-22','前望江麹令頌德','蕭縝','唐','御定全唐诗','yuding','','[]','政績雖殊道且同，無辭買石紀前功。',32,'御定全唐詩/json/563.json','["政績雖殊道且同，無辭買石紀前功。", "誰論重德光青史，過裏猶歌臥轍風。"]'),
('yuding-23','重陽東觀席上贈侍郎張固','盧順之','唐','御定全唐诗','yuding','','[]','渡江旌旆動魚龍，令節開筵上碧峰。翡翠巢低岩桂小，',40,'御定全唐詩/json/563.json','["渡江旌旆動魚龍，令節開筵上碧峰。翡翠巢低岩桂小，", "好是謝公高興處，夕陽歸騎出疏鬆。"]'),
('yuding-24','責漢水辭','李善夷','唐','御定全唐诗','yuding','','[]','漢之廣兮，風波四起。雖有風波，不如蹄涔之水。',94,'御定全唐詩/json/563.json','["漢之廣兮，風波四起。雖有風波，不如蹄涔之水。", "蹄涔之水，不為下國而傾天子。漢之深兮，其堤莫量。", "雖雲莫量，不如行潦之汪。行潦之汪，不為下國而溺天王。", "漢之美者曰魴。吾雖饑不食其魴，恐汙吾之饑腸。"]'),
('yuding-25','大堤曲','李善夷','唐','御定全唐诗','yuding','','[]','酒旗相望大堤頭，堤下連檣堤上樓。',32,'御定全唐詩/json/563.json','["酒旗相望大堤頭，堤下連檣堤上樓。", "日暮行人爭渡急，槳聲幽軋滿中流。"]'),
('yuding-26','金燈','盧溵','唐','御定全唐诗','yuding','','[]','疏莖秋擁翠，幽豔夕添紅。有月長燈在，無煙燼火同。',48,'御定全唐詩/json/563.json','["疏莖秋擁翠，幽豔夕添紅。有月長燈在，無煙燼火同。", "香濃初受露，勢庳不知風。應笑金臺上，先隨曉漏終。"]'),
('yuding-27','和李尚書命妓餞崔侍禦','盧溵','唐','御定全唐诗','yuding','','[]','烏臺上客紫髯公，共捧天書靜境中。',32,'御定全唐詩/json/563.json','["烏臺上客紫髯公，共捧天書靜境中。", "桃朵不辭歌白苧，耶溪暮雨起樵風。"]'),
('yuding-28','對酒','趙牧','唐','御定全唐诗','yuding','','[]','雲翁耕扶桑，種黍養日烏。手挼六十花甲子，',68,'御定全唐詩/json/563.json','["雲翁耕扶桑，種黍養日烏。手挼六十花甲子，", "饑魂吊骨吟古書，馮唐八十無高車。人生如雲在須臾，", "桐君桂父豈勝我，醉裏白龍多上升。菖蒲花開魚尾定，"]'),
('yuding-29','南歌子詞三首','裴諴','唐','御定全唐诗','yuding','','[]','不是廚中丳，爭知炙裏心。井邊銀釧落，輾轉恨還深。',72,'御定全唐詩/json/563.json','["不是廚中丳，爭知炙裏心。井邊銀釧落，輾轉恨還深。", "不信長相憶，抬頭問取天。風吹荷葉動，無夜不搖蓮。", "簳蠟為紅燭，情知不自由。細絲斜結網，爭奈眼相鉤。"]'),
('yuding-30','新添聲楊柳枝詞','裴諴','唐','御定全唐诗','yuding','','[]','思量大是惡姻緣，只得相看不得憐。',64,'御定全唐詩/json/563.json','["思量大是惡姻緣，只得相看不得憐。", "願作琵琶槽那畔，得他長抱在胸前。", "獨房蓮子沒有看，偷折蓮時命也拌。", "若有所由來借問，但道偷蓮是下官。"]'),
('yuding-0','夏杪登越王樓臨涪江望雪山寄朝中知友','于興宗','唐','御定全唐诗','yuding','','[]','巴西西北樓，堪望亦堪愁。山亂江回遠，川清樹欲秋。',48,'御定全唐詩/json/564.json','["巴西西北樓，堪望亦堪愁。山亂江回遠，川清樹欲秋。", "晴明中雪嶺，煙靄下漁舟。寫寄朝天客，知余恨獨遊。"]'),
('yuding-1','《東陽涵碧亭','于興宗','唐','御定全唐诗','yuding','','[]','高低竹雜松，積翠複留風。路劇陰溪裏，寒生暑氣中。',24,'御定全唐詩/json/564.json','["高低竹雜松，積翠複留風。路劇陰溪裏，寒生暑氣中。"]'),
('yuding-2','奉酬綿州中丞以江山小圖遠垂賜及兼寄詩','李朋','唐','御定全唐诗','yuding','','[]','巴江與雪山，井邑共回環。圖寫丹青內，分明煙靄間。',48,'御定全唐詩/json/564.json','["巴江與雪山，井邑共回環。圖寫丹青內，分明煙靄間。", "移君名郡興，助我小齋閑。日想登臨處，高蹤不可攀。"]'),
('yuding-3','奉酬於中丞登越王樓見寄之什','楊牢','唐','御定全唐诗','yuding','','[]','劍外書來日，驚忙自折封。丹青得山水，強健慰心胸。',72,'御定全唐詩/json/564.json','["劍外書來日，驚忙自折封。丹青得山水，強健慰心胸。", "事少勝諸郡，江回見幾重。寧悲久作別，且似一相逢。", "詩合焚香詠，愁應賴酒濃。庾樓寒更憶，腸斷雪千峰。"]'),
('yuding-4','贈舍弟','楊牢','唐','御定全唐诗','yuding','','[]','秦雲蜀浪兩堪愁，爾養晨昏我遠遊。千里客心難寄夢，',40,'御定全唐詩/json/564.json','["秦雲蜀浪兩堪愁，爾養晨昏我遠遊。千里客心難寄夢，", "袖裏鏌鋣光似水，丈夫不合等閒休。"]'),
('yuding-5','句','楊牢','唐','御定全唐诗','yuding','','[]','蝦蟆欲吃月，保護常教圓。',69,'御定全唐詩/json/564.json','["蝦蟆欲吃月，保護常教圓。", "心明外不察，月向懷中圓。", "羅幃若不卷，誰道中無人。（牢性情急，累居幕府，", "魁形下方天頂亞，二十四寸窗中月。（牢年六歲，"]'),
('yuding-6','和綿州於中丞登越王樓見寄','李續','唐','御定全唐诗','yuding','','[]','早年登此樓，退想不勝愁。地遠二千里，時將四十秋。',48,'御定全唐詩/json/564.json','["早年登此樓，退想不勝愁。地遠二千里，時將四十秋。", "邅迍多失路，華皓任虛舟。詩酒雖堪使，何因得共遊。"]'),
('yuding-7','和綿州於中丞登越王樓作','李汶儒','唐','御定全唐诗','yuding','','[]','珍重巴西守，殷勤寄遠情。劍峰當戶碧，詩韻滿樓清。',48,'御定全唐詩/json/564.json','["珍重巴西守，殷勤寄遠情。劍峰當戶碧，詩韻滿樓清。", "日照涪川闊，煙籠雪嶠明。征黃看即及，莫歎滯江城。"]'),
('yuding-8','和于中丞夏杪登越王樓望雪山見寄','田章','唐','御定全唐诗','yuding','','[]','志乖多感物，臨眺更增愁。暑候雖雲夏，江聲已似秋。',48,'御定全唐詩/json/564.json','["志乖多感物，臨眺更增愁。暑候雖雲夏，江聲已似秋。", "雪遙難辨木，村近好維舟。莫恨歸朝晚，朝簪擬勝遊。"]'),
('yuding-9','和綿州於中丞登越王樓作','薛蒙','唐','御定全唐诗','yuding','','[]','左綿江上樓，五馬此銷愁。暑退千山雪，風來萬木秋。',48,'御定全唐詩/json/564.json','["左綿江上樓，五馬此銷愁。暑退千山雪，風來萬木秋。", "邅回猶刺郡，系滯似維舟。即有征黃日，名川莫厭遊。"]'),
('yuding-10','和綿州於中丞登越王樓作','李鄴','唐','御定全唐诗','yuding','','[]','長聽巴西事，看圖勝所聞。江樓明返照，雪嶺亂晴雲。',48,'御定全唐詩/json/564.json','["長聽巴西事，看圖勝所聞。江樓明返照，雪嶺亂晴雲。", "景象詩情在，幽奇筆跡分。使君徒說好，不只怨離群。"]'),
('yuding-11','和綿州於中丞登越王樓作二首','于瑰','唐','御定全唐诗','yuding','','[]','樓因藩邸號，川勢似依樓。顯敞含清暑，嵐光入素秋。',96,'御定全唐詩/json/564.json','["樓因藩邸號，川勢似依樓。顯敞含清暑，嵐光入素秋。", "山宜姑射貌，江泛李膺舟。郢曲思朋執，輕紗畫勝遊。", "極目郡城樓，浮雲拂檻愁。政成多暇日，詩思動先秋。", "遠霽千岩雪，隨波一葉舟。昔曾窺粉繪，今願許陪遊。"]'),
('yuding-12','和於中丞登越王樓','王嚴','唐','御定全唐诗','yuding','','[]','雉堞臨朱檻，登茲便散愁。蟬聲怨炎夏，山色報新秋。',48,'御定全唐詩/json/564.json','["雉堞臨朱檻，登茲便散愁。蟬聲怨炎夏，山色報新秋。", "江轉穿雲樹，心閑隨葉舟。仲宣徒有歎，謝守幾追遊。"]'),
('yuding-13','題越王樓寄獻中丞使君','劉暌','唐','御定全唐诗','yuding','','[]','朱軒迥壓碧煙州，昔歲賢王是勝遊。山簇劍峰朝闕遠，',40,'御定全唐詩/json/564.json','["朱軒迥壓碧煙州，昔歲賢王是勝遊。山簇劍峰朝闕遠，", "今日登臨無限意，同沾惠化自銷愁。"]'),
('yuding-14','秋日登越王樓獻於中丞','李渥','唐','御定全唐诗','yuding','','[]','越王曾牧劍南州，因向城隅建此樓。橫玉遠開千嶠雪，',40,'御定全唐詩/json/564.json','["越王曾牧劍南州，因向城隅建此樓。橫玉遠開千嶠雪，", "徒學仲宣聊四望，且將詞賦好依劉。"]'),
('yuding-15','洋州於中丞頃牧左綿題詩越王樓上朝賢繼和輒課四韻','劉璐','唐','御定全唐诗','yuding','','[]','隔政代君侯，多慚跡令猷。山光來戶牖，江鳥滿汀洲。',48,'御定全唐詩/json/564.json','["隔政代君侯，多慚跡令猷。山光來戶牖，江鳥滿汀洲。", "雅韻征朝客，清詞寫郡樓。至今謠未已，注意在洋州。"]'),
('yuding-16','和於中丞登越王樓作','盧栯','唐','御定全唐诗','yuding','','[]','圖畫越王樓，開緘慰別愁。山光涵雪冷，水色帶江秋。',48,'御定全唐詩/json/564.json','["圖畫越王樓，開緘慰別愁。山光涵雪冷，水色帶江秋。", "雲島孤征雁，煙帆一葉舟。向風舒霽景，如伴謝公遊。"]'),
('yuding-17','飛鴻響遠音','李體仁','唐','御定全唐诗','yuding','','[]','漠漠微霜夕，翩翩出渚鴻。清聲流迥野，高韻入寥空。',72,'御定全唐詩/json/564.json','["漠漠微霜夕，翩翩出渚鴻。清聲流迥野，高韻入寥空。", "舊質經寒塞，殘音響遠風。縈雪猶類網，避月尚疑弓。", "弱羽雖能振，丹霄竟未通。欲知多怨思，聽取暮煙中。"]'),
('yuding-0','春愁','韓琮','唐','御定全唐诗','yuding','','[]','金烏長飛玉兔走，青鬢長青古無有。秦娥十六語如弦，',40,'御定全唐詩/json/565.json','["金烏長飛玉兔走，青鬢長青古無有。秦娥十六語如弦，", "勸君年少莫遊春，暖風遲日濃於酒。"]'),
('yuding-1','牡丹','韓琮','唐','御定全唐诗','yuding','','[]','殘花何處藏，盡在牡丹房。嫩蕊包金粉，重葩結繡囊。',48,'御定全唐詩/json/565.json','["殘花何處藏，盡在牡丹房。嫩蕊包金粉，重葩結繡囊。", "雲凝巫峽夢，簾閉景陽妝。應恨年華促，遲遲待日長。"]'),
('yuding-2','興平縣野中得落星石移置縣齋','韓琮','唐','御定全唐诗','yuding','','[]','的的墮芊蒼，茫茫不記年。幾逢疑虎將，應逐犯牛仙。',48,'御定全唐詩/json/565.json','["的的墮芊蒼，茫茫不記年。幾逢疑虎將，應逐犯牛仙。", "擇地依蘭畹，題詩間錦錢。何時成五色，卻上女媧天。"]'),
('yuding-3','題商山店','韓琮','唐','御定全唐诗','yuding','','[]','商山驛路幾經過，未到仙娥見謝娥。紅錦機頭拋皓腕，',40,'御定全唐詩/json/565.json','["商山驛路幾經過，未到仙娥見謝娥。紅錦機頭拋皓腕，", "碧澗門前一條水，豈知平地有天河。"]'),
('yuding-4','風','韓琮','唐','御定全唐诗','yuding','','[]','競持飄忽意何窮，為盛為衰半不同。偃草喜逢新雨後，',40,'御定全唐詩/json/565.json','["競持飄忽意何窮，為盛為衰半不同。偃草喜逢新雨後，", "莫見東風便無定，滿帆還有濟川功。"]'),
('yuding-5','雲','韓琮','唐','御定全唐诗','yuding','','[]','深惹離情靄落暉，如車如蓋早依依。山頭觸石應常在，',40,'御定全唐詩/json/565.json','["深惹離情靄落暉，如車如蓋早依依。山頭觸石應常在，", "春風淡蕩無心後，見說襄王夢亦稀。"]'),
('yuding-6','露','韓琮','唐','御定全唐诗','yuding','','[]','長隨聖澤墮堯天，濯遍幽蘭葉葉鮮。才喜輕塵銷陌上，',40,'御定全唐詩/json/565.json','["長隨聖澤墮堯天，濯遍幽蘭葉葉鮮。才喜輕塵銷陌上，", "幾處花枝抱離恨，曉風殘月正潸然。"]'),
('yuding-7','霞','韓琮','唐','御定全唐诗','yuding','','[]','應是行雲未擬歸，變成春態媚晴暉。深如綺色斜分閣，',40,'御定全唐詩/json/565.json','["應是行雲未擬歸，變成春態媚晴暉。深如綺色斜分閣，", "曉來何處低臨水，無限鴛鴦妒不飛。"]'),
('yuding-8','潁亭','韓琮','唐','御定全唐诗','yuding','','[]','潁上新亭瞰一川，幾重舊址敞幽關。寒聲北下當軒水，',40,'御定全唐詩/json/565.json','["潁上新亭瞰一川，幾重舊址敞幽關。寒聲北下當軒水，", "知君久負巢由志，早晚相忘寂寞間。"]'),
('yuding-9','詠馬','韓琮','唐','御定全唐诗','yuding','','[]','曾經伯樂識長鳴，不似龍行不敢行。金埒未登嘶若是，',40,'御定全唐詩/json/565.json','["曾經伯樂識長鳴，不似龍行不敢行。金埒未登嘶若是，", "早晚飛黃引同皂，碧雲天上作鸞鳴。"]'),
('yuding-10','題圭峰下長孫家林亭','韓琮','唐','御定全唐诗','yuding','','[]','趙國林亭二百年，綠苔如毯葛如煙。閑期竹色搖霜看，',40,'御定全唐詩/json/565.json','["趙國林亭二百年，綠苔如毯葛如煙。閑期竹色搖霜看，", "明知富貴非身物，莫為金章墮地仙。"]'),
('yuding-11','牡丹','韓琮','唐','御定全唐诗','yuding','','[]','桃時杏日不爭濃，葉帳陰成始放紅。曉豔遠分金掌露，',40,'御定全唐詩/json/565.json','["桃時杏日不爭濃，葉帳陰成始放紅。曉豔遠分金掌露，", "如夢如仙忽零落，暮霞何處綠屏空。"]'),
('yuding-12','雨','韓琮','唐','御定全唐诗','yuding','','[]','陰雲拂地散絲輕，長得為霖濟物名。夜浦漲歸天塹闊，',40,'御定全唐詩/json/565.json','["陰雲拂地散絲輕，長得為霖濟物名。夜浦漲歸天塹闊，", "不及流他荷葉上，似珠無數轉分明。"]'),
('yuding-13','京西即事','韓琮','唐','御定全唐诗','yuding','','[]','秋草河蘭起陣雲，涼州唯向管弦聞。豺狼毳幕三千帳，',40,'御定全唐詩/json/565.json','["秋草河蘭起陣雲，涼州唯向管弦聞。豺狼毳幕三千帳，", "昭陽亦待平安火，誰握旌旗不見勳。"]'),
('yuding-14','公子行','韓琮','唐','御定全唐诗','yuding','','[]','紫袖長衫色，銀蟬半臂花。帶裝盤水玉，鞍繡坐雲霞。',96,'御定全唐詩/json/565.json','["紫袖長衫色，銀蟬半臂花。帶裝盤水玉，鞍繡坐雲霞。", "別殿承恩澤，飛龍賜渥窪。控羅青褭轡，鏤象碧熏葩。", "意氣傾歌舞，闌珊走鈿車。袖障雲縹緲，釵轉鳳欹斜。", "珠卷迎歸箔，雕籠晃醉紗。唯無難夜日，不得似仙家。"]'),
('yuding-15','秋晚信州推院親友或責無書，即事寄答','韓琮','唐','御定全唐诗','yuding','','[]','官信安仁拙，書非叔夜慵。謬馳驄馬傳，難附鯉魚封。',144,'御定全唐詩/json/565.json','["官信安仁拙，書非叔夜慵。謬馳驄馬傳，難附鯉魚封。", "萬里勞何補，千年運忝逢。不量橫草力，虛慕入雲蹤。", "潔水空澄鑒，持鉛亦礪鋒。月寒深夜桂，霜凜近秋松。", "憲摘無逃魏，冤申得夢馮。問狸將挾虎，殲蠆敢虞蜂。", "商吹移砧調，春華改鏡容。歸期方畹積，愁思暮山重。", "仙鼠猶驚燕，莎雞欲變蛩。唯應碧湘浦，雲落及芙蓉。"]'),
('yuding-16','晚春江晴寄友人','韓琮','唐','御定全唐诗','yuding','','[]','晚日低霞綺，晴山遠畫眉。春青河畔草，不是望鄉時。',24,'御定全唐詩/json/565.json','["晚日低霞綺，晴山遠畫眉。春青河畔草，不是望鄉時。"]'),
('yuding-17','涼州詞','韓琮','唐','御定全唐诗','yuding','','[]','樹發花如錦，鶯啼柳若絲。更遊歡宴地，悲見別離時。',24,'御定全唐詩/json/565.json','["樹發花如錦，鶯啼柳若絲。更遊歡宴地，悲見別離時。"]'),
('yuding-18','暮春滻水送別','韓琮','唐','御定全唐诗','yuding','','[]','綠暗紅稀出鳳城，暮雲樓閣古今情。',32,'御定全唐詩/json/565.json','["綠暗紅稀出鳳城，暮雲樓閣古今情。", "行人莫聽宮前水，流盡年光是此聲。"]'),
('yuding-19','駱穀晚望','韓琮','唐','御定全唐诗','yuding','','[]','秦川如畫渭如絲，去國還家一望時。',32,'御定全唐詩/json/565.json','["秦川如畫渭如絲，去國還家一望時。", "公子王孫莫來好，嶺花多是斷腸枝。"]'),
('yuding-20','二月二日遊洛源','韓琮','唐','御定全唐诗','yuding','','[]','舊苑新晴草似苔，人還香在踏青回。',32,'御定全唐詩/json/565.json','["舊苑新晴草似苔，人還香在踏青回。", "今朝此地成惆悵，已後逢春更莫來。"]'),
('yuding-21','柳','韓琮','唐','御定全唐诗','yuding','','[]','折柳歌中得翠條，遠移金殿種青霄。',32,'御定全唐詩/json/565.json','["折柳歌中得翠條，遠移金殿種青霄。", "上陽宮女含聲送，不忿先歸舞細腰。"]'),
('yuding-22','楊柳枝','韓琮','唐','御定全唐诗','yuding','','[]','梁苑隋堤事已空，萬條猶舞舊春風。',32,'御定全唐詩/json/565.json','["梁苑隋堤事已空，萬條猶舞舊春風。", "那堪更想千年後，誰見楊花入漢宮。"]'),
('yuding-23','楊柳枝詞','韓琮','唐','御定全唐诗','yuding','','[]','枝鬥纖腰葉鬥眉，春來無處不如絲。',32,'御定全唐詩/json/565.json','["枝鬥纖腰葉鬥眉，春來無處不如絲。", "霸陵原上多離別，少有長條拂地垂。"]'),
('yuding-0','和襄陽徐相公商賀徐副使加章綬','王傳','唐','御定全唐诗','yuding','','[]','朱紫聯輝照日新，芳菲全屬斷金人。華筵重處宗盟地，',40,'御定全唐詩/json/566.json','["朱紫聯輝照日新，芳菲全屬斷金人。華筵重處宗盟地，", "自憐亦是膺門客，吟想恩榮氣益振。"]'),
('yuding-1','和李尚書命妓餞崔侍禦','盧鄴','唐','御定全唐诗','yuding','','[]','何郎載酒別賢侯，更吐歌珠宴庾樓。',32,'御定全唐詩/json/566.json','["何郎載酒別賢侯，更吐歌珠宴庾樓。", "莫道江南不同醉，即陪舟楫上京遊。"]'),
('yuding-2','松','陸肱','唐','御定全唐诗','yuding','','[]','雪霜知勁質，今古占嘉名。斷砌盤根遠，疏林偃蓋清。',48,'御定全唐詩/json/566.json','["雪霜知勁質，今古占嘉名。斷砌盤根遠，疏林偃蓋清。", "鶴棲何代色，僧老四時聲。鬱鬱心彌久，煙高萬井生。"]'),
('yuding-3','贈王福娘','崔澹','唐','御定全唐诗','yuding','','[]','怪得清風送異香，娉婷仙子曳霓裳。',32,'御定全唐詩/json/566.json','["怪得清風送異香，娉婷仙子曳霓裳。", "惟應錯認偷桃客，曼倩曾為漢侍郎。"]'),
('yuding-4','答問讀書居','莫宣卿','唐','御定全唐诗','yuding','','[]','書屋倚麒麟，不同牛馬路。床頭萬卷書，溪上五龍渡。',48,'御定全唐詩/json/566.json','["書屋倚麒麟，不同牛馬路。床頭萬卷書，溪上五龍渡。", "井汲冽寒泉，桂花香玉露。茅簷無外物，只見青雲護。"]'),
('yuding-5','百官乘月早朝聽殘漏','莫宣卿','唐','御定全唐诗','yuding','','[]','建禮儼朝冠，重門耿夜闌。碧空蟾魄度，清禁漏聲殘。',72,'御定全唐詩/json/566.json','["建禮儼朝冠，重門耿夜闌。碧空蟾魄度，清禁漏聲殘。", "候曉車輿合，淩霜劍佩寒。星河猶皎皎，銀箭尚珊珊。", "杳靄祥光起，霏微瑞氣攢。忻逢聖明代，長願接鵷鸞。"]'),
('yuding-6','賦得水懷珠','莫宣卿','唐','御定全唐诗','yuding','','[]','長川含媚色，波底孕靈珠。素魄生蘋末，圓規照水隅。',72,'御定全唐詩/json/566.json','["長川含媚色，波底孕靈珠。素魄生蘋末，圓規照水隅。", "淪漣冰彩動，蕩漾瑞光鋪。迥夜星同貫，清秋岸不枯。", "江妃思在掌，海客亦忘軀。合浦當還日，恩威信已敷。"]'),
('yuding-7','句','莫宣卿','唐','御定全唐诗','yuding','','[]','我本南山鳳，豈同凡鳥群。',12,'御定全唐詩/json/566.json','["我本南山鳳，豈同凡鳥群。"]'),
('yuding-8','和李尚書命妓餞崔侍禦','封彥卿','唐','御定全唐诗','yuding','','[]','蓮府才為綠水賓，忽乘驄馬入咸秦。',32,'御定全唐詩/json/566.json','["蓮府才為綠水賓，忽乘驄馬入咸秦。", "為君唱作西河調，日暮偏傷去住人。"]'),
('yuding-9','贈釋疏言還道林寺詩','李節','唐','御定全唐诗','yuding','','[]','湘川狺狺兮俗獷且佷，利殺業偷兮吏莫之馴。',97,'御定全唐詩/json/566.json','["湘川狺狺兮俗獷且佷，利殺業偷兮吏莫之馴。", "繄釋氏兮易暴使仁，釋何在兮釋在斯文，", "月沉浦兮煙暝山，檣席捲兮櫓床閑。偃仰兮嘯詠，", "湘川超忽兮落日啘啘，松覆秋亭兮蘭被春苑。", "上人去兮幾千里，何日同遊兮湘川水。"]'),
('yuding-10','和柯古窮居苦日喜雨','韋蟾','唐','御定全唐诗','yuding','','[]','貞機澹少思，雅尚防多僻。攬葛猶不畏，勞形同處瘠。',120,'御定全唐詩/json/566.json','["貞機澹少思，雅尚防多僻。攬葛猶不畏，勞形同處瘠。", "頭焦詎是焚，背汗甯關炙。方欣見潤礎，那虞悲鑠石。", "道與古人期，情難物外適。幾懷朱邸綬，頗曠金門藉。", "清奧已蕭蕭，陳柯將槭槭。玉律詩調正，瓊卮酒腸窄。", "衣桁襲中單，浴床拋下綌。黎侯寓於衛，六義非凡格。"]'),
('yuding-11','岳麓道林寺','韋蟾','唐','御定全唐诗','yuding','','[]','石門迥接蒼梧野，愁色陰深二妃寡。廣殿崔嵬萬壑間，',88,'御定全唐詩/json/566.json','["石門迥接蒼梧野，愁色陰深二妃寡。廣殿崔嵬萬壑間，", "暖日斜明螮蝀梁，濕煙散冪鴛鴦瓦。北方部落檀香塑，", "沈裴筆力鬥雄壯，宋杜詞源兩風雅。他方居士來施齋，", "何時得與劉遺民，同入東林遠公社。"]'),
('yuding-12','上元三首','韋蟾','唐','御定全唐诗','yuding','','[]','新正圓月夜，尤重看燈時。累塔嫌沙細，成文訝筆遲。',144,'御定全唐詩/json/566.json','["新正圓月夜，尤重看燈時。累塔嫌沙細，成文訝筆遲。", "歸牛疑燧落，過雁誤書遲。生惜蘭膏燼，遠為隔歲期。", "舉燭光才起，揮毫勢競分。點時驚墜石，挑處接崩雲。", "辭異秦丞相，銘非竇冠軍。唯愁殘焰落，逢玉亦俱焚。", "多寶神光動，生金瑞色浮。照人低入郭，伴月夜當樓。", "熏穴應無取，焚林固有求。夜闌陪玉帳，不見九枝留。"]'),
('yuding-13','梅','韋蟾','唐','御定全唐诗','yuding','','[]','高樹臨溪豔，低枝隔竹繁。何須是桃李，然後欲忘言。',48,'御定全唐詩/json/566.json','["高樹臨溪豔，低枝隔竹繁。何須是桃李，然後欲忘言。", "擬折魂先斷，須看眼更昏。誰知南陌草，卻解望王孫。"]'),
('yuding-14','送盧潘尚書之靈武','韋蟾','唐','御定全唐诗','yuding','','[]','賀蘭山下果園成，塞北江南舊有名。水木萬家朱戶暗，',40,'御定全唐詩/json/566.json','["賀蘭山下果園成，塞北江南舊有名。水木萬家朱戶暗，", "卻使六番諸子弟，馬前不信是書生。"]'),
('yuding-15','題僧壁','韋蟾','唐','御定全唐诗','yuding','','[]','一竹橫簷掛淨巾，灶無煙火地無塵。',32,'御定全唐詩/json/566.json','["一竹橫簷掛淨巾，灶無煙火地無塵。", "剃頭未必知心法，要且閑于名利人。"]'),
('yuding-16','贈商山僧','韋蟾','唐','御定全唐诗','yuding','','[]','商嶺東西路欲分，兩間茅屋一溪雲。',32,'御定全唐詩/json/566.json','["商嶺東西路欲分，兩間茅屋一溪雲。", "師言耳重知師意，人是人非不欲聞。"]'),
('yuding-17','長樂驛謔李湯給事題名','韋蟾','唐','御定全唐诗','yuding','','[]','渭水秦川拂眼明，希仁何事寡詩情。',32,'御定全唐詩/json/566.json','["渭水秦川拂眼明，希仁何事寡詩情。", "只應學得虞姬婿，書字才能記姓名。"]'),
('yuding-18','句','韋蟾','唐','御定全唐诗','yuding','','[]','爭揮鉤弋手，競聳踏搖身。傷頰詎關舞，捧心非效嚬。',24,'御定全唐詩/json/566.json','["爭揮鉤弋手，競聳踏搖身。傷頰詎關舞，捧心非效嚬。"]'),
('yuding-19','賦得壽星見','盧渥','唐','御定全唐诗','yuding','','[]','玄象今何應，時和政亦平。祥為一人壽，色映九霄明。',72,'御定全唐詩/json/566.json','["玄象今何應，時和政亦平。祥為一人壽，色映九霄明。", "皎潔垂銀漢，光芒近鬥城。含規同月滿，表瑞得天清。", "甘露盈條降，非煙向日生。無如此嘉祉，率土荷秋成。"]'),
('yuding-20','題嘉祥驛','盧渥','唐','御定全唐诗','yuding','','[]','交親榮餞洛城空，秉鉞戎裝上將同。星使自天丹詔下，',40,'御定全唐詩/json/566.json','["交親榮餞洛城空，秉鉞戎裝上將同。星使自天丹詔下，", "到後定知人易化，滿街棠樹有遺風。"]'),
('yuding-21','九華山','郭夔','唐','御定全唐诗','yuding','','[]','岩翠淩雲出迥然，岧嶢萬丈倚秋天。暮風飄送當軒色，',40,'御定全唐詩/json/566.json','["岩翠淩雲出迥然，岧嶢萬丈倚秋天。暮風飄送當軒色，", "畫圖何必家家有，自有畫圖來目前。"]'),
('yuding-22','送莫仲節狀元歸省','柳珪','唐','御定全唐诗','yuding','','[]','青驄聚送謫仙人，南國榮親不及君。椰子味從今日近，',40,'御定全唐詩/json/566.json','["青驄聚送謫仙人，南國榮親不及君。椰子味從今日近，", "想到故鄉應臘過，藥欄猶有異花熏。"]'),
('yuding-0','津陽門詩','鄭嵎','唐','御定全唐诗','yuding','','[]','津陽門北臨通逵，雪風獵獵飄酒旗。泥寒款段蹶不進，',577,'御定全唐詩/json/567.json','["津陽門北臨通逵，雪風獵獵飄酒旗。泥寒款段蹶不進，", "青錢瑣屑安足數，白醪軟美甘如飴。開壚引滿相獻酬，", "主翁移客挑華燈，雙肩隱膝烏帽欹。笑雲鮐老不為禮，", "翁曾豪盛客不見，我自為君陳昔時。時平親衛號羽林，", "此時初創觀風樓，簷高百尺堆華榱。樓南更起鬥雞殿，", "朝元閣成老君見，會昌縣以新豐移。幽州曉進供奉馬，", "羽林六軍各出射，籠山絡野張罝維。雕弓繡韣不知數，", "人煩馬殆禽獸盡，百里腥膻禾黍稀。暖山度臘東風微，", "犀屏象薦雜羅列，錦鳧繡雁相追隨。破簪碎鈿不足拾，", "繞床呼盧恣樗博，張燈達晝相謾欺。相君侈擬縱驕橫，", "畫輪寶軸從天來，雲中笑語聲融怡。鳴鞭後騎何躞蹀，", "驪駒吐沫一奮迅，路人擁篲爭珠璣。八姨新起合歡堂，", "四方節制傾附媚，窮奢極侈沽恩私。堂中特設夜明枕，", "迎娘歌喉玉窈窕，蠻兒舞帶金葳蕤。三郎紫笛弄煙月，", "飲鹿泉邊春露晞，粉梅檀杏飄朱墀。金沙洞口長生殿，", "羅公如意奪顏色，三藏袈裟成散絲。蓬萊池上望秋月，", "月中秘樂天半間，丁璫玉石和塤篪。宸聰聽覽未終曲，", "花萼樓南大合樂，八音九奏鸞來儀。都盧尋橦誠齷齪，", "祿山此時侍禦側，金雞畫障當罘罳。繡do衣褓日屭贔，", "大開內府恣供給，玉缶金筐銀簸箕。異謀潛熾促歸去，", "湯成召浴果不至，潼關已溢漁陽師。禦街一夕無禁鼓，", "縣官無人具軍頓，行宮徹屋屠雲螭。馬嵬驛前駕不發，", "青泥阪上到三蜀，金堤城邊止九旗。移文泣祭昔臣墓，", "兩君相見望賢頓，君臣鼓舞皆歔欷。宮中親呼高驃騎，"]'),
('yuding-1','春日即事','崔櫓','唐','御定全唐诗','yuding','','[]','一百五日又欲來，梨花梅花參差開。行人自笑不歸去，',40,'御定全唐詩/json/567.json','["一百五日又欲來，梨花梅花參差開。行人自笑不歸去，", "畫橋春暖清歌夜，肯信愁腸日九回。"]'),
('yuding-2','春晚岳陽言懷二首','崔櫓','唐','御定全唐诗','yuding','','[]','煙花零落過清明，異國光陰老客情。雲夢夕陽愁裏色，',80,'御定全唐詩/json/567.json','["煙花零落過清明，異國光陰老客情。雲夢夕陽愁裏色，", "獨倚闌幹意難寫，暮笳嗚咽調孤城。", "翠煙如鈿柳如環，晴倚南樓獨看山。江國草花三月暮，", "何以不羈詹父伴，睡煙歌月老潺潺。"]'),
('yuding-3','過蠻溪渡','崔櫓','唐','御定全唐诗','yuding','','[]','綠楊如發雨如煙，立馬危橋獨喚船。山口斷雲迷舊路，',40,'御定全唐詩/json/567.json','["綠楊如發雨如煙，立馬危橋獨喚船。山口斷雲迷舊路，", "歸去楚台還有計，釣船春雨日高眠。"]'),
('yuding-4','岸梅','崔櫓','唐','御定全唐诗','yuding','','[]','含情含怨一枝枝，斜壓漁家短短籬。惹袖尚餘香半日，',40,'御定全唐詩/json/567.json','["含情含怨一枝枝，斜壓漁家短短籬。惹袖尚餘香半日，", "行客見來無去意，解帆煙浦為題詩。"]'),
('yuding-5','重陽日次荊南路經武甯驛','崔櫓','唐','御定全唐诗','yuding','','[]','茱萸冷吹溪口香，菊花倒繞山腳黃。家山去此強百里，',40,'御定全唐詩/json/567.json','["茱萸冷吹溪口香，菊花倒繞山腳黃。家山去此強百里，", "莫看時節年年好，暗送搔頭逐手霜。"]'),
('yuding-6','述懷','崔櫓','唐','御定全唐诗','yuding','','[]','白首成何事，無歡可替悲。空餘酒中興，猶似少年時。',24,'御定全唐詩/json/567.json','["白首成何事，無歡可替悲。空餘酒中興，猶似少年時。"]'),
('yuding-7','三月晦日送客','崔櫓','唐','御定全唐诗','yuding','','[]','野酌亂無巡，送君兼送春。明年春色至，莫作未歸人。',24,'御定全唐詩/json/567.json','["野酌亂無巡，送君兼送春。明年春色至，莫作未歸人。"]'),
('yuding-8','華清宮三首','崔櫓','唐','御定全唐诗','yuding','','[]','草遮回磴絕鳴鑾，雲樹深深碧殿寒。',96,'御定全唐詩/json/567.json','["草遮回磴絕鳴鑾，雲樹深深碧殿寒。", "明月自來還自去，更無人倚玉欄幹。", "障掩金雞蓄禍機，翠華西拂蜀雲飛。", "珠簾一閉朝元閣，不見人歸見燕歸。", "門橫金鎖悄無人，落日秋聲渭水濱。", "紅葉下山寒寂寂，濕雲如夢雨如塵。"]'),
('yuding-9','題雲夢亭','崔櫓','唐','御定全唐诗','yuding','','[]','薄煙如夢雨如塵，霜景晴來卻勝春。',32,'御定全唐詩/json/567.json','["薄煙如夢雨如塵，霜景晴來卻勝春。", "好住池西紅葉樹，何年今日伴何人。"]'),
('yuding-10','有酒失于虔州陸郎中肱，以詩謝之','崔櫓','唐','御定全唐诗','yuding','','[]','醉時顛蹶醒時羞，麹糵推人不自由。',32,'御定全唐詩/json/567.json','["醉時顛蹶醒時羞，麹糵推人不自由。", "叵耐一雙窮相眼，不堪花卉在前頭。"]'),
('yuding-11','聞笛','崔櫓','唐','御定全唐诗','yuding','','[]','銀河漾漾月暉暉，樓礙星邊織女機。',32,'御定全唐詩/json/567.json','["銀河漾漾月暉暉，樓礙星邊織女機。", "橫玉叫雲天似水，滿空霜逐一聲飛。"]'),
('yuding-12','山路見花','崔櫓','唐','御定全唐诗','yuding','','[]','曉紅初拆露香新，獨立空山冷笑人。',32,'御定全唐詩/json/567.json','["曉紅初拆露香新，獨立空山冷笑人。", "春意自知無主惜，恣風吹逐馬蹄塵。"]'),
('yuding-13','暮春對花','崔櫓','唐','御定全唐诗','yuding','','[]','病香無力被風欺，多在青苔少在枝。',32,'御定全唐詩/json/567.json','["病香無力被風欺，多在青苔少在枝。", "馬上行人莫回首，斷君腸是欲殘時。"]'),
('yuding-14','句','崔櫓','唐','御定全唐诗','yuding','','[]','強半瘦因前夜雪，數枝愁向晚天來。（《梅花》。',95,'御定全唐詩/json/567.json','["強半瘦因前夜雪，數枝愁向晚天來。（《梅花》。", "以下並見《摭言》）", "無人解把無塵袖，盛取殘香盡日憐。", "一番春雨吹巢冷，半朵山花咽觜香。", "雲生柱礎降龍地，露洗林巒放鶴天。", "菱葉乍翻人采後，荇花初沒舸行時。"]'),
('yuding-0','烏夜號','李群玉','唐','御定全唐诗','yuding','','[]','層波隔夢渚，一望青楓林。有鳥在其間，達曉自悲吟。',96,'御定全唐詩/json/568.json','["層波隔夢渚，一望青楓林。有鳥在其間，達曉自悲吟。", "是時月黑天，四野煙雨深。如聞生離哭，其聲痛人心。", "悄悄夜正長，空山響哀音。遠客不可聽，坐愁華髮侵。", "既非蜀帝魂，恐是桓山禽。四子各分散，母聲猶至今。"]'),
('yuding-1','升仙操','李群玉','唐','御定全唐诗','yuding','','[]','嬴女去秦宮，瓊笙飛碧空。鳳台閉煙霧，鸞吹飄天風。',72,'御定全唐詩/json/568.json','["嬴女去秦宮，瓊笙飛碧空。鳳台閉煙霧，鸞吹飄天風。", "複聞周太子，亦遇浮丘公。叢簧發天弄，輕舉紫霞中。", "濁世不久駐，清都路何窮。一去霄漢上，世人那得逢。"]'),
('yuding-2','雨夜呈長官','李群玉','唐','御定全唐诗','yuding','','[]','遠客坐長夜，雨聲孤寺秋。請量東海水，看取淺深愁。',96,'御定全唐詩/json/568.json','["遠客坐長夜，雨聲孤寺秋。請量東海水，看取淺深愁。", "愁窮重于山，終年壓人頭。朱顏與芳景，暗赴東波流。", "鱗翼思風水，青雲方阻修。孤燈冷素豔，蟲響寒房幽。", "借問陶淵明，何物號忘憂。無因一酩酊，高枕萬情休。"]'),
('yuding-3','小弟艎南游近書來','李群玉','唐','御定全唐诗','yuding','','[]','湘南客帆稀，遊子寡消息。經時停尺素，望盡雲邊翼。',96,'御定全唐詩/json/568.json','["湘南客帆稀，遊子寡消息。經時停尺素，望盡雲邊翼。", "笑言頻夢寐，獨立想容色。落景無來人，修江入天白。", "停停倚門念，瑟瑟風雨夕。何處泊扁舟，迢遞湍波側。", "秋歸舊窗竹，永夜一淒寂。吟爾鶺鴒篇，中宵慰相憶。"]'),
('yuding-4','贈方處士','李群玉','唐','御定全唐诗','yuding','','[]','白衣方外人，高閑溪中鶴。無心戀稻粱，但以林泉樂。',48,'御定全唐詩/json/568.json','["白衣方外人，高閑溪中鶴。無心戀稻粱，但以林泉樂。", "赤霄終得意，天池俟飛躍。歲晏入帝鄉，期君在寥廓。"]'),
('yuding-5','秋怨','李群玉','唐','御定全唐诗','yuding','','[]','瑟瑟涼海氣，西來送愁容。金風死綠蕙，玉露生寒松。',96,'御定全唐詩/json/568.json','["瑟瑟涼海氣，西來送愁容。金風死綠蕙，玉露生寒松。", "所思在溟碧，無因一相逢。登樓睇去翼，目盡滄波重。", "虛窗度流螢，斜月啼幽蛩。疏紅落殘豔，冷水凋芙蓉。", "歲暮空太息，年華逐遺蹤。凝情耿不寐，攬涕起疏慵。"]'),
('yuding-6','感春','李群玉','唐','御定全唐诗','yuding','','[]','春情不可狀，豔豔令人醉。暮水綠楊愁，深窗落花思。',48,'御定全唐詩/json/568.json','["春情不可狀，豔豔令人醉。暮水綠楊愁，深窗落花思。", "吳宮新暖日，海燕雙飛至。秋思逐煙光，空蒙滿天地。"]'),
('yuding-7','山中秋夕','李群玉','唐','御定全唐诗','yuding','','[]','抱琴出南樓，氣爽浮雲滅。松風吹天簫，竹路踏碎月。',48,'御定全唐詩/json/568.json','["抱琴出南樓，氣爽浮雲滅。松風吹天簫，竹路踏碎月。", "後山鶴唳定，前浦荷香發。境寂良夜深，了與人間別。"]'),
('yuding-8','將游羅浮登廣陵楞伽台別羽客','李群玉','唐','御定全唐诗','yuding','','[]','清遠登高台，晃朗縱覽曆。濯泉喚仙風，於此蕩靈魄。',144,'御定全唐詩/json/568.json','["清遠登高台，晃朗縱覽曆。濯泉喚仙風，於此蕩靈魄。", "冷光邀遠目，百里見海色。送雲歸蓬壺，望鶴滅秋碧。", "波瀾收日氣，天自回澄寂。百越落掌中，十洲點空白。", "身居飛鳥上，口詠玄元籍。飄如出塵籠，想望吹簫客。", "冥冥人間世，歌笑不足惜。朅來羅浮巔，披雲煉瓊液。", "謝公雲岑興，可以躡高跡。吾將抱瑤琴，絕境縱所適。"]'),
('yuding-9','盧溪道中','李群玉','唐','御定全唐诗','yuding','','[]','曉發潺湲亭，夜宿潺湲水。風篁掃石瀨，琴聲九十裏。',48,'御定全唐詩/json/568.json','["曉發潺湲亭，夜宿潺湲水。風篁掃石瀨，琴聲九十裏。", "光奔覺來眼，寒落夢中耳。曾向三峽行，巴江亦如此。"]'),
('yuding-10','湖中古愁三首','李群玉','唐','御定全唐诗','yuding','','[]','涼風西海來，直渡洞庭水。翛翛木葉下，白浪連天起。',144,'御定全唐詩/json/568.json','["涼風西海來，直渡洞庭水。翛翛木葉下，白浪連天起。", "蘅蘭委皓雪，百草一時死。摧殘負志人，感歎何窮已。", "昔我睹雲夢，窮秋經汨羅。靈均竟不返，怨氣成微波。", "奠桂開古祠，朦朧入幽蘿。落日瀟湘上，淒涼吟九歌。", "南雲哭重華，水死悲二女。天邊九點黛，白骨迷處所。", "朦朧波上瑟，清夜降北渚。萬古一雙魂，飄飄在煙雨。"]'),
('yuding-11','別狄佩','李群玉','唐','御定全唐诗','yuding','','[]','翠竹不著花，鳳雛長忍饑。未開凡霄翮，空把碧梧枝。',72,'御定全唐詩/json/568.json','["翠竹不著花，鳳雛長忍饑。未開凡霄翮，空把碧梧枝。", "聖人奏雲韶，祥鳳一來儀。文章耀白日，眾鳥莫敢窺。", "鬱抑不自言，凡鳥何由知。當看九千仞，飛出太平時。"]'),
('yuding-12','古鏡','李群玉','唐','御定全唐诗','yuding','','[]','明月何處來，朦朧在人境。得非軒轅作，妙絕世莫並。',120,'御定全唐詩/json/568.json','["明月何處來，朦朧在人境。得非軒轅作，妙絕世莫並。", "瑤匣開旭日，白電走孤影。泓澄一尺天，徹底寒霜景。", "冰輝凜毛髮，使我肝膽冷。忽驚行深幽，面落九秋井。", "雲天入掌握，爽朗神魂淨。不必負局仙，金沙發光炯。", "陰沉蓄靈怪，可與天地永。恐為悲龍吟，飛去在俄頃。"]'),
('yuding-13','我思何所在','李群玉','唐','御定全唐诗','yuding','','[]','我思何所在，乃在陽臺側。良宵相望時，空此明月色。',72,'御定全唐詩/json/568.json','["我思何所在，乃在陽臺側。良宵相望時，空此明月色。", "歸魂泊湘雲，飄蕩去不得。覺來理舟楫，波浪春湖白。", "煙光浩楚秋，瑤草不忍摘。因書天末心，系此雙飛翼。"]'),
('yuding-14','送蕭綰之桂林','李群玉','唐','御定全唐诗','yuding','','[]','蘭香佩蘭人，弄蘭蘭江春。爾為蘭林秀，芳藻驚常倫。',144,'御定全唐詩/json/568.json','["蘭香佩蘭人，弄蘭蘭江春。爾為蘭林秀，芳藻驚常倫。", "燦燦鳳池裔，一毛今再新。竹花不給口，憔悴清湘濱。", "一朝南溟飛，彩翮不可親。蒼梧雲水晚，離思空凝顰。", "我亦縱煙棹，西浮彭蠡津。丈夫未虎變，落魄甘風塵。", "大禹惜寸陰，況我無才身。流光銷道路，以此生嗟辛。", "萬里闊分袂，相思杳難申。桂水秋更碧，寄書西上鱗。"]'),
('yuding-15','感興四首','李群玉','唐','御定全唐诗','yuding','','[]','子雲吞白鳳，遂吐太玄書。幽微十萬字，枝葉何扶疏。',192,'御定全唐詩/json/568.json','["子雲吞白鳳，遂吐太玄書。幽微十萬字，枝葉何扶疏。", "婉孌猛虎口，甘言累其初。一睹美新作，斯瑕安可除。", "昔竊不死藥，奔空有嫦娥。盈盈天上豔，孤潔棲金波。", "織女了無語，長宵隔銀河。軋軋揮素手，幾時停玉梭。", "洞房三五夕，金釭凝焰滅。美人抱雲和，斜倚紗窗月。", "沈吟想幽夢，閨思深不說。弦冷玉指寒，含顰待明發。", "朔雁銜邊秋，寒聲落燕代。先驚愁人耳，顏發潛消改。", "凝雲蔽洛浦，夢寐勞光彩。天邊無書來，相思淚成海。"]'),
('yuding-16','將之吳越留別坐中文酒諸侶','李群玉','唐','御定全唐诗','yuding','','[]','秋色滿水國，江湖興蕭然。氛埃斂八極，萬里淨澄鮮。',144,'御定全唐詩/json/568.json','["秋色滿水國，江湖興蕭然。氛埃斂八極，萬里淨澄鮮。", "涔浦縱孤棹，吳門渺三千。回隨衡陽雁，南入洞庭天。", "早聞陸士龍，矯掌跨山川。非思鱸魚膾，且弄五湖船。", "暝泊遠浦霞，曉飯蘆洲煙。風流訪王謝，佳境恣洄沿。", "霜剪別岸柳，香枯北池蓮。歲華坐搖落，寂寂感流年。", "明朝即漂萍，離憾無由宣。相思空江上，何處金波圓。"]'),
('yuding-17','大雲池泛舟','李群玉','唐','御定全唐诗','yuding','','[]','九月蓮花死，萍枯霜水清。船浮天光遠，棹拂翠瀾輕。',72,'御定全唐詩/json/568.json','["九月蓮花死，萍枯霜水清。船浮天光遠，棹拂翠瀾輕。", "古木□□□，了無煙靄生。遊鱗泳皎潔，洞見逍遙情。", "漁父一曲歌，滄浪遂知名。未知斯水上，可以濯吾纓。"]'),
('yuding-18','送友人之峽','李群玉','唐','御定全唐诗','yuding','','[]','東吳有賦客，願識陽臺仙。彩毫飛白雲，不減郢中篇。',48,'御定全唐詩/json/568.json','["東吳有賦客，願識陽臺仙。彩毫飛白雲，不減郢中篇。", "楚水五月浪，輕舟入暮煙。巫雲多感夢，桂楫早迴旋。"]'),
('yuding-19','登宜春醉宿景星寺寄鄭判官兼簡空上人','李群玉','唐','御定全唐诗','yuding','','[]','曉發碧水陽，暝宿金山寺。松風灑寒雨，淅瀝醒餘醉。',192,'御定全唐詩/json/568.json','["曉發碧水陽，暝宿金山寺。松風灑寒雨，淅瀝醒餘醉。", "夜中香積飯，蔬粒俱精異。境寂滅塵愁，神高得詩思。", "皎皎滎陽子，芳春富才義。漲海豁心源，冰壺見門地。", "碧霄有鳩序，未展聯行翅。俱笑一尺繩，三年絆騏驥。", "摧藏擔簦客，鬱抑胸襟事。名業爾未從，臨風嘿舒志。", "一身渺雲嶺，中夜空涕泗。側枕對孤燈，衾寒不成寐。", "糧薪極桂玉，大道生榛刺。恥息惡木陰，難書劍歌意。", "揚鞭入莽蒼，山驛淩煙翠。越鳥日南飛，芳音願相次。"]'),
('yuding-20','江樓獨酌懷從叔','李群玉','唐','御定全唐诗','yuding','','[]','水國發爽氣，川光靜高秋。酣歌金尊醁，送此清風愁。',72,'御定全唐詩/json/568.json','["水國發爽氣，川光靜高秋。酣歌金尊醁，送此清風愁。", "楚色忽滿目，灘聲落西樓。雲翻天邊葉，月弄波上鉤。", "芳意長搖落，蘅蘭謝汀洲。長吟碧雲合，悵望江之幽。"]'),
('yuding-21','登章華樓','李群玉','唐','御定全唐诗','yuding','','[]','楚子故宮地，蒼然雲水秋。我來覽從事，落景空生愁。',96,'御定全唐詩/json/568.json','["楚子故宮地，蒼然雲水秋。我來覽從事，落景空生愁。", "伯業沒荊棘，雄圖成古丘。沈吟問鼎語，但見東波流。", "征鴻引鄉心，一去何悠悠。晴湖碧雲晚，暝色空高樓。", "迢遞趨遠嶠，微茫入孤舟。空路不堪望，西風白浪稠。"]'),
('yuding-22','驄馬','李群玉','唐','御定全唐诗','yuding','','[]','浮雲何權奇，絕足世未知。長嘶清海風，蹀躞振雲絲。',96,'御定全唐詩/json/568.json','["浮雲何權奇，絕足世未知。長嘶清海風，蹀躞振雲絲。", "由來渥窪種，本是蒼龍兒。穆滿不再活，無人昆閬騎。", "若識躍嶠怯，甯勞耀金羈。青芻與白水，空笑駑駘肥。", "伯樂儻一見，應驚耳長垂。當思八荒外，逐日向瑤池。"]'),
('yuding-23','贈方處士兼以寫別','李群玉','唐','御定全唐诗','yuding','','[]','天與雲鶴情，人間恣詩酒。龍宮奉采覓，澒洞一千首。',168,'御定全唐詩/json/568.json','["天與雲鶴情，人間恣詩酒。龍宮奉采覓，澒洞一千首。", "清如南熏絲，韻若黃鐘吼。喜於風騷地，忽見陶謝手。", "籍籍九江西，篇篇在人口。芙蓉為芳菲，未落諸花後。", "所知心眼大，別自開戶牖。才力似風鵬，誰能算升鬥。", "無營傲雲竹，琴帙靜為友。鸞鳳戢羽儀，騏驥在郊藪。", "鏡湖春水綠，越客憶歸否。白衣四十秋，逍遙一何久。", "此身無定跡，又逐浮雲走。離思書不窮，殘陽落江柳。"]'),
('yuding-24','湘西寺霽夜','李群玉','唐','御定全唐诗','yuding','','[]','雨過琉璃宮，佳興浩清絕。松風冷晴灘，竹路踏碎月。',72,'御定全唐詩/json/568.json','["雨過琉璃宮，佳興浩清絕。松風冷晴灘，竹路踏碎月。", "月波蕩如水，氣爽星朗滅。皓夜千樹寒，崢嶸萬岩雪。", "後山鶴唳斷，前池荷香發。境寂涼夜深，神思空飛越。"]'),
('yuding-25','傷思','李群玉','唐','御定全唐诗','yuding','','[]','八月白露濃，芙蓉抱香死。紅枯金粉墮，寥落寒塘水。',48,'御定全唐詩/json/568.json','["八月白露濃，芙蓉抱香死。紅枯金粉墮，寥落寒塘水。", "西風團葉下，疊縠參差起。不見棹歌人，空垂綠房子。"]'),
('yuding-26','送鄭京昭之雲安','李群玉','唐','御定全唐诗','yuding','','[]','君吟高唐賦，路過巫山渚。莫令巫山下，幽夢惹雲雨。',72,'御定全唐詩/json/568.json','["君吟高唐賦，路過巫山渚。莫令巫山下，幽夢惹雲雨。", "往事幾千年，芬菲今尚傳。空留荊王館，岩嶂深蒼然。", "楚水五月浪，輕舟入蘋煙。送君揚楫去，愁絕郢城篇。"]'),
('yuding-27','送處士自番禺東游便歸蘇台別業','李群玉','唐','御定全唐诗','yuding','','[]','啞軋暮江上，櫓聲搖落心。宛陵三千里，路指吳雲深。',144,'御定全唐詩/json/568.json','["啞軋暮江上，櫓聲搖落心。宛陵三千里，路指吳雲深。", "蓴菜動歸興，忽然聞會吟。南浮龍川月，東下敬亭岑。", "多君詠逍遙，結蘿碧溪陰。高籠華表鶴，靜對幽蘭琴。", "汗漫江海思，傲然抽冠簪。歸嶼未雲寂，還家應追尋。", "二陸文苑秀，岧嶢懷所欽。惜我入洛晚，不睹雙南金。", "江左風流盡，名賢成古今。送君無限意，別酒但加斟。"]'),
('yuding-28','法華微上人盛話金山境勝，舊遊在目，吟成此篇','李群玉','唐','御定全唐诗','yuding','','[]','江上青蓮宮，人間蓬萊島。煙霞與波浪，隱映樓臺好。',48,'御定全唐詩/json/568.json','["江上青蓮宮，人間蓬萊島。煙霞與波浪，隱映樓臺好。", "潮門梵音靜，海日天光早。願與靈鷲人，吟經此終老。"]'),
('yuding-29','洞庭入澧江寄巴丘故人','李群玉','唐','御定全唐诗','yuding','','[]','四月桑半枝，吳蠶初弄絲。江行好風日，燕舞輕波時。',48,'御定全唐詩/json/568.json','["四月桑半枝，吳蠶初弄絲。江行好風日，燕舞輕波時。", "去事旋成夢，來歡難預期。唯憑東流水，日夜寄相思。"]'),
('yuding-30','自澧浦東游江表，途出巴丘，投員外從公虞','李群玉','唐','御定全唐诗','yuding','','[]','短翮後飛者，前攀鸞鶴翔。力微應萬里，矯首空蒼蒼。',360,'御定全唐詩/json/568.json','["短翮後飛者，前攀鸞鶴翔。力微應萬里，矯首空蒼蒼。", "誰昔探花源，考盤西岳陽。高風動商洛，綺皓無馨香。", "一朝下蒲輪，清輝照岩廊。孤醒立眾醉，古道何由昌。", "經術震浮蕩，國風掃齊梁。文襟即玄圃，筆下成琳琅。", "霞水散吟嘯，松筠奉琴觴。冰壺避皎潔，武庫羞鋒鋩。", "小子書代耕，束發頗自強。艱哉水投石，壯志空摧藏。", "十年侶龜魚，垂頭在沅湘。巴歌掩白雪，鮑肆埋蘭芳。", "騷雅道未喪，何憂名不彰。饑寒束困厄，默塞飛星霜。", "百志不成一，東波擲年光。塵生脫粟甑，萬里違高堂。", "中夜恨火來，焚燒九回腸。平明梁山淚，緣枕沾匡床。", "依泊洞庭波，木葉忽已黃。哀砧搗秋色，曉月啼寒螿。", "複此棹孤舟，雲濤浩茫茫。朱門待媒勢，短褐誰揄揚。", "仰羨野陂鳧，無心憂稻粱。不如天邊雁，南北皆成行。", "男兒白日間，變化未可量。所希困辱地，剪拂成騰驤。", "咋筆話肝肺，詠茲枯魚章。何由首西路，目斷白雲鄉。"]'),
('yuding-31','洞庭驛樓雪夜宴集，奉贈前湘州張員外','李群玉','唐','御定全唐诗','yuding','','[]','昔與張湘州，閑登岳陽樓。目窮衡巫表，興盡荊吳秋。',192,'御定全唐詩/json/568.json','["昔與張湘州，閑登岳陽樓。目窮衡巫表，興盡荊吳秋。", "擲筆落郢曲，巴人不能酬。是時簪裾會，景物窮冥搜。", "誤忝玳筵秀，得陪文苑遊。幾篇雲楣上，風雨沉銀鉤。", "□□□□□，□□□滄洲。童兒待郭伋，竹馬空遲留。", "路指雲漢津，誰能吟四愁。銀壺傲海雪，青管羅名謳。", "賤子跡未安，謀身拙如鳩。分隨煙霞老，豈有風雲求。", "不逐萬物化，但貽知己羞。方窮立命說，戰勝心悠悠。", "不然蹲會稽，鉤下三五牛。所期波濤助，燀赫呈吞舟。"]'),
('yuding-32','送鄭子寬棄官東遊便歸女幾','李群玉','唐','御定全唐诗','yuding','','[]','八月湖浸天，揚帆入秋色。岷峨雪氣來，寒漲瀟湘碧。',144,'御定全唐詩/json/568.json','["八月湖浸天，揚帆入秋色。岷峨雪氣來，寒漲瀟湘碧。", "子真冥鴻志，不逐籠下翼。九女疊雲屏，於焉恣棲息。", "新詩山水思，靜入陶謝格。困醉松花春，追攀紫煙客。", "相逢十年舊，嚬笑等歡慽。一飯玉露蔬，中腸展堆積。", "停食不盡意，傾意悵可惜。雲水一分飛，離憂洞庭側。", "回車三鄉路，仙菊正堪摘。寄謝杜蘭香，何年別張碩。"]'),
('yuding-33','長沙九日登東樓觀舞','李群玉','唐','御定全唐诗','yuding','','[]','南國有佳人，輕盈綠腰舞。華筵九秋暮，飛袂拂雲雨。',96,'御定全唐詩/json/568.json','["南國有佳人，輕盈綠腰舞。華筵九秋暮，飛袂拂雲雨。", "翩如蘭苕翠，婉如游龍舉。越豔罷前溪，吳姬停白紵。", "慢態不能窮，繁姿曲向終。低回蓮破浪，淩亂雪縈風。", "墜珥時流盻，修裾欲溯空。唯愁捉不住，飛去逐驚鴻。"]'),
('yuding-34','龍山人惠石廩方及團茶','李群玉','唐','御定全唐诗','yuding','','[]','客有衡嶽隱，遺余石廩茶。自雲淩煙露，采掇春山芽。',120,'御定全唐詩/json/568.json','["客有衡嶽隱，遺余石廩茶。自雲淩煙露，采掇春山芽。", "珪璧相壓疊，積芳莫能加。碾成黃金粉，輕嫩如松花。", "紅爐爨霜枝，越兒斟井華。灘聲起魚眼，滿鼎漂清霞。", "凝澄坐曉燈，病眼如蒙紗。一甌拂昏寐，襟鬲開煩拏。", "顧渚與方山，誰人留品差？持甌默吟味，搖膝空咨嗟。"]'),
('yuding-35','宿鳥遠峽化台遇風雨','李群玉','唐','御定全唐诗','yuding','','[]','孤鶴長松顛，獨宿萬岩雨。龍湫在石腳，引袂時一取。',48,'御定全唐詩/json/568.json','["孤鶴長松顛，獨宿萬岩雨。龍湫在石腳，引袂時一取。", "驚風折喬木，飛焰獵窗戶。半夜霹靂聲，高齋有人語。"]'),
('yuding-36','岳陽春晚','李群玉','唐','御定全唐诗','yuding','','[]','不覺春物老，塊然湖上樓。雲沙鷓鴣思，風日沅湘愁。',48,'御定全唐詩/json/568.json','["不覺春物老，塊然湖上樓。雲沙鷓鴣思，風日沅湘愁。", "去翼滅雲夢，來帆指昭丘。所嗟芳桂晚，寂寞對汀洲。"]'),
('yuding-37','漢陽春晚','李群玉','唐','御定全唐诗','yuding','','[]','漢陽抱青山，飛樓映湘渚。白雲蔽黃鶴，綠樹藏鸚鵡。',48,'御定全唐詩/json/568.json','["漢陽抱青山，飛樓映湘渚。白雲蔽黃鶴，綠樹藏鸚鵡。", "憑高送春目，流恨傷千古。遐思禰衡才，令人怨黃祖。"]'),
('yuding-38','將離澧浦置酒野嶼奉懷沈正字昆弟三人聯登高第','李群玉','唐','御定全唐诗','yuding','','[]','春月三改兔，花枝成綠陰。年光東流水，浩歎傷羈心。',144,'御定全唐詩/json/568.json','["春月三改兔，花枝成綠陰。年光東流水，浩歎傷羈心。", "酌桂煙嶼晚，鴂鳴江草深。良圖一超忽，萬恨空相尋。", "上國刈翹楚，才微甘陸沉。無燈假貧女，有淚沾牛衾。", "衡岳三麒麟，各振黃鐘音。卿雲被文彩，芳價搖詞林。", "夫子芸閣英，養鱗湘水潯。晴沙踏蘭菊，隱幾當青岑。", "明月洞庭上，悠揚掛離襟。停觴一搖筆，聊寄生芻吟。"]'),
('yuding-39','湘中別成威闍黎','李群玉','唐','御定全唐诗','yuding','','[]','至哉彼上人，冰霜凜規則。游心杳何境，宴坐入冥默。',144,'御定全唐詩/json/568.json','["至哉彼上人，冰霜凜規則。游心杳何境，宴坐入冥默。", "解空與密行，名臘信崇德。吐論駕秋濤，龍宮發胸臆。", "群迷行大夜，浩浩一昏黑。赤水千丈深，玄珠幾人得。", "持杯挹溟漲，至理安可測。甯假喻芭蕉，真成嗅薝蔔。", "松聲掃白月，霽夜來靜域。清梵罷法筵，天香滿衣襋。", "何方濟了岸，祗仗慈航力。願與十八賢，同棲翠蓮國。"]'),
('yuding-40','別尹煉師','李群玉','唐','御定全唐诗','yuding','','[]','吾家五千言，至道懸日月。若非函穀令，誰注流沙說。',144,'御定全唐詩/json/568.json','["吾家五千言，至道懸日月。若非函穀令，誰注流沙說。", "多君飛升志，機悟獨超拔。學道玉笥山，燒丹白雲穴。", "南窮衡疑秀，采藥曆幽絕。夜臥瀑布風，朝行碧岩雪。", "洞宮四百日，玉籍恣探閱。徒以菌蟪姿，緬攀修真訣。", "塵籠罩浮世，遐思空飛越。一罷棋酒歡，離情滿寥泬。", "願騎紫蓋鶴，早向黃金闕。城市不可留，塵埃穢仙骨。"]'),
('yuding-41','飯僧','李群玉','唐','御定全唐诗','yuding','','[]','好讀天竺書，為尋無生理。焚香面金偈，一室唯巾水。',144,'御定全唐詩/json/568.json','["好讀天竺書，為尋無生理。焚香面金偈，一室唯巾水。", "交信方外言，二三空門子。峻范照秋霜，高標掩僧史。", "清晨潔蔬茗，延請良有以。一落喧嘩競，棲心願依止。", "奔曦入半百，冉冉頹蒙汜。雲泛名利心，風輕是非齒。", "向為情愛縛，未盡金仙旨。以靜制猿心，將虞瞥然起。", "綸巾與藜杖，此意真已矣。他日雲壑間，來尋幽居士。"]'),
('yuding-42','贈回雪','李群玉','唐','御定全唐诗','yuding','','[]','回雪舞縈盈，縈盈若回雪。腰支一把玉，只恐風吹折。',48,'御定全唐詩/json/568.json','["回雪舞縈盈，縈盈若回雪。腰支一把玉，只恐風吹折。", "如能買一笑，滿鬥量明月。安得金蓮花，步步承羅襪。"]'),
('yuding-43','將之京國贈薛員外','李群玉','唐','御定全唐诗','yuding','','[]','黃葉下空館，寂寥寒雨愁。平居歲華晏，絡緯啼林幽。',216,'御定全唐詩/json/568.json','["黃葉下空館，寂寥寒雨愁。平居歲華晏，絡緯啼林幽。", "節物凋壯志，咄嗟不能休。空懷趙鞅歎，變化良無由。", "所思杳何知，側身仰皇州。蒼煙晦楚野，寒浪埋昭丘。", "趙壹賦命薄，陳思多世憂。翻然羨魚鳥，暢矣山川遊。", "薛公龍泉姿，其氣在鬥牛。南冠束秀髮，白石勞悲謳。", "圭袞照崇閱，文儒嗣箕裘。曠然方寸地，霽海浮雲舟。", "澧浦一遺佩，郢南再悲秋。叫閽路既阻，浩蕩懷靈修。", "莫奏武溪笛，且登仲宣樓。亨通與否閉，物理相沉浮。", "天子坐宣室，夔龍奉謨猷。行當賜環去，豈作遺賢羞。"]'),
('yuding-44','送魏珪覲省','李群玉','唐','御定全唐诗','yuding','','[]','木落楚色深，風高浪花白。送君飛一葉，鳥逝入空碧。',215,'御定全唐詩/json/568.json','["木落楚色深，風高浪花白。送君飛一葉，鳥逝入空碧。", "猗歟白華秀，傷心倚門夕。不知雲漲遙，萬里看咫尺。", "蕭蕭青楓岸，去掩江山宅。離觴有黃花，節物助淒戚。", "瀟湘入𤃩桂，一路縈水石。煙蘿拂行舟，玉瀨鏘枕席", "多君林泉趣，耽玩日成癖。長嘯淩清暉，襟情當雪滌。", "登龍屈指內，飛譽甚籍籍。未折月中枝，甯隨宋都鶂。", "曰餘吞聲地，舉足傷瓦礫。見爾一開顏，溫明乃珠璧。", "春風到雲嶠，把酒時相憶。豆蔻花入船，鷓鴣啼送客。", "颺天與瘴海，此去備沿曆。珍重春官英，加餐數刀帛。"]'),
('yuding-45','始忝四座奏狀聞薦蒙恩授官旋進歌詩延英宣賜言懷紀事呈同館諸公二十四韻','李群玉','唐','御定全唐诗','yuding','','[]','兩鬢有二毛，光陰流浪中。形骸日土木，志氣隨雲風。',288,'御定全唐詩/json/568.json','["兩鬢有二毛，光陰流浪中。形骸日土木，志氣隨雲風。", "冥默楚江畔，蕭條林巷空。幽鳥事翔翥，斂翼依蒿蓬。", "一飯五放箸，愀然念途窮。孟門在步武，所向何由通。", "只征大易言，物否不可終。庶期白雪調，一奏驚凡聾。", "昨忝丞相召，揚鞭指冥鴻。姓名掛丹詔，文句飛天聰。", "解薜龍鳳署，懷鉛蘭桂叢。聲名仰聞見，煙漢陪高蹤。", "峨峨群玉山，肅肅紫殿東。神飆泛鐘漏，佳氣浮筠松。", "自顧瑉玞璞，何緣侶圭琮。群賢垂重價，省已增磨礱。", "天子棲穆清，三台付夔龍。九霄降雨露，萬國望時雍。", "巍巍致君期，勳華將比崇。承天四柱石，嶷若窺衡嵩。", "日見帝道升，謀猷垂景鐘。寰瀛納壽域，翔泳皆沖融。", "百神儼雲亭，佇將告成功。吾徒事文藻，驤首歌登封。"]'),
('yuding-46','穆天子','李群玉','唐','御定全唐诗','yuding','','[]','穆滿恣逸志，而輕天下君。一朝得八駿，逐日西溟濆。',96,'御定全唐詩/json/568.json','["穆滿恣逸志，而輕天下君。一朝得八駿，逐日西溟濆。", "寂漠崦嵫幽，絕跡留空文。三千閟宮豔，怨絕寧勝雲。", "或言帝軒轅，乘龍淩紫氛。橋山葬弓劍，曖昧竟難分。", "不思五弦琴，作歌詠南熏。但聽西王母，瑤池吟白雲。"]'),
('yuding-47','廣州重別方處士之封川','李群玉','唐','御定全唐诗','yuding','','[]','楚國傲名客，九州遍芳聲。白衣謝簪紱，雲臥重岩扃。',96,'御定全唐詩/json/568.json','["楚國傲名客，九州遍芳聲。白衣謝簪紱，雲臥重岩扃。", "長波飛素舸，五月下南溟。大笑相逢日，天邊作酒星。", "七年一雲雨，常恨輝容隔。天末又分襟，離憂鬢堪白。", "願回淩潮楫，且著登山屐。共期羅浮秋，與子醉海色。"]'),
('yuding-48','洞庭遇秋','李群玉','唐','御定全唐诗','yuding','','[]','塵愁老來顏，久與江山隔。逍遙澄湖上，洗眼見秋色。',48,'御定全唐詩/json/568.json','["塵愁老來顏，久與江山隔。逍遙澄湖上，洗眼見秋色。", "涼波弄輕棹，湖月生遠碧。未減遙客情，西望杳何極。"]'),
('yuding-49','寄短書歌','李群玉','唐','御定全唐诗','yuding','','[]','骨肉萍蓬各天末，十度附書九不達。孤台冷眼無來人，',40,'御定全唐詩/json/568.json','["骨肉萍蓬各天末，十度附書九不達。孤台冷眼無來人，", "三年音信凝顰外，一曲哀歌白髮生。"]'),
('yuding-50','王內人琵琶引','李群玉','唐','御定全唐诗','yuding','','[]','檀槽一曲黃鐘羽，細撥紫雲金鳳語。萬里胡天海寒秋，',48,'御定全唐詩/json/568.json','["檀槽一曲黃鐘羽，細撥紫雲金鳳語。萬里胡天海寒秋，", "嬴女停吹降浦簫，嫦娥淨掩空波瑟。翠幕橫雲蠟焰光，"]'),
('yuding-51','醒起獨酌懷友','李群玉','唐','御定全唐诗','yuding','','[]','西風靜夜吹蓮塘，芙蓉破紅金粉香。摘花把酒弄秋芳，',24,'御定全唐詩/json/568.json','["西風靜夜吹蓮塘，芙蓉破紅金粉香。摘花把酒弄秋芳，"]'),
('yuding-52','競渡時在湖外偶為成章','李群玉','唐','御定全唐诗','yuding','','[]','雷奔電逝三千兒，彩舟畫楫射初暉。喧江雷鼓鱗甲動，',40,'御定全唐詩/json/568.json','["雷奔電逝三千兒，彩舟畫楫射初暉。喧江雷鼓鱗甲動，", "綠草斜煙日暮時，笛聲幽遠愁江鬼。"]'),
('yuding-0','新荷','李群玉','唐','御定全唐诗','yuding','','[]','田田八九葉，散點綠池初。嫩碧才平水，圓陰已蔽魚。',48,'御定全唐詩/json/569.json','["田田八九葉，散點綠池初。嫩碧才平水，圓陰已蔽魚。", "浮萍遮不合，弱荇繞猶疏。增在春波底，芳心卷未舒。"]'),
('yuding-1','初月二首','李群玉','唐','御定全唐诗','yuding','','[]','灩灩流光淺，娟娟泛露輕。雲間龍爪落，簾上玉鉤明。',96,'御定全唐詩/json/569.json','["灩灩流光淺，娟娟泛露輕。雲間龍爪落，簾上玉鉤明。", "桂樹枝猶小，仙人影未成。欲為千里別，倚幌獨含情。", "凝顰立戶前，細魄向娟娟。破鏡徒相問，刀頭恐來年。", "輕輕搖遠水，脈脈下春煙。別後春江上，隨人何處圓。"]'),
('yuding-2','石瀦','李群玉','唐','御定全唐诗','yuding','','[]','古岸陶為器，高林盡一焚。焰紅湘浦口，煙濁洞庭雲。',48,'御定全唐詩/json/569.json','["古岸陶為器，高林盡一焚。焰紅湘浦口，煙濁洞庭雲。", "迥野煤飛亂，遙空爆響聞。地形穿鑿勢，恐到祝融墳。"]'),
('yuding-3','雲安','李群玉','唐','御定全唐诗','yuding','','[]','灘惡黃牛吼，城孤白帝秋。水寒巴字急，歌迥竹枝愁。',48,'御定全唐詩/json/569.json','["灘惡黃牛吼，城孤白帝秋。水寒巴字急，歌迥竹枝愁。", "樹暗荊王館，雲昏蜀客舟。瑤姬不可見，行雨在高丘。"]'),
('yuding-4','石頭城','李群玉','唐','御定全唐诗','yuding','','[]','伯業隨流水，寒蕪上古城。長空橫海色，斷岸落潮聲。',48,'御定全唐詩/json/569.json','["伯業隨流水，寒蕪上古城。長空橫海色，斷岸落潮聲。", "八極悲扶拄，五湖來止傾。東南天子氣，掃地入函京。"]'),
('yuding-5','湖闊','李群玉','唐','御定全唐诗','yuding','','[]','楚色籠青草，秋風洗洞庭。夕霏生水寺，初月盡雲汀。',48,'御定全唐詩/json/569.json','["楚色籠青草，秋風洗洞庭。夕霏生水寺，初月盡雲汀。", "棹響來空闊，漁歌發杳冥。欲浮闌下艇，一到鬥牛星。"]'),
('yuding-6','失鶴','李群玉','唐','御定全唐诗','yuding','','[]','瑤台煙霧外，一去不回心。清海蓬壺遠，秋風碧落深。',48,'御定全唐詩/json/569.json','["瑤台煙霧外，一去不回心。清海蓬壺遠，秋風碧落深。", "墮翎留片雪，雅操入孤琴。豈是籠中物，雲蘿莫更尋。"]'),
('yuding-7','臘夜雪霽月彩交光開閣臨軒竟睡不得命家僕吹笙數曲獨引一壺奉寄江陵副使杜中丞','李群玉','唐','御定全唐诗','yuding','','[]','月華臨霽雪，皓彩射貂裘。桂酒寒無醉，銀笙凍不流。',48,'御定全唐詩/json/569.json','["月華臨霽雪，皓彩射貂裘。桂酒寒無醉，銀笙凍不流。", "懷哉梁苑客，思作剡溪遊。竟夕吟瓊樹，川途恨阻修。"]'),
('yuding-8','長沙陪裴大夫登北樓','李群玉','唐','御定全唐诗','yuding','','[]','岩嶂隨高步，琴尊奉勝遊。金風吹綠簟，湘水入朱樓。',48,'御定全唐詩/json/569.json','["岩嶂隨高步，琴尊奉勝遊。金風吹綠簟，湘水入朱樓。", "朗抱雲開月，高情鶴見秋。登臨多暇日，非為賦消憂。"]'),
('yuding-9','登蒲澗寺後二岩三首','李群玉','唐','御定全唐诗','yuding','','[]','五仙騎五羊，何代降茲鄉。澗有堯年韭，山餘禹日糧。',144,'御定全唐詩/json/569.json','["五仙騎五羊，何代降茲鄉。澗有堯年韭，山餘禹日糧。", "樓臺籠海色，草樹發天香。浩嘯波光裏，浮溟興甚長。", "行盡崎嶇路，驚從汗漫遊。青天豁眼快，碧海醒心秋。", "便欲尋河漢，因之犯鬥牛。九霄身自致，何必遇浮丘。", "南溟吞越絕，極望碧鴻蒙。龍渡潮聲裏，雷喧雨氣中。", "趙佗丘壟滅，馬援鼓鼙空。遐想魚鵬化，開襟九萬風。"]'),
('yuding-10','早鴻','李群玉','唐','御定全唐诗','yuding','','[]','木落波浪動，南飛聞夜鴻。參差天漢霧，嘹唳月明風。',48,'御定全唐詩/json/569.json','["木落波浪動，南飛聞夜鴻。參差天漢霧，嘹唳月明風。", "野水蓮莖折，寒泥稻穗空。無令一行侶，相失五湖中。"]'),
('yuding-11','旅泊','李群玉','唐','御定全唐诗','yuding','','[]','搖落江天裏，飄零倚客舟。短篇才遣悶，小釀不供愁。',48,'御定全唐詩/json/569.json','["搖落江天裏，飄零倚客舟。短篇才遣悶，小釀不供愁。", "沙雨潮痕細，林風月影稠。書空閒度日，深擁破貂裘。"]'),
('yuding-12','半醉','李群玉','唐','御定全唐诗','yuding','','[]','處俗常如病，看花亦似秋。若無時複酒，甯遣鎮長愁。',48,'御定全唐詩/json/569.json','["處俗常如病，看花亦似秋。若無時複酒，甯遣鎮長愁。", "漸覺身非我，都迷蝶與周。何煩五色藥，尊下即丹丘。"]'),
('yuding-13','晝寐','李群玉','唐','御定全唐诗','yuding','','[]','筠桂晚蕭疏，任人嘲宰予。鳥驚林下夢，風展枕前書。',48,'御定全唐詩/json/569.json','["筠桂晚蕭疏，任人嘲宰予。鳥驚林下夢，風展枕前書。", "正作莊生蝶，誰知惠子魚。人間無樂事，直擬到華胥。"]'),
('yuding-14','晚蓮','李群玉','唐','御定全唐诗','yuding','','[]','露冷芳意盡，稀疏空碧荷。殘香隨暮雨，枯蕊墮寒波。',48,'御定全唐詩/json/569.json','["露冷芳意盡，稀疏空碧荷。殘香隨暮雨，枯蕊墮寒波。", "楚客罷奇服，吳姬停棹歌。涉江無可寄，幽恨竟如何。"]'),
('yuding-15','將之番禺留別湖南府幕','李群玉','唐','御定全唐诗','yuding','','[]','本乏煙霞志，那隨鴛鷺遊。一枝仍未定，數粒欲何求。',48,'御定全唐詩/json/569.json','["本乏煙霞志，那隨鴛鷺遊。一枝仍未定，數粒欲何求。", "溟漲道途遠，荊吳雲雪愁。會登梅嶺翠，南翥入炎洲。"]'),
('yuding-16','宵民','李群玉','唐','御定全唐诗','yuding','','[]','大雅無憂怨，宵民有愛憎。魯侯天不遇，臧氏爾何能。',48,'御定全唐詩/json/569.json','["大雅無憂怨，宵民有愛憎。魯侯天不遇，臧氏爾何能。", "慘慘心如虺，營營舌似蠅。誰於銷骨地，一鑒玉壺冰。"]'),
('yuding-17','吾道','李群玉','唐','御定全唐诗','yuding','','[]','吾道成微哂，時情付絕言。鳳兮衰已盡，犬也吠何繁。',48,'御定全唐詩/json/569.json','["吾道成微哂，時情付絕言。鳳兮衰已盡，犬也吠何繁。", "輕重憂衡曲，妍媸慮鏡昏。方忻耳目淨，誰到翟公門。"]'),
('yuding-18','與三山人夜話','李群玉','唐','御定全唐诗','yuding','','[]','靜談雲鶴趣，高會兩三賢。酒思彈琴夜，茶芳向火天。',48,'御定全唐詩/json/569.json','["靜談雲鶴趣，高會兩三賢。酒思彈琴夜，茶芳向火天。", "兔裘堆膝暖，鳩杖倚床偏。各厭池籠窄，相看意浩然。"]'),
('yuding-19','春寒','李群玉','唐','御定全唐诗','yuding','','[]','撥火垂簾夕，將暄向冷天。悶斟壺酒暖，愁聽雨聲眠。',48,'御定全唐詩/json/569.json','["撥火垂簾夕，將暄向冷天。悶斟壺酒暖，愁聽雨聲眠。", "處世心悠爾，幹時思索然。春光看已半，明日又藏煙。"]'),
('yuding-20','廣江驛餞筵留別','李群玉','唐','御定全唐诗','yuding','','[]','別筵欲盡秋，一醉海西樓。夜雨寒潮水，孤燈萬里舟。',48,'御定全唐詩/json/569.json','["別筵欲盡秋，一醉海西樓。夜雨寒潮水，孤燈萬里舟。", "酒飛鸚鵡重，歌送鷓鴣愁。惆悵三年客，難期此處遊。"]'),
('yuding-21','桑落洲','李群玉','唐','御定全唐诗','yuding','','[]','九江寒露夕，微浪北風生。浦嶼漁人火，蒹葭鳧雁聲。',48,'御定全唐詩/json/569.json','["九江寒露夕，微浪北風生。浦嶼漁人火，蒹葭鳧雁聲。", "頹雲晦廬嶽，微鼓辨湓城。遠憶天邊弟，曾從此路行。"]'),
('yuding-22','杜門','李群玉','唐','御定全唐诗','yuding','','[]','且詠閒居賦，飛翔去未能。春風花嶼酒，秋雨竹溪燈。',48,'御定全唐詩/json/569.json','["且詠閒居賦，飛翔去未能。春風花嶼酒，秋雨竹溪燈。", "世路變陵谷，時情驗友朋。達生書一卷，名利付春冰。"]'),
('yuding-23','池州封員外郡齋雙鶴丹頂霜翎仙態浮曠罷政之日因呈此章','李群玉','唐','御定全唐诗','yuding','','[]','瀟灑二白鶴，對之高興清。寒溪侶雲水，朱閣伴琴笙。',48,'御定全唐詩/json/569.json','["瀟灑二白鶴，對之高興清。寒溪侶雲水，朱閣伴琴笙。", "顧慕稻粱惠，超遙江海情。應攜帝鄉去，仙闕看飛鳴。"]'),
('yuding-24','經費拾遺所居呈封員外','李群玉','唐','御定全唐诗','yuding','','[]','雲臥竟不起，少微空隕光。唯應孔北海，為立鄭公鄉。',48,'御定全唐詩/json/569.json','["雲臥竟不起，少微空隕光。唯應孔北海，為立鄭公鄉。", "舊館苔蘚合，幽齋松菊荒。空餘書帶草，日日上階長。"]'),
('yuding-25','送秦煉師','李群玉','唐','御定全唐诗','yuding','','[]','紫府靜沉沉，松軒思別琴。水流甯有意，雲泛本無心。',48,'御定全唐詩/json/569.json','["紫府靜沉沉，松軒思別琴。水流甯有意，雲泛本無心。", "錦洞桃花遠，青山竹葉深。不因時賣藥，何路更相尋。"]'),
('yuding-26','湘陰縣送遷客北歸','李群玉','唐','御定全唐诗','yuding','','[]','不須留薏苡，重遣世人疑。瘴染面如檗，愁熏頭似絲。',48,'御定全唐詩/json/569.json','["不須留薏苡，重遣世人疑。瘴染面如檗，愁熏頭似絲。", "黃梅住雨外，青草過湖時。今日開湯網，冥飛亦未遲。"]'),
('yuding-27','九日陪崔大夫宴清河亭','李群玉','唐','御定全唐诗','yuding','','[]','玉醴浮金菊，雲亭敞玳筵。晴山低畫浦，斜雁遠書天。',48,'御定全唐詩/json/569.json','["玉醴浮金菊，雲亭敞玳筵。晴山低畫浦，斜雁遠書天。", "謝胱離都日，殷公出守年。不知瑤水宴，誰和白雲篇。"]'),
('yuding-28','送房處士閒遊','李群玉','唐','御定全唐诗','yuding','','[]','采藥陶貞白，尋山許遠遊。刀圭藏妙用，岩洞契冥搜。',48,'御定全唐詩/json/569.json','["采藥陶貞白，尋山許遠遊。刀圭藏妙用，岩洞契冥搜。", "花月三江水，琴尊一葉舟。羨君隨野鶴，長揖稻粱愁。"]'),
('yuding-29','贈花','李群玉','唐','御定全唐诗','yuding','','[]','酒為看花醞，花須趁酒紅。莫令芳樹晚，使我綠尊空。',48,'御定全唐詩/json/569.json','["酒為看花醞，花須趁酒紅。莫令芳樹晚，使我綠尊空。", "金穀園無主，桃源路不通。縱非乘露折，長短盡隨風。"]'),
('yuding-30','洞庭風雨二首','李群玉','唐','御定全唐诗','yuding','','[]','面南一片黑，俄起北風顛。浪潑巴陵樹，雷燒鹿角田。',96,'御定全唐詩/json/569.json','["面南一片黑，俄起北風顛。浪潑巴陵樹，雷燒鹿角田。", "魚龍方簸蕩，雲雨正喧闐。想赭君山日，秦皇怒赫然。", "巨浸吞湘澧，西風忽怒號。水將天共黑，雲與浪爭高。", "羽化思乘鯉，山漂欲抃鼇。陽烏猶曝翅，真恐濕蟠桃。"]'),
('yuding-31','臨水薔薇','李群玉','唐','御定全唐诗','yuding','','[]','堪愛複堪傷，無情不久長。浪搖千臉笑，風舞一叢芳。',48,'御定全唐詩/json/569.json','["堪愛複堪傷，無情不久長。浪搖千臉笑，風舞一叢芳。", "似濯文君錦，如窺漢女妝。所思雲雨外，何處寄馨香。"]'),
('yuding-32','中秋維舟君山看月二首','李群玉','唐','御定全唐诗','yuding','','[]','汗漫鋪澄碧，朦朧吐玉盤。雨師清滓穢，川後掃波瀾。',96,'御定全唐詩/json/569.json','["汗漫鋪澄碧，朦朧吐玉盤。雨師清滓穢，川後掃波瀾。", "氣射繁星滅，光籠八表寒。來從雲漲迥，路上碧霄寬。", "熠耀遊何處，蟾蜍食漸殘。棹翻銀浪急，林映白虹攢。", "練彩連河曉，冰暉壓樹幹。夜深高不動，天下仰頭看。"]'),
('yuding-33','桂州經佳人故居琪樹','李群玉','唐','御定全唐诗','yuding','','[]','種樹人何在，攀枝空歎嗟。人無重見日，樹有每年花。',48,'御定全唐詩/json/569.json','["種樹人何在，攀枝空歎嗟。人無重見日，樹有每年花。", "滿院雀聲暮，半庭春景斜。東風不知恨，遍地落餘霞。"]'),
('yuding-34','贈元紱','李群玉','唐','御定全唐诗','yuding','','[]','相逢在總角，與子即同心。隱石那知玉，披沙始遇金。',48,'御定全唐詩/json/569.json','["相逢在總角，與子即同心。隱石那知玉，披沙始遇金。", "蘭秋香不死，松晚翠方深。各保芳堅性，寧憂霜霰侵。"]'),
('yuding-35','中秋廣江驛示韋益','李群玉','唐','御定全唐诗','yuding','','[]','莫惜三更坐，難消萬里情。同看一片月，俱在廣州城。',48,'御定全唐詩/json/569.json','["莫惜三更坐，難消萬里情。同看一片月，俱在廣州城。", "淚逐金波滿，魂隨夜鵲驚。支頤鄉思斷，無語到雞鳴。"]'),
('yuding-36','九日越台','李群玉','唐','御定全唐诗','yuding','','[]','旭日高山上，秋天大海隅。黃花羅粔籹，絳實簇茱萸。',48,'御定全唐詩/json/569.json','["旭日高山上，秋天大海隅。黃花羅粔籹，絳實簇茱萸。", "病久歡情薄，鄉遙客思孤。無心同落帽，天際望歸途。"]'),
('yuding-37','中秋越台看月','李群玉','唐','御定全唐诗','yuding','','[]','海雨洗塵埃，月從空碧來。水光籠草樹，練影掛樓臺。',48,'御定全唐詩/json/569.json','["海雨洗塵埃，月從空碧來。水光籠草樹，練影掛樓臺。", "皓曜迷鯨目，晶熒失蚌胎。宵分憑檻望，應合見蓬萊。"]'),
('yuding-38','長沙開元寺昔與故長林許侍禦題松竹聯句','李群玉','唐','御定全唐诗','yuding','','[]','牆陰數行字，懷舊慘傷情。薜荔侵年月，莓苔壓姓名。',48,'御定全唐詩/json/569.json','["牆陰數行字，懷舊慘傷情。薜荔侵年月，莓苔壓姓名。", "逝川前後水，浮世短長生。獨立秋風暮，凝顰隔郢城。"]'),
('yuding-39','傷友','李群玉','唐','御定全唐诗','yuding','','[]','玉棺來九天，鳧舄掩窮泉。蕪沒池塘嶼，淒涼翰墨筵。',48,'御定全唐詩/json/569.json','["玉棺來九天，鳧舄掩窮泉。蕪沒池塘嶼，淒涼翰墨筵。", "短期存大夢，舊好委浮煙。我有幽蘭曲，因君遂絕弦。"]'),
('yuding-40','法性寺六祖戒壇','李群玉','唐','御定全唐诗','yuding','','[]','初地無階級，餘基數尺低。天香開茉莉，梵樹落菩提。',48,'御定全唐詩/json/569.json','["初地無階級，餘基數尺低。天香開茉莉，梵樹落菩提。", "驚俗生真性，青蓮出淤泥。何人得心法，衣缽在曹溪。"]'),
('yuding-41','東湖二首','李群玉','唐','御定全唐诗','yuding','','[]','晚景微雨歇，逍遙湖上亭。波閑魚弄餌，樹靜鳥遺翎。',96,'御定全唐詩/json/569.json','["晚景微雨歇，逍遙湖上亭。波閑魚弄餌，樹靜鳥遺翎。", "性野難依俗，詩玄自入冥。何繇遂瀟灑，高枕對雲汀。", "雨氣消殘暑，蒼蒼月欲升。林間風卷簟，欄下水搖燈。", "迥野垂銀鏡，層巒掛玉繩。重期浮小楫，來摘半湖菱。"]'),
('yuding-42','湖閣曉晴寄呈從翁二首','李群玉','唐','御定全唐诗','yuding','','[]','嶺日開寒霧，湖光蕩霽華。風烏搖徑柳，水蝶戀幽花。',96,'御定全唐詩/json/569.json','["嶺日開寒霧，湖光蕩霽華。風烏搖徑柳，水蝶戀幽花。", "蜀國地西極，吳門天一涯。輕舟欄下去，點點入湘霞。", "高秋憑遠檻，萬里看新晴。重霧披天急，千雲觸石輕。", "湖山四五點，湘雁兩三聲。遙想潘園裏，琴尊興轉清。"]'),
('yuding-43','同張明府游漊水亭','李群玉','唐','御定全唐诗','yuding','','[]','草色綠溪晚，梅香生縠文。雲天斂餘霽，水木籠微曛。',48,'御定全唐詩/json/569.json','["草色綠溪晚，梅香生縠文。雲天斂餘霽，水木籠微曛。", "垂釣坐方嶼，幽禽時一聞。何當五柳下，酌醴吟庭筠。"]'),
('yuding-44','七月十五夜看月','李群玉','唐','御定全唐诗','yuding','','[]','朦朧南溟月，洶湧出雲濤。下射長鯨眼，遙分玉兔毫。',48,'御定全唐詩/json/569.json','["朦朧南溟月，洶湧出雲濤。下射長鯨眼，遙分玉兔毫。", "勢來星斗動，路越青冥高。竟夕瞻光彩，昂頭把白醪。"]'),
('yuding-45','北風','李群玉','唐','御定全唐诗','yuding','','[]','病發幹垂枕，臨風強起梳。蝶飛魂尚弱，蟻鬥體猶虛。',48,'御定全唐詩/json/569.json','["病發幹垂枕，臨風強起梳。蝶飛魂尚弱，蟻鬥體猶虛。", "瘦骨呻吟後，羸容几杖初。庭幽行藥靜，涼暑翠筠疏。"]'),
('yuding-46','遊玉芝觀','李群玉','唐','御定全唐诗','yuding','','[]','尋仙向玉清，獨倚雪初晴。木落寒郊迥，煙開疊嶂明。',48,'御定全唐詩/json/569.json','["尋仙向玉清，獨倚雪初晴。木落寒郊迥，煙開疊嶂明。", "片雲盤鶴影，孤磬雜松聲。且共探玄理，歸途月未生。"]'),
('yuding-47','中秋夜南樓寄友人','李群玉','唐','御定全唐诗','yuding','','[]','海月出銀浪，湖光射高樓。朗吟無淥酒，賤價買清秋。',48,'御定全唐詩/json/569.json','["海月出銀浪，湖光射高樓。朗吟無淥酒，賤價買清秋。", "氣冷魚龍寂，輪高星漢幽。他鄉此夜客，對景餞多愁。"]'),
('yuding-48','三月五日陪裴大夫泛長沙東湖','李群玉','唐','御定全唐诗','yuding','','[]','上巳餘風景，芳辰集遠坰。彩舟浮滉蕩，繡轂下娉婷。',72,'御定全唐詩/json/569.json','["上巳餘風景，芳辰集遠坰。彩舟浮滉蕩，繡轂下娉婷。", "林榭回蔥蒨，笙歌轉杳冥。湖光迷翡翠，草色醉蜻蜓。", "鳥弄桐花日，魚翻穀雨萍。從今留勝會，誰肯畫蘭亭。"]'),
('yuding-49','龜','李群玉','唐','御定全唐诗','yuding','','[]','靜養千年壽，重泉自隱居。不應隨跛鱉，寧肯滯凡魚。',96,'御定全唐詩/json/569.json','["靜養千年壽，重泉自隱居。不應隨跛鱉，寧肯滯凡魚。", "靈腹唯玄露，芳巢必翠蕖。揚花輸蚌蛤，奔月恨蟾蜍。", "曳尾辭泥後，支床得水初。冠山期不小，鑄印事寧虛。", "有志酬毛寶，無心畏豫且。他時清洛汭，會薦帝堯書。"]'),
('yuding-50','長沙春望寄涔陽故人','李群玉','唐','御定全唐诗','yuding','','[]','清明別後雨晴時，極浦空顰一望眉。湖畔春山煙黯黯，',40,'御定全唐詩/json/569.json','["清明別後雨晴時，極浦空顰一望眉。湖畔春山煙黯黯，", "風暖草長愁自醉，行吟無處寄相思。"]'),
('yuding-51','金塘路中','李群玉','唐','御定全唐诗','yuding','','[]','山連楚越複吳秦，蓬梗何年是住身。黃葉黃花古城路，',40,'御定全唐詩/json/569.json','["山連楚越複吳秦，蓬梗何年是住身。黃葉黃花古城路，", "十口系心拋不得，每回回首即長顰。"]'),
('yuding-52','自遣','李群玉','唐','御定全唐诗','yuding','','[]','翻覆升沉百歲中，前途一半已成空。浮生暫寄夢中夢，',40,'御定全唐詩/json/569.json','["翻覆升沉百歲中，前途一半已成空。浮生暫寄夢中夢，", "一壺濁酒暄和景，誰會陶然失馬翁。"]'),
('yuding-53','送於少監自廣州還紫邏','李群玉','唐','御定全唐诗','yuding','','[]','鳴皋山水似麻源，謝監東還憶故園。海嶠煙霞輕逸翰，',40,'御定全唐詩/json/569.json','["鳴皋山水似麻源，謝監東還憶故園。海嶠煙霞輕逸翰，", "明日中書見顏范，始應通籍入金門。"]'),
('yuding-54','石門韋明府為致東陽潭石鯽鱠','李群玉','唐','御定全唐诗','yuding','','[]','錦鱗銜餌出清漣，暖日江亭動鱠筵。疊雪亂飛消箸底，',40,'御定全唐詩/json/569.json','["錦鱗銜餌出清漣，暖日江亭動鱠筵。疊雪亂飛消箸底，", "雋味品流知第一，更勞霜橘助芳鮮。"]'),
('yuding-55','規公業在淨名得甚深義僕近獲顧長康月宮真影對戴安道所畫文殊走筆此篇以屈瞻禮','李群玉','唐','御定全唐诗','yuding','','[]','五濁之世塵冥冥，達觀棲心於此經。但用須彌藏芥子，',40,'御定全唐詩/json/569.json','["五濁之世塵冥冥，達觀棲心於此經。但用須彌藏芥子，", "今日淨開方丈室，一飛白足到茅亭。"]'),
('yuding-56','玉真觀','李群玉','唐','御定全唐诗','yuding','','[]','高情帝女慕乘鸞，紺發初簪玉葉冠。秋月無雲生碧落，',40,'御定全唐詩/json/569.json','["高情帝女慕乘鸞，紺發初簪玉葉冠。秋月無雲生碧落，", "一自簫聲飛去後，洞宮深掩碧瑤壇。"]'),
('yuding-57','辱綿州于中丞書信','李群玉','唐','御定全唐诗','yuding','','[]','一緘垂露到雲林，中有孫陽念驥心。萬木自凋山不動，',40,'御定全唐詩/json/569.json','["一緘垂露到雲林，中有孫陽念驥心。萬木自凋山不動，", "他日縱陪池上酌，已應難到暝猿吟。"]'),
('yuding-58','送崔使君蕭山禱雨甘澤遽降','李群玉','唐','御定全唐诗','yuding','','[]','謝公一拜敬亭祠，五馬旋歸下散絲。不假土龍呈夭矯，',40,'御定全唐詩/json/569.json','["謝公一拜敬亭祠，五馬旋歸下散絲。不假土龍呈夭矯，", "已向為霖報消息，潁川征詔是前期。"]'),
('yuding-59','重經巴丘追感','李群玉','唐','御定全唐诗','yuding','','[]','昔年高接李膺歡，日泛仙舟醉碧瀾。詩句亂隨青草發，',40,'御定全唐詩/json/569.json','["昔年高接李膺歡，日泛仙舟醉碧瀾。詩句亂隨青草發，", "今日片帆城下去，秋風回首淚闌幹。"]'),
('yuding-60','湘陰江亭卻寄友人','李群玉','唐','御定全唐诗','yuding','','[]','湘岸初晴淑景遲，風光正是客愁時。幽花暮落騷人浦，',40,'御定全唐詩/json/569.json','["湘岸初晴淑景遲，風光正是客愁時。幽花暮落騷人浦，", "煙波自此扁舟去，小酌文園杳未期。"]'),
('yuding-61','哭郴州王使君','李群玉','唐','御定全唐诗','yuding','','[]','銀章朱紱照雲驄，六換魚書惠化崇。瑤樹忽傾滄海裏，',40,'御定全唐詩/json/569.json','["銀章朱紱照雲驄，六換魚書惠化崇。瑤樹忽傾滄海裏，", "曾是綺羅筵上客，一來長慟向春風。"]'),
('yuding-62','九日巴丘楊公臺上宴集','李群玉','唐','御定全唐诗','yuding','','[]','淒淒霜日上高臺，水國秋深客思哀。萬疊銀山寒浪起，',40,'御定全唐詩/json/569.json','["淒淒霜日上高臺，水國秋深客思哀。萬疊銀山寒浪起，", "江漢路長身不定，菊花三笑旅萍開。"]'),
('yuding-63','奉和張舍人送秦煉師歸岑公山','李群玉','唐','御定全唐诗','yuding','','[]','仙翁歸臥翠微岑，一夜西風月峽深。松徑定知芳草合，',40,'御定全唐詩/json/569.json','["仙翁歸臥翠微岑，一夜西風月峽深。松徑定知芳草合，", "蘭浦蒼蒼春欲暮，落花流水怨離琴。"]'),
('yuding-64','送陶少府赴選','李群玉','唐','御定全唐诗','yuding','','[]','陶君官興本蕭疏，長傍青山碧水居。久向三茅窮藝術，',40,'御定全唐詩/json/569.json','["陶君官興本蕭疏，長傍青山碧水居。久向三茅窮藝術，", "自是葛洪求藥價，不關梅福戀簪裾。"]'),
('yuding-65','寄張祜','李群玉','唐','御定全唐诗','yuding','','[]','越水吳山任興行，五湖雲月掛高情。不游都邑稱平子，',40,'御定全唐詩/json/569.json','["越水吳山任興行，五湖雲月掛高情。不游都邑稱平子，", "如君氣力波瀾地，留取陰何沈範名。"]'),
('yuding-66','寄長沙許侍禦','李群玉','唐','御定全唐诗','yuding','','[]','三年文會許追隨，和遍南朝雜體詩。未把彩毫還郭璞，',40,'御定全唐詩/json/569.json','["三年文會許追隨，和遍南朝雜體詩。未把彩毫還郭璞，", "今日秋風滿湘浦，只應搔首詠瓊枝。"]'),
('yuding-67','望月懷友','李群玉','唐','御定全唐诗','yuding','','[]','浮雲卷盡看朣朧，直出滄溟上碧空。盈手水光寒不濕，',40,'御定全唐詩/json/569.json','["浮雲卷盡看朣朧，直出滄溟上碧空。盈手水光寒不濕，", "川路正長難可越，美人千里思何窮。"]'),
('yuding-68','和吳中丞悼笙妓','李群玉','唐','御定全唐诗','yuding','','[]','麗質仙姿煙逐風，鳳凰聲斷吹台空。多情草色怨還綠，',40,'御定全唐詩/json/569.json','["麗質仙姿煙逐風，鳳凰聲斷吹台空。多情草色怨還綠，", "唯應去抱雲和管，從此長歸阿母宮。"]'),
('yuding-69','薛侍禦處乞靴','李群玉','唐','御定全唐诗','yuding','','[]','越客南來誇桂麖，良工用意巧縫成。看時共說茱萸皺，',40,'御定全唐詩/json/569.json','["越客南來誇桂麖，良工用意巧縫成。看時共說茱萸皺，", "日于文苑陪高步，贏得芳塵接武名。"]'),
('yuding-70','九子坡聞鷓鴣','李群玉','唐','御定全唐诗','yuding','','[]','落照蒼茫秋草明，鷓鴣啼處遠人行。正穿詰曲崎嶇路，',40,'御定全唐詩/json/569.json','["落照蒼茫秋草明，鷓鴣啼處遠人行。正穿詰曲崎嶇路，", "此時為爾腸千斷，乞放今宵白髮生。"]'),
('yuding-71','涼公從叔春祭廣利王廟','李群玉','唐','御定全唐诗','yuding','','[]','龍驤伐鼓下長川，直濟雲濤古廟前。海客斂威驚火旆，',40,'御定全唐詩/json/569.json','["龍驤伐鼓下長川，直濟雲濤古廟前。海客斂威驚火旆，", "從此華夷封域靜，潛熏玉燭奉堯年。"]'),
('yuding-72','長沙紫極宮雨夜愁坐','李群玉','唐','御定全唐诗','yuding','','[]','獨坐高齋寒擁衾，洞宮台殿窅沉沉。春燈含思靜相伴，',40,'御定全唐詩/json/569.json','["獨坐高齋寒擁衾，洞宮台殿窅沉沉。春燈含思靜相伴，", "羈棲摧剪平生志，抱膝時為梁甫吟。"]'),
('yuding-73','送人隱居','李群玉','唐','御定全唐诗','yuding','','[]','棋局茅亭幽澗濱，竹寒江靜遠無人。村梅尚斂風前笑，',40,'御定全唐詩/json/569.json','["棋局茅亭幽澗濱，竹寒江靜遠無人。村梅尚斂風前笑，", "平生自有煙霞志，久欲拋身狎隱淪。"]'),
('yuding-74','江樓閑望懷關中親故','李群玉','唐','御定全唐诗','yuding','','[]','搖落江天欲盡秋，遠鴻高送一行愁。音書寂絕秦雲外，',40,'御定全唐詩/json/569.json','["搖落江天欲盡秋，遠鴻高送一行愁。音書寂絕秦雲外，", "風淒日冷江湖晚，駐目寒空獨倚樓。"]'),
('yuding-75','請告南歸留別同館','李群玉','唐','御定全唐诗','yuding','','[]','一點燈前獨坐身，西風初動帝城砧。不勝庾信鄉關思，',40,'御定全唐詩/json/569.json','["一點燈前獨坐身，西風初動帝城砧。不勝庾信鄉關思，", "應憐一別瀛洲侶，萬里單飛雲外深。"]'),
('yuding-76','仙明洲口號','李群玉','唐','御定全唐诗','yuding','','[]','長愛沙洲水竹居，暮江春樹綠陰初。浪翻新月金波淺，',40,'御定全唐詩/json/569.json','["長愛沙洲水竹居，暮江春樹綠陰初。浪翻新月金波淺，", "二年此處尋佳句，景物常輸楚客書。"]'),
('yuding-77','送蕭十二校書赴郢州婚姻','李群玉','唐','御定全唐诗','yuding','','[]','蓬萊才子即蕭郎，彩服青書蔔鳳凰。玉佩定催紅粉色，',40,'御定全唐詩/json/569.json','["蓬萊才子即蕭郎，彩服青書蔔鳳凰。玉佩定催紅粉色，", "領取和鳴好風景，石城花月送歸鄉。"]'),
('yuding-78','送隱者歸羅浮','李群玉','唐','御定全唐诗','yuding','','[]','春山杳杳日遲遲，路入雲峰白犬隨。兩卷素書留貰酒，',40,'御定全唐詩/json/569.json','["春山杳杳日遲遲，路入雲峰白犬隨。兩卷素書留貰酒，", "自此塵寰音信斷，山川風月永相思。"]'),
('yuding-79','獻王中丞時有除拜','李群玉','唐','御定全唐诗','yuding','','[]','登仙望絕李膺舟，從此青蠅點遂稠。半夜劍吹牛鬥動，',40,'御定全唐詩/json/569.json','["登仙望絕李膺舟，從此青蠅點遂稠。半夜劍吹牛鬥動，", "他日圖勳畫麟閣，定呈肝膽始應休。"]'),
('yuding-80','哭小女癡兒','李群玉','唐','御定全唐诗','yuding','','[]','平生未省夢熊羆，稚女如花墜曉枝。條蔓縱橫輸葛藟，',40,'御定全唐詩/json/569.json','["平生未省夢熊羆，稚女如花墜曉枝。條蔓縱橫輸葛藟，", "負爾五年恩愛淚，眼中惟有涸泉知。"]'),
('yuding-81','醉後贈馮姬','李群玉','唐','御定全唐诗','yuding','','[]','黃昏歌舞促瓊筵，銀燭臺西見小蓮。二寸橫波回慢水，',40,'御定全唐詩/json/569.json','["黃昏歌舞促瓊筵，銀燭臺西見小蓮。二寸橫波回慢水，", "願托襄王雲雨夢，陽臺今夜降神仙。"]'),
('yuding-82','廣州陪涼公從叔越台宴集','李群玉','唐','御定全唐诗','yuding','','[]','一徑松梢踏石梯，步窮身在白雲西。日銜赤浪金車沒，',40,'御定全唐詩/json/569.json','["一徑松梢踏石梯，步窮身在白雲西。日銜赤浪金車沒，", "玉鉤掛海笙歌合，珠履三千半似泥。"]'),
('yuding-83','留別馬使君','李群玉','唐','御定全唐诗','yuding','','[]','俱來海上歎煙波，君佩銀魚我觸羅。蜀國才微甘放蕩，',40,'御定全唐詩/json/569.json','["俱來海上歎煙波，君佩銀魚我觸羅。蜀國才微甘放蕩，", "唯有管弦知客意，分明吹出感恩多。"]'),
('yuding-84','將欲南行陪崔八宴海榴亭','李群玉','唐','御定全唐诗','yuding','','[]','朝宴華堂暮未休，幾人偏得謝公留。風傳鼓角霜侵戟，',40,'御定全唐詩/json/569.json','["朝宴華堂暮未休，幾人偏得謝公留。風傳鼓角霜侵戟，", "謾誇書劍無歸處，水遠山長步步愁。"]'),
('yuding-85','湖寺清明夜遣懷','李群玉','唐','御定全唐诗','yuding','','[]','柳暗花香愁不眠，獨憑危檻思淒然。野雲將雨渡微月，',40,'御定全唐詩/json/569.json','["柳暗花香愁不眠，獨憑危檻思淒然。野雲將雨渡微月，", "餳餐冷酒明年在，未定萍蓬何處邊。"]'),
('yuding-86','九日','李群玉','唐','御定全唐诗','yuding','','[]','年年羞見菊花開，十度悲秋上楚台。半嶺殘陽銜樹落，',40,'御定全唐詩/json/569.json','["年年羞見菊花開，十度悲秋上楚台。半嶺殘陽銜樹落，", "絲管闌珊歸客盡，黃昏獨自詠詩回。"]'),
('yuding-87','同鄭相並歌姬小飲戲贈','李群玉','唐','御定全唐诗','yuding','','[]','裙拖六幅湘江水，鬢聳巫山一段雲。風格只應天上有，',40,'御定全唐詩/json/569.json','["裙拖六幅湘江水，鬢聳巫山一段雲。風格只應天上有，", "不是相如憐賦客，爭教容易見文君。"]'),
('yuding-88','秣陵懷古','李群玉','唐','御定全唐诗','yuding','','[]','野花黃葉舊吳宮，六代豪華燭散風，龍虎勢衰佳氣歇，',40,'御定全唐詩/json/569.json','["野花黃葉舊吳宮，六代豪華燭散風，龍虎勢衰佳氣歇，", "霸業鼎圖人去盡，獨來惆悵水雲中。"]'),
('yuding-89','黃陵廟','李群玉','唐','御定全唐诗','yuding','','[]','小姑洲北浦雲邊，二女容華自儼然。野廟向江春寂寂，',40,'御定全唐詩/json/569.json','["小姑洲北浦雲邊，二女容華自儼然。野廟向江春寂寂，", "猶似含顰望巡狩，九疑愁斷隔湘川。"]'),
('yuding-90','送唐侍禦福建省兄','李群玉','唐','御定全唐诗','yuding','','[]','桂枝攀盡賈家才，霄漢春風棣萼開。世掌綸言傳大筆，',40,'御定全唐詩/json/569.json','["桂枝攀盡賈家才，霄漢春風棣萼開。世掌綸言傳大筆，", "到日池塘春草綠，謝公應夢惠連來。"]'),
('yuding-91','送秦煉師歸岑公山','李群玉','唐','御定全唐诗','yuding','','[]','紫泥飛詔下金鑾，列象分明世仰觀。北省諫書藏舊草，',40,'御定全唐詩/json/569.json','["紫泥飛詔下金鑾，列象分明世仰觀。北省諫書藏舊草，", "偏是此生棲息者，滿衣零淚一時幹。"]'),
('yuding-92','潯陽觀水','李群玉','唐','御定全唐诗','yuding','','[]','朝宗漢水接陽臺，唅呀填坑吼作雷。莫見九江平穩去，',40,'御定全唐詩/json/569.json','["朝宗漢水接陽臺，唅呀填坑吼作雷。莫見九江平穩去，", "直至滄溟涵貯盡，深沉不動浸昭回。"]'),
('yuding-93','謫仙吟贈趙道士','李群玉','唐','御定全唐诗','yuding','','[]','汗漫東游黃鶴雛，縉雲仙子住清都。三元麟鳳推高座，',40,'御定全唐詩/json/569.json','["汗漫東游黃鶴雛，縉雲仙子住清都。三元麟鳳推高座，", "若為失意居蓬島，鼇足塵飛桑樹枯。"]'),
('yuding-94','長沙陪裴大夫夜宴','李群玉','唐','御定全唐诗','yuding','','[]','東山夜宴酒成河，銀燭熒煌照綺羅。四面雨聲籠笑語，',40,'御定全唐詩/json/569.json','["東山夜宴酒成河，銀燭熒煌照綺羅。四面雨聲籠笑語，", "共向柏台窺雅量，澄陂萬頃見天和。"]'),
('yuding-95','寶劍','李群玉','唐','御定全唐诗','yuding','','[]','雷煥豐城掘劍池，年深事遠跡依稀。泥沙難掩沖天氣，',40,'御定全唐詩/json/569.json','["雷煥豐城掘劍池，年深事遠跡依稀。泥沙難掩沖天氣，", "自從星坼中台後，化作雙龍去不歸。"]'),
('yuding-96','人日梅花病中作','李群玉','唐','御定全唐诗','yuding','','[]','去年今日湘南寺，獨把寒梅愁斷腸。今年此日江邊宅，',48,'御定全唐詩/json/569.json','["去年今日湘南寺，獨把寒梅愁斷腸。今年此日江邊宅，", "玉鱗寂寂飛斜月，素豔亭亭對夕陽。已被兒童苦攀折，"]'),
('yuding-0','靜夜相思','李群玉','唐','御定全唐诗','yuding','','[]','山空天籟寂，水榭延輕涼。浪定一浦月，藕花閑自香。',24,'御定全唐詩/json/570.json','["山空天籟寂，水榭延輕涼。浪定一浦月，藕花閑自香。"]'),
('yuding-1','桂州經佳人故居','李群玉','唐','御定全唐诗','yuding','','[]','桂水依舊綠，佳人本不還。只應隨暮雨，飛入九疑山。',24,'御定全唐詩/json/570.json','["桂水依舊綠，佳人本不還。只應隨暮雨，飛入九疑山。"]'),
('yuding-2','放魚','李群玉','唐','御定全唐诗','yuding','','[]','早覓為龍去，江湖莫漫遊。須知香餌下，觸口是銛鉤。',24,'御定全唐詩/json/570.json','["早覓為龍去，江湖莫漫遊。須知香餌下，觸口是銛鉤。"]'),
('yuding-3','蓮葉','李群玉','唐','御定全唐诗','yuding','','[]','根是泥中玉，心承露下珠。在君塘下種，埋沒任春浦。',24,'御定全唐詩/json/570.json','["根是泥中玉，心承露下珠。在君塘下種，埋沒任春浦。"]'),
('yuding-4','客愁二首','李群玉','唐','御定全唐诗','yuding','','[]','客愁看柳色，日日逐春深。蕩漾春風起，誰知曆亂心。',48,'御定全唐詩/json/570.json','["客愁看柳色，日日逐春深。蕩漾春風起，誰知曆亂心。", "客愁看柳色，日日逐春長。憑送湘流水，綿綿入帝鄉。"]'),
('yuding-5','洞庭幹二首','李群玉','唐','御定全唐诗','yuding','','[]','借問蓬萊水，誰逢清淺年。傷心雲夢澤，歲歲作桑田。',48,'御定全唐詩/json/570.json','["借問蓬萊水，誰逢清淺年。傷心雲夢澤，歲歲作桑田。", "朱宮紫貝闕，一旦作沙洲。八月還平在，魚蝦不用愁。"]'),
('yuding-6','病起別主人','李群玉','唐','御定全唐诗','yuding','','[]','益愧千金少，情將一飯殊。恨無泉客淚，盡泣感恩珠。',24,'御定全唐詩/json/570.json','["益愧千金少，情將一飯殊。恨無泉客淚，盡泣感恩珠。"]'),
('yuding-7','火爐前坐','李群玉','唐','御定全唐诗','yuding','','[]','孤燈照不寐，風雨滿西林。多少關心事，書灰到夜深。',24,'御定全唐詩/json/570.json','["孤燈照不寐，風雨滿西林。多少關心事，書灰到夜深。"]'),
('yuding-8','古詞','李群玉','唐','御定全唐诗','yuding','','[]','一合相思淚，臨江灑素秋。碧波如會意，卻與向西流。',24,'御定全唐詩/json/570.json','["一合相思淚，臨江灑素秋。碧波如會意，卻與向西流。"]'),
('yuding-9','嘲賣藥翁','李群玉','唐','御定全唐诗','yuding','','[]','劚盡春山土，辛勤賣藥翁。莫拋破笠子，留作敗天公。',24,'御定全唐詩/json/570.json','["劚盡春山土，辛勤賣藥翁。莫拋破笠子，留作敗天公。"]'),
('yuding-10','傷小女癡兒','李群玉','唐','御定全唐诗','yuding','','[]','哭爾春日短，支頤長歎嗟。不如半死樹，猶吐一枝花。',24,'御定全唐詩/json/570.json','["哭爾春日短，支頤長歎嗟。不如半死樹，猶吐一枝花。"]'),
('yuding-11','青鷁','李群玉','唐','御定全唐诗','yuding','','[]','獨立蒹葭雨，低飛浦嶼風。須知毛色下，莫入鷺鷥叢。',24,'御定全唐詩/json/570.json','["獨立蒹葭雨，低飛浦嶼風。須知毛色下，莫入鷺鷥叢。"]'),
('yuding-12','池塘晚景','李群玉','唐','御定全唐诗','yuding','','[]','風荷珠露傾，驚起睡鵁鶄。月落池塘靜，金刀剪一聲。',24,'御定全唐詩/json/570.json','["風荷珠露傾，驚起睡鵁鶄。月落池塘靜，金刀剪一聲。"]'),
('yuding-13','役從叔','李群玉','唐','御定全唐诗','yuding','','[]','可惜出群蹄，毛焦久臥泥。孫陽如不顧，騏驥向誰嘶。',24,'御定全唐詩/json/570.json','["可惜出群蹄，毛焦久臥泥。孫陽如不顧，騏驥向誰嘶。"]'),
('yuding-14','惱自澄','李群玉','唐','御定全唐诗','yuding','','[]','常聞天女會，玉指散天花。莫遣春風裏，紅芳點袈裟。',24,'御定全唐詩/json/570.json','["常聞天女會，玉指散天花。莫遣春風裏，紅芳點袈裟。"]'),
('yuding-15','讀賈誼傳','李群玉','唐','御定全唐诗','yuding','','[]','卑濕長沙地，空拋出世才。已齊生死理，鵩鳥莫為災。',24,'御定全唐詩/json/570.json','["卑濕長沙地，空拋出世才。已齊生死理，鵩鳥莫為災。"]'),
('yuding-16','寄人','李群玉','唐','御定全唐诗','yuding','','[]','寄語雙蓮子，須知用意深。莫嫌一點苦，便擬棄蓮心。',24,'御定全唐詩/json/570.json','["寄語雙蓮子，須知用意深。莫嫌一點苦，便擬棄蓮心。"]'),
('yuding-17','寄韋秀才','李群玉','唐','御定全唐诗','yuding','','[]','荊台蘭渚客，寥落共含情。空館相思夜，孤燈照雨聲。',24,'御定全唐詩/json/570.json','["荊台蘭渚客，寥落共含情。空館相思夜，孤燈照雨聲。"]'),
('yuding-18','春日寄友','李群玉','唐','御定全唐诗','yuding','','[]','晴氣熏櫻蕊，豐蒙雪滿林。請君三鬥酒，醉臥白羅岑。',24,'御定全唐詩/json/570.json','["晴氣熏櫻蕊，豐蒙雪滿林。請君三鬥酒，醉臥白羅岑。"]'),
('yuding-19','題竹','李群玉','唐','御定全唐诗','yuding','','[]','一頃含秋綠，森風十萬竿。氣吹朱夏轉，聲掃碧霄寒。',24,'御定全唐詩/json/570.json','["一頃含秋綠，森風十萬竿。氣吹朱夏轉，聲掃碧霄寒。"]'),
('yuding-20','懷初公','李群玉','唐','御定全唐诗','yuding','','[]','不見休上人，空傷碧雲思。何處開寶書，秋風海光寺。',24,'御定全唐詩/json/570.json','["不見休上人，空傷碧雲思。何處開寶書，秋風海光寺。"]'),
('yuding-21','龍安寺佳人阿最歌八首','李群玉','唐','御定全唐诗','yuding','','[]','團團明月面，冉冉柳枝腰。未入鴛鴦被，心長似火燒。',192,'御定全唐詩/json/570.json','["團團明月面，冉冉柳枝腰。未入鴛鴦被，心長似火燒。", "見面知何益，聞名憶轉深。拳攣荷葉子，未得展蓮心。", "欲摘不得摘，如看波上花。若教親玉樹，情願作蒹葭。", "門路穿茶焙，房門映竹煙。會須隨鹿女，乞火到窗前。", "不是求心印，都緣愛綠珠。何須同泰寺，然後始為奴。", "既為金界客，任改淨人名。願掃琉璃地，燒香過一生。", "素腕撩金索，輕紅約翠紗。不如欄下水，終日見桃花。", "第一龍宮女，相憐是阿誰。好魚輸獺盡，白鷺鎮長饑。"]'),
('yuding-22','野鴨','李群玉','唐','御定全唐诗','yuding','','[]','鸂鶒借毛衣，喧呼鷹隼稀。雲披菱藻地，任汝作群飛。',24,'御定全唐詩/json/570.json','["鸂鶒借毛衣，喧呼鷹隼稀。雲披菱藻地，任汝作群飛。"]'),
('yuding-23','題二妃廟','李群玉','唐','御定全唐诗','yuding','','[]','黃陵廟前春已空，子規啼血滴松風。',32,'御定全唐詩/json/570.json','["黃陵廟前春已空，子規啼血滴松風。", "不知精爽歸何處，疑是行雲秋色中。"]'),
('yuding-24','寄友二首','李群玉','唐','御定全唐诗','yuding','','[]','野水晴山雪後時，獨行村落更相思。',64,'御定全唐詩/json/570.json','["野水晴山雪後時，獨行村落更相思。", "無因一向溪頭醉，處處寒梅映酒旗。", "花落輕寒酒熟遲，醉眠不及落花期。", "愁人相憶春山暮，煙樹蒼蒼播谷時。"]'),
('yuding-25','桃源','李群玉','唐','御定全唐诗','yuding','','[]','我到瞿真上升處，山川四望使人愁。',32,'御定全唐詩/json/570.json','["我到瞿真上升處，山川四望使人愁。", "紫雪白鶴去不返，唯有桃花溪水流。"]'),
('yuding-26','題王侍禦宅','李群玉','唐','御定全唐诗','yuding','','[]','門向滄江碧岫開，地多鷗鷺少塵埃。',32,'御定全唐詩/json/570.json','["門向滄江碧岫開，地多鷗鷺少塵埃。", "綠陰十裏灘聲裏，閑自王家看竹來。"]'),
('yuding-27','聞湘南從叔朝覲','李群玉','唐','御定全唐诗','yuding','','[]','長沙地窄卻回時，舟楫駸駸向鳳池。',32,'御定全唐詩/json/570.json','["長沙地窄卻回時，舟楫駸駸向鳳池。", "為報湘川神女道，莫教雲雨濕旌旗。"]'),
('yuding-28','漢陽太白樓','李群玉','唐','御定全唐诗','yuding','','[]','江上層樓翠靄間，滿簾春水滿窗山。',32,'御定全唐詩/json/570.json','["江上層樓翠靄間，滿簾春水滿窗山。", "青楓綠草將愁去，遠入吳雲暝不還。"]'),
('yuding-29','送客','李群玉','唐','御定全唐诗','yuding','','[]','沅水羅文海燕回，柳條牽恨到荊台。',32,'御定全唐詩/json/570.json','["沅水羅文海燕回，柳條牽恨到荊台。", "定知行路春愁裏，故郢城邊見落梅。"]'),
('yuding-30','醴陵道中','李群玉','唐','御定全唐诗','yuding','','[]','別酒離亭十裏強，半醒半醉引愁長。',32,'御定全唐詩/json/570.json','["別酒離亭十裏強，半醒半醉引愁長。", "無端寂寂春山路，雪打溪梅狼藉香。"]'),
('yuding-31','校書叔遺暑服','李群玉','唐','御定全唐诗','yuding','','[]','翠雲箱裏疊樬櫳，楚葛湘紗淨似空。',32,'御定全唐詩/json/570.json','["翠雲箱裏疊樬櫳，楚葛湘紗淨似空。", "便著清江明月夜，輕涼與掛一身風。"]'),
('yuding-32','贈魏三十七','李群玉','唐','御定全唐诗','yuding','','[]','名珪字玉淨無瑕，美譽芳聲有數車。',32,'御定全唐詩/json/570.json','["名珪字玉淨無瑕，美譽芳聲有數車。", "莫放焰光高二丈，來年燒殺杏園花。"]'),
('yuding-33','酬崔表仁','李群玉','唐','御定全唐诗','yuding','','[]','昨日朱門一見君，忽驚野鶴在雞群。',32,'御定全唐詩/json/570.json','["昨日朱門一見君，忽驚野鶴在雞群。", "不應長啄潢污水，早晚歸飛碧落雲。"]'),
('yuding-34','旅遊番禺獻涼公','李群玉','唐','御定全唐诗','yuding','','[]','帝鄉群侶杳難尋，獨立滄洲歲暮心。',32,'御定全唐詩/json/570.json','["帝鄉群侶杳難尋，獨立滄洲歲暮心。", "野鶴棲飛無遠近，稻粱多處是恩深。"]'),
('yuding-35','長沙元門寺張璪員外壁畫','李群玉','唐','御定全唐诗','yuding','','[]','片石長松倚素楹，翛然雲壑見高情。',32,'御定全唐詩/json/570.json','["片石長松倚素楹，翛然雲壑見高情。", "世人只愛凡花鳥，無處不知梁廣名。"]'),
('yuding-36','請告出春明門','李群玉','唐','御定全唐诗','yuding','','[]','本不將心掛名利，亦無情意在樊籠。',32,'御定全唐詩/json/570.json','["本不將心掛名利，亦無情意在樊籠。", "鹿裘藜杖且歸去，富貴榮華春夢中。"]'),
('yuding-37','引水行','李群玉','唐','御定全唐诗','yuding','','[]','一條寒玉走秋泉，引出深蘿洞口煙。',32,'御定全唐詩/json/570.json','["一條寒玉走秋泉，引出深蘿洞口煙。", "十裏暗流聲不斷，行人頭上過潺湲。"]'),
('yuding-38','移松竹','李群玉','唐','御定全唐诗','yuding','','[]','龍髯鳳尾亂颼颼，帶霧停風一畝秋。',32,'御定全唐詩/json/570.json','["龍髯鳳尾亂颼颼，帶霧停風一畝秋。", "待取滿庭蒼翠合，酒尊書案閉門休。"]'),
('yuding-39','歎靈鷲寺山榴','李群玉','唐','御定全唐诗','yuding','','[]','水蝶岩蜂俱不知，露紅凝豔數千枝。',32,'御定全唐詩/json/570.json','["水蝶岩蜂俱不知，露紅凝豔數千枝。", "山深春晚無人賞，即是杜鵑催落時。"]'),
('yuding-40','黃陵廟','李群玉','唐','御定全唐诗','yuding','','[]','黃陵廟前莎草春，黃陵女兒茜裙新。',32,'御定全唐詩/json/570.json','["黃陵廟前莎草春，黃陵女兒茜裙新。", "輕舟短棹唱歌去，水遠山長愁殺人。"]'),
('yuding-41','北亭','李群玉','唐','御定全唐诗','yuding','','[]','斜雨飛絲織曉空，疏簾半卷野亭風。',32,'御定全唐詩/json/570.json','["斜雨飛絲織曉空，疏簾半卷野亭風。", "荷花向盡秋光晚，零落殘紅綠沼中。"]'),
('yuding-42','送客往涔陽','李群玉','唐','御定全唐诗','yuding','','[]','春與春愁逐日長，遠人天畔遠思鄉。',32,'御定全唐詩/json/570.json','["春與春愁逐日長，遠人天畔遠思鄉。", "蘋生水綠不歸去，孤負東溪七裏莊。"]'),
('yuding-43','寄友人鹿胎冠子','李群玉','唐','御定全唐诗','yuding','','[]','數點疏星紫錦斑，仙家新樣剪三山。',32,'御定全唐詩/json/570.json','["數點疏星紫錦斑，仙家新樣剪三山。", "宜與謝公松下戴，淨簪雲發翠微間。"]'),
('yuding-44','江南','李群玉','唐','御定全唐诗','yuding','','[]','鱗鱗別浦起微波，泛泛輕舟桃葉歌。',32,'御定全唐詩/json/570.json','["鱗鱗別浦起微波，泛泛輕舟桃葉歌。", "斜雪北風何處宿，江南一路酒旗多。"]'),
('yuding-45','答友人寄新茗','李群玉','唐','御定全唐诗','yuding','','[]','滿火芳香碾麹塵，吳甌湘水綠花新。',32,'御定全唐詩/json/570.json','["滿火芳香碾麹塵，吳甌湘水綠花新。", "愧君千里分滋味，寄與春風酒渴人。"]'),
('yuding-46','峽山寺上方','李群玉','唐','御定全唐诗','yuding','','[]','滿院泉聲水殿涼，疏簾微雨野松香。',32,'御定全唐詩/json/570.json','["滿院泉聲水殿涼，疏簾微雨野松香。", "東峰下視南溟月，笑踏金波看海光。"]'),
('yuding-47','秋登涔陽城二首','李群玉','唐','御定全唐诗','yuding','','[]','萬戶砧聲水國秋，涼風吹起故鄉愁。',64,'御定全唐詩/json/570.json','["萬戶砧聲水國秋，涼風吹起故鄉愁。", "行人望遠偏傷思，白浪青楓滿北樓。", "穿針樓上閉秋煙，織女佳期又來年。", "斜笛夜深吹不落，一條銀漢掛秋天。"]'),
('yuding-48','釣魚','李群玉','唐','御定全唐诗','yuding','','[]','七尺青竿一丈絲，菰浦葉裏逐風吹。',32,'御定全唐詩/json/570.json','["七尺青竿一丈絲，菰浦葉裏逐風吹。", "幾回舉手拋芳餌，驚起沙灘水鴨兒。"]'),
('yuding-49','酬魏三十七','李群玉','唐','御定全唐诗','yuding','','[]','靜裏寒香觸思初，開緘忽見二瓊琚。',32,'御定全唐詩/json/570.json','["靜裏寒香觸思初，開緘忽見二瓊琚。", "一吟麗可風流極，沒得弘文李校書。"]'),
('yuding-50','贈琵琶妓','李群玉','唐','御定全唐诗','yuding','','[]','我見鴛鴦飛水上，君還望月苦相思。',32,'御定全唐詩/json/570.json','["我見鴛鴦飛水上，君還望月苦相思。", "一雙裙帶同心結，早寄黃鸝孤雁兒。"]'),
('yuding-51','落帆後賦得二絕','李群玉','唐','御定全唐诗','yuding','','[]','平湖茫茫春日落，危檣獨映沙洲泊。',64,'御定全唐詩/json/570.json','["平湖茫茫春日落，危檣獨映沙洲泊。", "上岸閑尋細草行，古查飛起黃金鶚。", "水浮秋煙沙曉雪，皎潔無風燈影徹。", "海客雲帆未掛時，相與緣江拾明月。"]'),
('yuding-52','贈人','李群玉','唐','御定全唐诗','yuding','','[]','曾留宋玉舊衣裳，惹得巫山夢裏香。',32,'御定全唐詩/json/570.json','["曾留宋玉舊衣裳，惹得巫山夢裏香。", "雲雨無情難管領，任他別嫁楚襄王。"]'),
('yuding-53','贈妓人','李群玉','唐','御定全唐诗','yuding','','[]','誰家少女字千金，省向人間逐處尋。',32,'御定全唐詩/json/570.json','["誰家少女字千金，省向人間逐處尋。", "今日分明花裏見，一雙紅臉動春心。"]'),
('yuding-54','山榴','李群玉','唐','御定全唐诗','yuding','','[]','洞中春氣蒙籠暄，尚有紅英千樹繁。',32,'御定全唐詩/json/570.json','["洞中春氣蒙籠暄，尚有紅英千樹繁。", "可憐夾水錦步障，羞數石家金穀園。"]'),
('yuding-55','鸂鶒','李群玉','唐','御定全唐诗','yuding','','[]','錦羽相呼暮沙曲，波上雙聲戛哀玉。',32,'御定全唐詩/json/570.json','["錦羽相呼暮沙曲，波上雙聲戛哀玉。", "霞明川靜極望中，一時飛滅青山綠。"]'),
('yuding-56','沅江漁者','李群玉','唐','御定全唐诗','yuding','','[]','倚棹汀洲沙日晚，江鮮野菜桃花飯。',32,'御定全唐詩/json/570.json','["倚棹汀洲沙日晚，江鮮野菜桃花飯。", "長歌一曲煙靄深，歸去滄江綠波遠。"]'),
('yuding-57','題金山寺石堂','李群玉','唐','御定全唐诗','yuding','','[]','白波四面照樓臺，日夜潮聲繞寺回。',32,'御定全唐詩/json/570.json','["白波四面照樓臺，日夜潮聲繞寺回。", "千葉紅蓮高會處，幾曾龍女獻珠來。"]'),
('yuding-58','戲贈魏十四','李群玉','唐','御定全唐诗','yuding','','[]','蘭浦秋來煙雨深，幾多情思在琴心。',32,'御定全唐詩/json/570.json','["蘭浦秋來煙雨深，幾多情思在琴心。", "知君調得東家子，早晚和鳴入錦衾。"]'),
('yuding-59','和人贈別','李群玉','唐','御定全唐诗','yuding','','[]','嚬黛低紅別怨多，深亭芳恨滿橫波。',32,'御定全唐詩/json/570.json','["嚬黛低紅別怨多，深亭芳恨滿橫波。", "聲中唱出纏綿意，淚落燈前一曲歌。"]'),
('yuding-60','宿巫山廟二首','李群玉','唐','御定全唐诗','yuding','','[]','寂寞高堂別楚君，玉人天上逐行雲。',64,'御定全唐詩/json/570.json','["寂寞高堂別楚君，玉人天上逐行雲。", "停舟十二峰巒下，幽佩仙香半夜聞。", "廟閉春山曉月光，波聲回合樹蒼蒼。", "自從一別襄王夢，雲雨空飛巫峽長。"]'),
('yuding-61','傷柘枝妓','李群玉','唐','御定全唐诗','yuding','','[]','曾見雙鸞舞鏡中，聯飛接影對春風。',32,'御定全唐詩/json/570.json','["曾見雙鸞舞鏡中，聯飛接影對春風。", "今來獨在花筵散，月滿秋天一半空。"]'),
('yuding-62','題櫻桃','李群玉','唐','御定全唐诗','yuding','','[]','春初攜酒此花間，幾度臨風倒玉山。',32,'御定全唐詩/json/570.json','["春初攜酒此花間，幾度臨風倒玉山。", "今日葉深黃滿樹，再來惆悵不能攀。"]'),
('yuding-63','惱從兄','李群玉','唐','御定全唐诗','yuding','','[]','芳草萋萋新燕飛，芷汀南望雁書稀。',32,'御定全唐詩/json/570.json','["芳草萋萋新燕飛，芷汀南望雁書稀。", "武陵洞裏尋春客，已被桃花迷不歸。"]'),
('yuding-64','紫極宮齋後','李群玉','唐','御定全唐诗','yuding','','[]','紫府空歌碧落寒，曉星寥亮月光殘。',32,'御定全唐詩/json/570.json','["紫府空歌碧落寒，曉星寥亮月光殘。", "一群白鶴高飛上，唯有松風吹石壇。"]'),
('yuding-65','春晚','李群玉','唐','御定全唐诗','yuding','','[]','思鄉之客空凝嚬，天邊欲盡未盡春。',32,'御定全唐詩/json/570.json','["思鄉之客空凝嚬，天邊欲盡未盡春。", "獨攀江樹深不語，芳草落花愁殺人。"]'),
('yuding-66','喜渾吉見訪','李群玉','唐','御定全唐诗','yuding','','[]','公子春衫桂水香，遠沖飛雪過書堂。',32,'御定全唐詩/json/570.json','["公子春衫桂水香，遠沖飛雪過書堂。", "貧家冷落難消日，唯有松筠滿院涼。"]'),
('yuding-67','索曲送酒','李群玉','唐','御定全唐诗','yuding','','[]','簾外春風正落梅，須求狂藥解愁回。',32,'御定全唐詩/json/570.json','["簾外春風正落梅，須求狂藥解愁回。", "煩君玉指輕攏撚，慢撥鴛鴦送一杯。"]'),
('yuding-68','山驛梅花','李群玉','唐','御定全唐诗','yuding','','[]','生在幽崖獨無主，溪蘿澗鳥為儔侶。',32,'御定全唐詩/json/570.json','["生在幽崖獨無主，溪蘿澗鳥為儔侶。", "行人陌上不留情，愁香空謝深山雨。"]'),
('yuding-69','重陽日上渚宮楊尚書','李群玉','唐','御定全唐诗','yuding','','[]','落帽台邊菊半黃，行人惆悵對重陽。',32,'御定全唐詩/json/570.json','["落帽台邊菊半黃，行人惆悵對重陽。", "荊州一見桓宣武，為趁悲秋入帝鄉。"]'),
('yuding-70','書院二小松','李群玉','唐','御定全唐诗','yuding','','[]','一雙幽色出凡塵，數粒秋煙二尺鱗。',32,'御定全唐詩/json/570.json','["一雙幽色出凡塵，數粒秋煙二尺鱗。", "從此靜窗聞細韻，琴聲長伴讀書人。"]'),
('yuding-71','勸人廬山讀書','李群玉','唐','御定全唐诗','yuding','','[]','憐君少雋利如鋒，氣爽神清刻骨聰。',32,'御定全唐詩/json/570.json','["憐君少雋利如鋒，氣爽神清刻骨聰。", "片玉若磨唯轉瑩，莫辭雲水入廬峰。"]'),
('yuding-72','言懷','李群玉','唐','御定全唐诗','yuding','','[]','白鶴高飛不逐群，嵇康琴酒鮑昭文。',32,'御定全唐詩/json/570.json','["白鶴高飛不逐群，嵇康琴酒鮑昭文。", "此身未有棲歸處，天下人間一片雲。"]'),
('yuding-73','聞笛','李群玉','唐','御定全唐诗','yuding','','[]','冉冉生山草何異，截而吹之動天地。',32,'御定全唐詩/json/570.json','["冉冉生山草何異，截而吹之動天地。", "望鄉臺上望鄉時，不獨落梅兼落淚。"]'),
('yuding-74','曉宴','李群玉','唐','御定全唐诗','yuding','','[]','金波西傾銀漢落，綠樹含煙倚朱閣。',33,'御定全唐詩/json/570.json','["金波西傾銀漢落，綠樹含煙倚朱閣。", "曉華朧xz聞調笙，一點殘燈隔羅幕。"]'),
('yuding-75','將游荊州投魏中丞','李群玉','唐','御定全唐诗','yuding','','[]','貧埋病壓老巑岏，拂拭菱花不喜看。',32,'御定全唐詩/json/570.json','["貧埋病壓老巑岏，拂拭菱花不喜看。", "又恐無人肯青眼，事須憑仗小還丹。"]'),
('yuding-76','二辛夷','李群玉','唐','御定全唐诗','yuding','','[]','狂吟辭舞雙白鶴，霜翎玉羽紛紛落。',32,'御定全唐詩/json/570.json','["狂吟辭舞雙白鶴，霜翎玉羽紛紛落。", "空庭向晚春雨微，卻斂寒香抱瑤萼。"]'),
('yuding-77','題龍潭西齋','李群玉','唐','御定全唐诗','yuding','','[]','寂寞幽齋暝煙起，滿徑西風落松子。',32,'御定全唐詩/json/570.json','["寂寞幽齋暝煙起，滿徑西風落松子。", "遠公一去兜率宮，唯有面前虎溪水。"]'),
('yuding-78','中秋寄南海梁侍禦','李群玉','唐','御定全唐诗','yuding','','[]','海靜天高景氣殊，鯨睛失彩蚌潛珠。',32,'御定全唐詩/json/570.json','["海靜天高景氣殊，鯨睛失彩蚌潛珠。", "不知今夜越臺上，望見瀛洲方丈無。"]'),
('yuding-79','戲贈姬人','李群玉','唐','御定全唐诗','yuding','','[]','骰子巡拋裹手拈，無因得見玉纖纖。',32,'御定全唐詩/json/570.json','["骰子巡拋裹手拈，無因得見玉纖纖。", "但知謔道金釵落，圖向人前露指尖。"]'),
('yuding-80','大庾山嶺別友人','李群玉','唐','御定全唐诗','yuding','','[]','筼簹無子鴛雛饑，毛彩凋摧不得歸。',32,'御定全唐詩/json/570.json','["筼簹無子鴛雛饑，毛彩凋摧不得歸。", "誰念火雲千嶂裏，低身猶傍鷓鴣飛。"]'),
('yuding-81','石門戍','李群玉','唐','御定全唐诗','yuding','','[]','到此空思吳隱之，潮痕草蔓上幽碑。',32,'御定全唐詩/json/570.json','["到此空思吳隱之，潮痕草蔓上幽碑。", "人來皆望珠璣去，誰詠貪泉四句詩。"]'),
('yuding-82','文殊院避暑','李群玉','唐','御定全唐诗','yuding','','[]','赤日黃埃滿世間，松聲入耳即心閑。',32,'御定全唐詩/json/570.json','["赤日黃埃滿世間，松聲入耳即心閑。", "願尋五百仙人去，一世清涼住雪山。"]'),
('yuding-83','南莊春晚二首','李群玉','唐','御定全唐诗','yuding','','[]','連雲草映一條陂，鸂鶒雙雙帶水飛。',64,'御定全唐詩/json/570.json','["連雲草映一條陂，鸂鶒雙雙帶水飛。", "南村小路桃花落，細雨斜風獨自歸。", "草暖沙長望去舟，微茫煙浪向巴丘。", "沅江寂寂春歸盡，水綠蘋香人自愁。"]'),
('yuding-84','湘妃廟','李群玉','唐','御定全唐诗','yuding','','[]','少將風月怨平湖，見盡扶桑水到枯。',32,'御定全唐詩/json/570.json','["少將風月怨平湖，見盡扶桑水到枯。", "相約杏花壇上去，畫欄紅紫鬥樗蒲。"]'),
('yuding-0','古意','賈島','唐','御定全唐诗','yuding','','[]','碌碌複碌碌，百年雙轉轂。志士終夜心，良馬白日足。',48,'御定全唐詩/json/571.json','["碌碌複碌碌，百年雙轉轂。志士終夜心，良馬白日足。", "俱為不等閒，誰是知音目。眼中兩行淚，曾吊三獻玉。"]'),
('yuding-1','望山','賈島','唐','御定全唐诗','yuding','','[]','南山三十裏，不見逾一旬。冒雨時立望，望之如朋親。',96,'御定全唐詩/json/571.json','["南山三十裏，不見逾一旬。冒雨時立望，望之如朋親。", "虯龍一掬波，洗蕩千萬春。日日雨不斷，愁殺望山人。", "天事不可長，勁風來如奔。陰霪一以掃，浩翠寫國門。", "長安百萬家，家家張屏新。誰家最好山，我願為其鄰。"]'),
('yuding-2','北嶽廟','賈島','唐','御定全唐诗','yuding','','[]','天地有五嶽，恒岳居其北。岩巒疊萬重，詭怪浩難測。',60,'御定全唐詩/json/571.json','["天地有五嶽，恒岳居其北。岩巒疊萬重，詭怪浩難測。", "人來不敢入，祠宇白日黑。有時起霖雨，一灑天地德。", "神兮安在哉，永康我王國。"]'),
('yuding-3','朝饑','賈島','唐','御定全唐诗','yuding','','[]','市中有樵山，此舍朝無煙。井底有甘泉，釜中乃空然。',60,'御定全唐詩/json/571.json','["市中有樵山，此舍朝無煙。井底有甘泉，釜中乃空然。", "我要見白日，雪來塞青天。坐聞西床琴，凍折兩三弦。", "饑莫詣他門，古人有拙言。"]'),
('yuding-4','哭盧仝','賈島','唐','御定全唐诗','yuding','','[]','賢人無官死，不親者亦悲。空令古鬼哭，更得新鄰比。',108,'御定全唐詩/json/571.json','["賢人無官死，不親者亦悲。空令古鬼哭，更得新鄰比。", "平生四十年，惟著白布衣。天子未辟召，地府誰來追。", "長安有交友，托孤遽棄移。塚側志石短，文字行參差。", "無錢買松栽，自生蒿草枝。在日贈我文，淚流把讀時。", "從茲加敬重，深藏恐失遺。"]'),
('yuding-5','劍客','賈島','唐','御定全唐诗','yuding','','[]','十年磨一劍，霜刃未曾試。今日把似君，誰為不平事。',24,'御定全唐詩/json/571.json','["十年磨一劍，霜刃未曾試。今日把似君，誰為不平事。"]'),
('yuding-6','口號','賈島','唐','御定全唐诗','yuding','','[]','中夜忽自起，汲此百尺泉。林木含白露，星斗在青天。',24,'御定全唐詩/json/571.json','["中夜忽自起，汲此百尺泉。林木含白露，星斗在青天。"]'),
('yuding-7','寄遠','賈島','唐','御定全唐诗','yuding','','[]','別腸多鬱紆，豈能肥肌膚。始知相結密，不及相結疏。',96,'御定全唐詩/json/571.json','["別腸多鬱紆，豈能肥肌膚。始知相結密，不及相結疏。", "疏別恨應少，密離恨難袪。門前南流水，中有北飛魚。", "魚飛向北海，可以寄遠書。不惜寄遠書，故人今在無。", "況此數尺身，阻彼萬里途。自非日月光，難以知子軀。"]'),
('yuding-8','齋中','賈島','唐','御定全唐诗','yuding','','[]','眈靜非謬為，本性實疏索。齋中一就枕，不覺白日落。',84,'御定全唐詩/json/571.json','["眈靜非謬為，本性實疏索。齋中一就枕，不覺白日落。", "低扉礙軒轡，寡德謝接諾。叢菊在牆陰，秋窮未開萼。", "所餐類病馬，動影似移嶽。欲駐迫逃衰，豈殊辭綆縛。", "已見飽時雨，應豐蔬與藥。"]'),
('yuding-9','感秋','賈島','唐','御定全唐诗','yuding','','[]','商氣颯已來，歲華又虛擲。朝雲藏奇峰，暮雨灑疏滴。',96,'御定全唐詩/json/571.json','["商氣颯已來，歲華又虛擲。朝雲藏奇峰，暮雨灑疏滴。", "幾蜩嘿涼葉，數蛩思陰壁。落日空館中，歸心遠山碧。", "昔人多秋感，今人何異昔。四序馳百年，玄發坐成白。", "喧喧徇聲利，擾擾同轍跡。儻無世上懷，去偃松下石。"]'),
('yuding-10','玩月','賈島','唐','御定全唐诗','yuding','','[]','寒月破東北，賈生立西南。西南立倚何，立倚青青杉。',228,'御定全唐詩/json/571.json','["寒月破東北，賈生立西南。西南立倚何，立倚青青杉。", "近月有數星，星名未詳諳。但愛杉倚月，我倚杉為三。", "月乃不上杉，上杉難相參。眙愕子細視，睛瞳桂枝劖。", "目常有熱疾，久視無煩炎。以手捫衣裳，零露已濡沾。", "久立雙足凍，時向股髀淹。立久病足折，兀然黐膠粘。", "他人應已睡，轉喜此景恬。此景亦胡及，而我苦淫耽。", "無異市井人，見金不知廉。不知此夜中，幾人同無厭。", "待得上頂看，未擬歸枕函。強步望寢齋，步步情不堪。", "步到竹叢西，東望如隔簾。卻坐竹叢外，清思刮幽潛。", "量知愛月人，身願化為蟾。"]'),
('yuding-11','辭二知己','賈島','唐','御定全唐诗','yuding','','[]','一雙千歲鶴，立別孤翔鴻。波島忽已暮，海雨寒濛濛。',72,'御定全唐詩/json/571.json','["一雙千歲鶴，立別孤翔鴻。波島忽已暮，海雨寒濛濛。", "離人聞美彈，亦與哀彈同。況茲切切弄，繞彼行行躬。", "雲飛北嶽碧，火息西山紅。何以代遠誠，折芳臘雪中。"]'),
('yuding-12','義雀行和朱評事','賈島','唐','御定全唐诗','yuding','','[]','玄鳥雄雌俱，春雷驚蟄餘。口銜黃河泥，空即翔天隅。',84,'御定全唐詩/json/571.json','["玄鳥雄雌俱，春雷驚蟄餘。口銜黃河泥，空即翔天隅。", "一夕皆莫歸，嘵嘵遺眾雛。雙雀抱仁義，哺食勞劬劬。", "雛既邐迤飛，雲間聲相呼。燕雀雖微類，感愧誠不殊。", "禽賢難自彰，幸得主人書。"]'),
('yuding-13','宿懸泉驛','賈島','唐','御定全唐诗','yuding','','[]','曉行瀝水樓，暮到懸泉驛。林月值雲遮，山燈照愁寂。',24,'御定全唐詩/json/571.json','["曉行瀝水樓，暮到懸泉驛。林月值雲遮，山燈照愁寂。"]'),
('yuding-14','辯士','賈島','唐','御定全唐诗','yuding','','[]','辯士多毀訾，不聞談己非。猛虎恣殺暴，未嘗齧妻兒。',60,'御定全唐詩/json/571.json','["辯士多毀訾，不聞談己非。猛虎恣殺暴，未嘗齧妻兒。", "此理天所感，所感當問誰。求食飼雛禽，吐出美言詞。", "善哉君子人，揚光掩瑕玼。"]'),
('yuding-15','不欺','賈島','唐','御定全唐诗','yuding','','[]','上不欺星辰，下不欺鬼神。知心兩如此，然後何所陳。',60,'御定全唐詩/json/571.json','["上不欺星辰，下不欺鬼神。知心兩如此，然後何所陳。", "食魚味在鮮，食蓼味在辛。掘井須到流，結交須到頭。", "此語誠不謬，敵君三萬秋。"]'),
('yuding-16','絕句','賈島','唐','御定全唐诗','yuding','','[]','海底有明月，圓於天上輪。得之一寸光，可買千里春。',24,'御定全唐詩/json/571.json','["海底有明月，圓於天上輪。得之一寸光，可買千里春。"]'),
('yuding-17','寓興','賈島','唐','御定全唐诗','yuding','','[]','莫居暗室中，開目閉目同。莫趨碧霄路，容飛不容步。',48,'御定全唐詩/json/571.json','["莫居暗室中，開目閉目同。莫趨碧霄路，容飛不容步。", "暗室未可居，碧霄未可趨。勸君跨仙鶴，日下雲為衢。"]'),
('yuding-18','游仙','賈島','唐','御定全唐诗','yuding','','[]','借得孤鶴騎，高近金烏飛。掬河洗老貌，照月生光輝。',60,'御定全唐詩/json/571.json','["借得孤鶴騎，高近金烏飛。掬河洗老貌，照月生光輝。", "天中鶴路直，天盡鶴一息。歸來不騎鶴，身自有羽翼。", "若人無仙骨，芝朮徒煩食。"]'),
('yuding-19','枕上吟','賈島','唐','御定全唐诗','yuding','','[]','夜長憶白日，枕上吟千詩。何當苦寒氣，忽被東風吹。',36,'御定全唐詩/json/571.json','["夜長憶白日，枕上吟千詩。何當苦寒氣，忽被東風吹。", "冰開魚龍別，天波殊路岐。"]'),
('yuding-20','雙魚謠','賈島','唐','御定全唐诗','yuding','','[]','天河墮雙魴，飛我庭中央。掌握尺餘雪，劈開腸有璜。',48,'御定全唐詩/json/571.json','["天河墮雙魴，飛我庭中央。掌握尺餘雪，劈開腸有璜。", "見令饞舌短，烹繞鄰舍香。一得古詩字，與玉含異藏。"]'),
('yuding-21','易水懷古','賈島','唐','御定全唐诗','yuding','','[]','荊卿重虛死，節烈書前史。我歎方寸心，誰論一時事。',48,'御定全唐詩/json/571.json','["荊卿重虛死，節烈書前史。我歎方寸心，誰論一時事。", "至今易水橋，寒風兮蕭蕭。易水流得盡，荊卿名不消。"]'),
('yuding-22','早起','賈島','唐','御定全唐诗','yuding','','[]','北客入西京，北雁再離北。秋寢獨前興，天梭星落織。',72,'御定全唐詩/json/571.json','["北客入西京，北雁再離北。秋寢獨前興，天梭星落織。", "耽玩餘恬爽，顧盼輕痾力。旅途少顏盡，明鏡勸仙食。", "出門路縱橫，張家路最直。昨夜夢見書，張家廳上壁。"]'),
('yuding-23','客喜','賈島','唐','御定全唐诗','yuding','','[]','客喜非實喜，客悲非實悲。百回信到家，未當身一歸。',72,'御定全唐詩/json/571.json','["客喜非實喜，客悲非實悲。百回信到家，未當身一歸。", "未歸長嗟愁，嗟愁填中懷。開口吐愁聲，還卻入耳來。", "常恐淚滴多，自損兩目輝。鬢邊雖有絲，不堪織寒衣。"]'),
('yuding-24','延壽裏精舍寓居','賈島','唐','御定全唐诗','yuding','','[]','旅托避華館，荒樓遂愚慵。短庭無繁植，珍果春亦濃。',84,'御定全唐詩/json/571.json','["旅托避華館，荒樓遂愚慵。短庭無繁植，珍果春亦濃。", "側廬廢扃樞，纖魄時臥逢。耳目乃鄽井，肺肝即岩峰。", "汲泉飲酌餘，見我閒靜容。霜蹊猶舒英，寒蝶斷來蹤。", "雙履與誰逐，一尋青瘦筇。"]'),
('yuding-25','贈智朗禪師','賈島','唐','御定全唐诗','yuding','','[]','上人分明見，玉兔潭底沒。上人光慘貌，古來恨峭發。',84,'御定全唐詩/json/571.json','["上人分明見，玉兔潭底沒。上人光慘貌，古來恨峭發。", "涕辭孔顏廟，笑訪禪寂室。步隨青山影，坐學白塔骨。", "解聽無弄琴，不禮有身佛。欲問師何之，忽與我相別。", "率賦贈遠言，言慚非子曰。"]'),
('yuding-26','送沈秀才下第東歸','賈島','唐','御定全唐诗','yuding','','[]','曲言惡者誰，悅耳如彈絲。直言好者誰，刺耳如長錐。',108,'御定全唐詩/json/571.json','["曲言惡者誰，悅耳如彈絲。直言好者誰，刺耳如長錐。", "沈生才俊秀，心腸無邪欺。君子忌苟合，擇交如求師。", "毀出疾夫口，騰入禮部闈。下第子不恥，遺才人恥之。", "東歸家室遠，掉轡時參差。浙雲近吳見，汴柳接楚垂。", "明年春光別，回首不復疑。"]'),
('yuding-27','酬棲上人','賈島','唐','御定全唐诗','yuding','','[]','夜久城館閑，情幽出在山。新月有微輝，朗朗空庭間。',72,'御定全唐詩/json/571.json','["夜久城館閑，情幽出在山。新月有微輝，朗朗空庭間。", "處世雖識機，伊余多掩關。松姿度臘見，籬藥知春還。", "靜覽冰雪詞，厚為酬贈顏。東林有躑躅，脫屣期共攀。"]'),
('yuding-28','冬月長安雨中見終南雪','賈島','唐','御定全唐诗','yuding','','[]','秋節新已盡，雨疏露山雪。西峰稍覺明，殘滴猶未絕。',60,'御定全唐詩/json/571.json','["秋節新已盡，雨疏露山雪。西峰稍覺明，殘滴猶未絕。", "氣侵瀑布水，凍著白雲穴。今朝灞滻雁，何夕瀟湘月。", "想彼石房人，對雪扉不閉。"]'),
('yuding-29','寄孟協律','賈島','唐','御定全唐诗','yuding','','[]','我有吊古泣，不泣向路岐。揮淚灑暮天，滴著桂樹枝。',84,'御定全唐詩/json/571.json','["我有吊古泣，不泣向路岐。揮淚灑暮天，滴著桂樹枝。", "別後冬節至，離心北風吹。坐孤雪扉夕，泉落石橋時。", "不驚猛虎嘯，難辱君子詞。欲酬空覺老，無以堪遠持。", "岧嶢倚角窗，王屋懸清思。"]'),
('yuding-30','和劉涵','賈島','唐','御定全唐诗','yuding','','[]','京官始雲滿，野人依舊閑。閉扉一畝居，中有古風還。',84,'御定全唐詩/json/571.json','["京官始雲滿，野人依舊閑。閉扉一畝居，中有古風還。", "市井日已午，幽窗夢南山。喬木覆北齋，有鳥鳴其間。", "前日遠嶽僧，來時與開關。新題驚我瘦，窺鏡見醜顏。", "陶情惜清澹，此意複誰攀。"]'),
('yuding-31','明月山懷獨孤崇魚琢','賈島','唐','御定全唐诗','yuding','','[]','明月長在目，明月長在心。在心複在目，何得稀去尋。',108,'御定全唐詩/json/571.json','["明月長在目，明月長在心。在心複在目，何得稀去尋。", "試望明月人，孟夏樹蔽岑。想彼歎此懷，樂喧忘幽林。", "鄉本北嶽外，悔恨東夷深。願縮地脈還，豈待天恩臨。", "非不渴隱秀，卻嫌他事侵。或雲岳樓鐘，來繞草堂吟。", "當從令尹後，再往步柏林。"]'),
('yuding-32','投張太祝','賈島','唐','御定全唐诗','yuding','','[]','風骨高更老，向春初陽葩。泠泠月下韻，一一落海涯。',96,'御定全唐詩/json/571.json','["風骨高更老，向春初陽葩。泠泠月下韻，一一落海涯。", "有子不敢和，一聽千歎嗟。身臥東北泥，魂掛西南霞。", "手把一枝栗，往輕覺程賒。水天朔方色，暖日嵩根花。", "達閑幽棲山，遣尋種藥家。欲買雙瓊瑤，慚無一木瓜。"]'),
('yuding-33','詠韓氏二子','賈島','唐','御定全唐诗','yuding','','[]','千岩一尺璧，八月十五夕。清露墮桂花，白鳥舞虛碧。',24,'御定全唐詩/json/571.json','["千岩一尺璧，八月十五夕。清露墮桂花，白鳥舞虛碧。"]'),
('yuding-34','送別','賈島','唐','御定全唐诗','yuding','','[]','丈夫未得意，行行且低眉。素琴彈複彈，會有知音知。',24,'御定全唐詩/json/571.json','["丈夫未得意，行行且低眉。素琴彈複彈，會有知音知。"]'),
('yuding-35','攜新文詣張籍韓愈途中成','賈島','唐','御定全唐诗','yuding','','[]','袖有新成詩，欲見張韓老。青竹未生翼，一步萬里道。',72,'御定全唐詩/json/571.json','["袖有新成詩，欲見張韓老。青竹未生翼，一步萬里道。", "仰望青冥天，雲雪壓我腦。失卻終南山，惆悵滿懷抱。", "安得西北風，身願變蓬草。地只聞此語，突出驚我倒。"]'),
('yuding-36','上谷送客游江湖','賈島','唐','御定全唐诗','yuding','','[]','莫歎迢遞分，何殊咫尺別。江樓到夜登，還見南台月。',24,'御定全唐詩/json/571.json','["莫歎迢遞分，何殊咫尺別。江樓到夜登，還見南台月。"]'),
('yuding-37','重酬姚少府','賈島','唐','御定全唐诗','yuding','','[]','隙月斜枕旁，諷詠夏貽什。如今何時節，蟲虺亦已蟄。',144,'御定全唐詩/json/571.json','["隙月斜枕旁，諷詠夏貽什。如今何時節，蟲虺亦已蟄。", "答遲禮涉傲，抱疾思加澀。僕本胡為者，銜肩貢客集。", "茫然九州內，譬如一錐立。欺暗少此懷，自明曾瀝泣。", "量無趫勇士，誠欲戈矛戢。原閣期躋攀，潭舫偶俱入。", "深齋竹木合，畢夕風雨急。俸利沐均分，價稱煩噓噏。", "百篇見刪罷，一命嗟未及。滄浪愚將還，知音激所習。"]'),
('yuding-38','投孟郊','賈島','唐','御定全唐诗','yuding','','[]','月中有孤芳，天下聆熏風。江南有高唱，海北初來通。',192,'御定全唐詩/json/571.json','["月中有孤芳，天下聆熏風。江南有高唱，海北初來通。", "容飄清冷餘，自蘊襟抱中。止息乃流溢，推尋卻冥蒙。", "我知雪山子，謁彼偈句空。必竟獲所實，爾焉遂深衷。", "錄之孤燈前，猶恨百首終。一吟動狂機，萬疾辭頑躬。", "生平面未交，永夕夢輒同。敘詰誰君師，詎言無吾宗。", "餘求履其跡，君曰可但攻。啜波腸易飽，揖險神難從。", "前歲曾入洛，差池阻從龍。萍家複從趙，雲思長縈縈。", "嵩海每可詣，長途追再窮。原傾肺腸事，盡入焦梧桐。"]'),
('yuding-39','代邊將','賈島','唐','御定全唐诗','yuding','','[]','持戈簇邊日，戰罷浮雲收。露草泣寒霽，夜泉鳴隴頭。',48,'御定全唐詩/json/571.json','["持戈簇邊日，戰罷浮雲收。露草泣寒霽，夜泉鳴隴頭。", "三尺握中鐵，氣沖星斗牛。報國不拘貴，憤將平虜讎。"]'),
('yuding-40','寄劉棲楚','賈島','唐','御定全唐诗','yuding','','[]','趨走與偃臥，去就自殊分。當窗一重樹，上有萬里雲。',72,'御定全唐詩/json/571.json','["趨走與偃臥，去就自殊分。當窗一重樹，上有萬里雲。", "離披不相顧，仿佛類人群。友生去更遠，來書絕如焚。", "蟬吟我為聽，我歌蟬豈聞。歲暮儻旋歸，晤言桂氛氳。"]'),
('yuding-41','寄丘儒','賈島','唐','御定全唐诗','yuding','','[]','地近輕數見，地遠重一面。一面如何重，重甚珍寶片。',96,'御定全唐詩/json/571.json','["地近輕數見，地遠重一面。一面如何重，重甚珍寶片。", "自經失歡笑，幾度騰霜霰。此心鎮懸懸，天象固回轉。", "長安秋風高，子在東甸縣。儀形信寂蔑，風雨豈乖間。", "憑人報消息，何易憑筆硯。俱不盡我心，終須對君宴。"]'),
('yuding-42','送陳商','賈島','唐','御定全唐诗','yuding','','[]','古道長荊棘，新岐路交橫。君於荒榛中，尋得古轍行。',96,'御定全唐詩/json/571.json','["古道長荊棘，新岐路交橫。君於荒榛中，尋得古轍行。", "足踏聖人路，貌端禪士形。我曾接夜談，似聽講一經。", "聯翩曾數舉，昨登高第名。釜底絕煙火，曉行皇帝京。", "上客遠府游，主人須目明。青雲別青山，何日複可升。"]'),
('yuding-43','送張校書季霞','賈島','唐','御定全唐诗','yuding','','[]','從京去容州，馬在船上多。容州幾千里，直傍青天涯。',108,'御定全唐詩/json/571.json','["從京去容州，馬在船上多。容州幾千里，直傍青天涯。", "掌記試校書，未稱高詞華。義往不可屈，出家如入家。", "城市七月初，熱與夏未差。餞君到野地，秋涼滿山坡。", "南境異北候，風起無塵沙。秦吟宿楚澤，海酒落桂花。", "暫醉即還醒，彼土生桂茶。"]'),
('yuding-44','寄友人','賈島','唐','御定全唐诗','yuding','','[]','同人半年別，一別寂來音。賴有別時文，相思時一吟。',72,'御定全唐詩/json/571.json','["同人半年別，一別寂來音。賴有別時文，相思時一吟。", "我常倦投跡，君亦知此衿。筆硯且勿棄，蘇張曾陸沉。", "但存舌在口，當冀身遂心。君看明月夜，松桂寒森森。"]'),
('yuding-45','答王參','賈島','唐','御定全唐诗','yuding','','[]','寸晷不相待，四時互如競。客思先覺秋，蟲聲苦知暝。',72,'御定全唐詩/json/571.json','["寸晷不相待，四時互如競。客思先覺秋，蟲聲苦知暝。", "霜松積舊翠，露月團如鏡。詩負屬景同，琴孤坐堂聽。", "相期黃菊節，別約紅桃徑。每把式微篇，臨風一長詠。"]'),
('yuding-46','延康吟','賈島','唐','御定全唐诗','yuding','','[]','寄居延壽裏，為與延康鄰。不愛延康裏，愛此裏中人。',48,'御定全唐詩/json/571.json','["寄居延壽裏，為與延康鄰。不愛延康裏，愛此裏中人。", "人非十年故，人非九族親。人有不朽語，得之煙山春。"]'),
('yuding-47','戲贈友人','賈島','唐','御定全唐诗','yuding','','[]','一日不作詩，心源如廢井。筆硯為轆轤，吟詠作縻綆。',48,'御定全唐詩/json/571.json','["一日不作詩，心源如廢井。筆硯為轆轤，吟詠作縻綆。", "朝來重汲引，依舊得清冷。書贈同懷人，詞中多苦辛。"]'),
('yuding-48','寓興','賈島','唐','御定全唐诗','yuding','','[]','真集道方至，貌殊妒還多。山泉入城池，自然生渾波。',96,'御定全唐詩/json/571.json','["真集道方至，貌殊妒還多。山泉入城池，自然生渾波。", "今時出古言，在眾翻為訛。有琴含正韻，知音者如何。", "一生足感激，世言忽嵯峨。不得市井味，思響吾岩阿。", "浮華豈我事，日月徒蹉跎。曠哉潁陽風，千載無其他。"]'),
('yuding-49','懷鄭從志','賈島','唐','御定全唐诗','yuding','','[]','西風吹陰雲，雨雪半夜收。忽憶天涯人，起看鬥與牛。',72,'御定全唐詩/json/571.json','["西風吹陰雲，雨雪半夜收。忽憶天涯人，起看鬥與牛。", "故人別二年，我意如百秋。音信兩杳杳，誰雲昔綢繆。", "平明一封書，寄向東北舟。翩翩春歸鳥，會自為匹儔。"]'),
('yuding-50','易州登龍興寺樓望郡北高峰','賈島','唐','御定全唐诗','yuding','','[]','郡北最高峰，巉岩絕雲路。朝來上樓望，稍覺得幽趣。',48,'御定全唐詩/json/571.json','["郡北最高峰，巉岩絕雲路。朝來上樓望，稍覺得幽趣。", "朦朧碧煙裏，群嶺若相附。何時一登陟，萬物皆下顧。"]'),
('yuding-51','送鄭山人游江湖','賈島','唐','御定全唐诗','yuding','','[]','南游衡嶽上，東往天臺裏。足躡華頂峰，目觀滄海水。',24,'御定全唐詩/json/571.json','["南游衡嶽上，東往天臺裏。足躡華頂峰，目觀滄海水。"]'),
('yuding-52','就峰公宿','賈島','唐','御定全唐诗','yuding','','[]','河出鳥宿後，螢火白露中。上人坐不倚，共我論量空。',48,'御定全唐詩/json/571.json','["河出鳥宿後，螢火白露中。上人坐不倚，共我論量空。", "殘月華晻曖，遠水響玲瓏。爾時無了夢，茲宵方未窮。"]'),
('yuding-53','劉景陽東齋','賈島','唐','御定全唐诗','yuding','','[]','松陰連竹影，中有蕪苔井。清風此地多，白日空自永。',48,'御定全唐詩/json/571.json','["松陰連竹影，中有蕪苔井。清風此地多，白日空自永。", "景陽公幹孫，詩句得真景。勸我不須歸，月出東齋靜。"]'),
('yuding-54','對菊','賈島','唐','御定全唐诗','yuding','','[]','九日不出門，十日見黃菊。灼灼尚繁英，美人無消息。',24,'御定全唐詩/json/571.json','["九日不出門，十日見黃菊。灼灼尚繁英，美人無消息。"]'),
('yuding-55','送集文上人游方','賈島','唐','御定全唐诗','yuding','','[]','來從道陵井，雙木溪邊會。分首芳草時，遠意青天外。',36,'御定全唐詩/json/571.json','["來從道陵井，雙木溪邊會。分首芳草時，遠意青天外。", "此游詣幾岳，嵩華衡恒泰。"]'),
('yuding-56','題岸上人郡內閒居','賈島','唐','御定全唐诗','yuding','','[]','靜向方寸求，不居山嶂幽。池開菡萏香，門閉莓苔秋。',60,'御定全唐詩/json/571.json','["靜向方寸求，不居山嶂幽。池開菡萏香，門閉莓苔秋。", "金玉重四句，秕糠輕九流。爐煙上喬木，鐘磬下危樓。", "手種一株松，貞心與師儔。"]'),
('yuding-57','遊子','賈島','唐','御定全唐诗','yuding','','[]','遊子喜鄉遠，非吾憶歸廬。誰知奔他山，自欲早旋車。',48,'御定全唐詩/json/571.json','["遊子喜鄉遠，非吾憶歸廬。誰知奔他山，自欲早旋車。", "朝賞暮已足，圖歸願無餘。當期附鵬翼，未偶方躊躇。"]'),
('yuding-58','寄山中王參','賈島','唐','御定全唐诗','yuding','','[]','我看嶽西雲，君看嶽北月。長懷燕城南，相送十裏別。',48,'御定全唐詩/json/571.json','["我看嶽西雲，君看嶽北月。長懷燕城南，相送十裏別。", "別來千餘日，日日憶不歇。遠寄一紙書，數字論白髮。"]'),
('yuding-59','送汲鵬','賈島','唐','御定全唐诗','yuding','','[]','淮南臥理後，複逢君姓汲。文采非尋常，志願期卓立。',48,'御定全唐詩/json/571.json','["淮南臥理後，複逢君姓汲。文采非尋常，志願期卓立。", "深江東泛舟，夕陽眺原隰。夏夜言詩會，往往追不及。"]'),
('yuding-60','寄令狐相公','賈島','唐','御定全唐诗','yuding','','[]','策杖馳山驛，逢人問梓州。長江那可到，行客替生愁。',24,'御定全唐詩/json/571.json','["策杖馳山驛，逢人問梓州。長江那可到，行客替生愁。"]'),
('yuding-0','哭柏岩和尚','賈島','唐','御定全唐诗','yuding','','[]','苔覆石床新，師曾占幾春。寫留行道影，焚卻坐禪身。',48,'御定全唐詩/json/572.json','["苔覆石床新，師曾占幾春。寫留行道影，焚卻坐禪身。", "塔院關松雪，經房鎖隙塵。自嫌雙淚下，不是解空人。"]'),
('yuding-1','山中道士','賈島','唐','御定全唐诗','yuding','','[]','頭髮梳千下，休糧帶瘦容。養雛成大鶴，種子作高松。',48,'御定全唐詩/json/572.json','["頭髮梳千下，休糧帶瘦容。養雛成大鶴，種子作高松。", "白石通宵煮，寒泉盡日舂。不曾離隱處，那得世人逢。"]'),
('yuding-2','就可公宿','賈島','唐','御定全唐诗','yuding','','[]','十裏尋幽寺，寒流數派分。僧同雪夜坐，雁向草堂聞。',48,'御定全唐詩/json/572.json','["十裏尋幽寺，寒流數派分。僧同雪夜坐，雁向草堂聞。", "靜語終燈焰，餘生許嶠雲。由來多抱疾，聲不達明君。"]'),
('yuding-3','旅遊','賈島','唐','御定全唐诗','yuding','','[]','此心非一事，書劄若為傳。舊國別多日，故人無少年。',48,'御定全唐詩/json/572.json','["此心非一事，書劄若為傳。舊國別多日，故人無少年。", "空巢霜葉落，疏牖水螢穿。留得林僧宿，中宵坐默然。"]'),
('yuding-4','送鄒明府游靈武','賈島','唐','御定全唐诗','yuding','','[]','曾宰西畿縣，三年馬不肥。債多平劍與，官滿載書歸。',48,'御定全唐詩/json/572.json','["曾宰西畿縣，三年馬不肥。債多平劍與，官滿載書歸。", "邊雪藏行徑，林風透臥衣。靈州聽曉角，客館未開扉。"]'),
('yuding-5','題皇甫荀藍田廳','賈島','唐','御定全唐诗','yuding','','[]','任官經一年，縣與玉峰連。竹籠拾山果，瓦瓶擔石泉。',48,'御定全唐詩/json/572.json','["任官經一年，縣與玉峰連。竹籠拾山果，瓦瓶擔石泉。", "客歸秋雨後，印鎖暮鐘前。久別丹陽浦，時時夢釣船。"]'),
('yuding-6','贈王將軍','賈島','唐','御定全唐诗','yuding','','[]','宿衛爐煙近，除書墨未幹。馬曾金鏃中，身有寶刀瘢。',48,'御定全唐詩/json/572.json','["宿衛爐煙近，除書墨未幹。馬曾金鏃中，身有寶刀瘢。", "父子同時捷，君王畫陣看。何當為外帥，白日出長安。"]'),
('yuding-7','下第','賈島','唐','御定全唐诗','yuding','','[]','下第隻空囊，如何住帝鄉。杏園啼百舌，誰醉在花傍。',48,'御定全唐詩/json/572.json','["下第隻空囊，如何住帝鄉。杏園啼百舌，誰醉在花傍。", "淚落故山遠，病來春草長。知音逢豈易，孤棹負三湘。"]'),
('yuding-8','寄賀蘭朋吉','賈島','唐','御定全唐诗','yuding','','[]','往往東林下，花香似火焚。故園從小別，夜雨近秋聞。',96,'御定全唐詩/json/572.json','["往往東林下，花香似火焚。故園從小別，夜雨近秋聞。", "野菜連寒水，枯株簇古墳。泛舟同遠客，尋寺入幽雲。", "斜日扉多掩，荒田徑細分。相思蟬幾處，偶坐蝶成群。", "會宿曾論道，登高省議文。苦吟遙可想，邊葉向紛紛。"]'),
('yuding-9','憶吳處士','賈島','唐','御定全唐诗','yuding','','[]','半夜長安雨，燈前越客吟。孤舟行一月，萬水與千岑。',48,'御定全唐詩/json/572.json','["半夜長安雨，燈前越客吟。孤舟行一月，萬水與千岑。", "島嶼夏雲起，汀洲芳草深。何當折松葉，拂石剡溪陰。"]'),
('yuding-10','哭孟郊','賈島','唐','御定全唐诗','yuding','','[]','身死聲名在，多應萬古傳。寡妻無子息，破宅帶林泉。',48,'御定全唐詩/json/572.json','["身死聲名在，多應萬古傳。寡妻無子息，破宅帶林泉。", "塚近登山道，詩隨過海船。故人相吊後，斜日下寒天。"]'),
('yuding-11','送崔定','賈島','唐','御定全唐诗','yuding','','[]','未知遊子意，何不避炎蒸。幾日到漢水，新蟬鳴杜陵。',48,'御定全唐詩/json/572.json','["未知遊子意，何不避炎蒸。幾日到漢水，新蟬鳴杜陵。", "秋江待得月，夜語恨無僧。巴峽吟過否，連天十二層。"]'),
('yuding-12','寄白閣默公','賈島','唐','御定全唐诗','yuding','','[]','已知歸白閣，山遠晚晴看。石室人心靜，冰潭月影殘。',48,'御定全唐詩/json/572.json','["已知歸白閣，山遠晚晴看。石室人心靜，冰潭月影殘。", "微雲分片滅，古木落薪幹。後夜誰聞磬，西峰絕頂寒。"]'),
('yuding-13','雨後宿劉司馬池上','賈島','唐','御定全唐诗','yuding','','[]','藍溪秋漱玉，此地漲清澄。蘆葦聲兼雨，芰荷香繞燈。',48,'御定全唐詩/json/572.json','["藍溪秋漱玉，此地漲清澄。蘆葦聲兼雨，芰荷香繞燈。", "岸頭秦古道，亭面漢荒陵。靜想泉根本，幽崖落幾層。"]'),
('yuding-14','送朱可久歸越中','賈島','唐','御定全唐诗','yuding','','[]','石頭城下泊，北固暝鐘初。汀鷺潮沖起，船窗月過虛。',48,'御定全唐詩/json/572.json','["石頭城下泊，北固暝鐘初。汀鷺潮沖起，船窗月過虛。", "吳山侵越眾，隋柳入唐疏。日欲躬調膳，辟來何府書。"]'),
('yuding-15','送田卓入華山','賈島','唐','御定全唐诗','yuding','','[]','幽深足暮蟬，驚覺石床眠。瀑布五千仞，草堂瀑布邊。',48,'御定全唐詩/json/572.json','["幽深足暮蟬，驚覺石床眠。瀑布五千仞，草堂瀑布邊。", "壇松涓滴露，嶽月泬寥天。鶴過君須看，上頭應有仙。"]'),
('yuding-16','送董正字常州覲省','賈島','唐','御定全唐诗','yuding','','[]','相逐一行鴻，何時出磧中。江流翻白浪，木葉落青楓。',48,'御定全唐詩/json/572.json','["相逐一行鴻，何時出磧中。江流翻白浪，木葉落青楓。", "輕楫浮吳國，繁霜下楚空。春來歡侍阻，正字在東宮。"]'),
('yuding-17','酬姚少府','賈島','唐','御定全唐诗','yuding','','[]','梅樹與山木，俱應搖落初。柴門掩寒雨，蟲響出秋蔬。',48,'御定全唐詩/json/572.json','["梅樹與山木，俱應搖落初。柴門掩寒雨，蟲響出秋蔬。", "枯槁彰清鏡，孱愚友道書。刊文非不朽，君子自相于。"]'),
('yuding-18','送無可上人','賈島','唐','御定全唐诗','yuding','','[]','圭峰霽色新，送此草堂人。麈尾同離寺，蛩鳴暫別親。',48,'御定全唐詩/json/572.json','["圭峰霽色新，送此草堂人。麈尾同離寺，蛩鳴暫別親。", "獨行潭底影，數息樹邊身。終有煙霞約，天臺作近鄰。"]'),
('yuding-19','送李騎曹','賈島','唐','御定全唐诗','yuding','','[]','歸騎雙旌遠，歡生此別中。蕭關分磧路，嘶馬背寒鴻。',48,'御定全唐詩/json/572.json','["歸騎雙旌遠，歡生此別中。蕭關分磧路，嘶馬背寒鴻。", "朔色晴天北，河源落日東。賀蘭山頂草，時動卷帆風。"]'),
('yuding-20','送烏行中石淙別業','賈島','唐','御定全唐诗','yuding','','[]','寒水長繩汲，丁泠數滴翻。草通石淙脈，硯帶海潮痕。',48,'御定全唐詩/json/572.json','["寒水長繩汲，丁泠數滴翻。草通石淙脈，硯帶海潮痕。", "嶽色何曾遠，蟬聲尚未繁。勞思當此夕，苗稼在西原。"]'),
('yuding-21','送覺興上人歸中條山兼謁河中李司空','賈島','唐','御定全唐诗','yuding','','[]','又憶西岩寺，秦原草白時。山尋樵徑上，人到雪房遲。',48,'御定全唐詩/json/572.json','["又憶西岩寺，秦原草白時。山尋樵徑上，人到雪房遲。", "暮磬潭泉凍，荒林野燒移。聞師新譯偈，說擬對旌麾。"]'),
('yuding-22','寄無可上人','賈島','唐','御定全唐诗','yuding','','[]','僻寺多高樹，涼天憶重遊。磬過溝水盡，月入草堂秋。',48,'御定全唐詩/json/572.json','["僻寺多高樹，涼天憶重遊。磬過溝水盡，月入草堂秋。", "穴蟻苔痕靜，藏蟬柏葉稠。名山思遍往，早晚到嵩丘。"]'),
('yuding-23','南池','賈島','唐','御定全唐诗','yuding','','[]','蕭條微雨絕，荒岸抱清源。入舫山侵塞，分泉稻接村。',48,'御定全唐詩/json/572.json','["蕭條微雨絕，荒岸抱清源。入舫山侵塞，分泉稻接村。", "秋聲依樹色，月影在蒲根。淹泊方難遂，他宵關夢魂。"]'),
('yuding-24','寄龍池寺貞空二上人','賈島','唐','御定全唐诗','yuding','','[]','受請終南住，俱妨去石橋。林中秋信絕，峰頂夜禪遙。',48,'御定全唐詩/json/572.json','["受請終南住，俱妨去石橋。林中秋信絕，峰頂夜禪遙。", "寒草煙藏虎，高松月照雕。霜天期到寺，寺置即前朝。"]'),
('yuding-25','送貞空二上人','賈島','唐','御定全唐诗','yuding','','[]','林下中餐後，天涯欲去時。衡陽過有伴，夢澤出應遲。',48,'御定全唐詩/json/572.json','["林下中餐後，天涯欲去時。衡陽過有伴，夢澤出應遲。", "石磬疏寒韻，銅瓶結夜澌。殷勤訝此別，且未定歸期。"]'),
('yuding-26','送裴校書','賈島','唐','御定全唐诗','yuding','','[]','拜官從秘省，署職在藩維。多故長疏索，高秋遠別離。',48,'御定全唐詩/json/572.json','["拜官從秘省，署職在藩維。多故長疏索，高秋遠別離。", "天寒泗上醉，夜靜岳陽棋。使府臨南海，帆飛到不遲。"]'),
('yuding-27','升道精舍南台對月寄姚合','賈島','唐','御定全唐诗','yuding','','[]','月向南台見，秋霖洗滌餘。出逢危葉落，靜看眾峰疏。',48,'御定全唐詩/json/572.json','["月向南台見，秋霖洗滌餘。出逢危葉落，靜看眾峰疏。", "冷露常時有，禪窗此夜虛。相思聊悵望，潤氣遍衣初。"]'),
('yuding-28','即事','賈島','唐','御定全唐诗','yuding','','[]','索莫對孤燈，陰雲積幾層。自嗟憐十上，誰肯待三征。',84,'御定全唐詩/json/572.json','["索莫對孤燈，陰雲積幾層。自嗟憐十上，誰肯待三征。", "心被通人見，文叨大匠稱。悲秋秦塞草，懷古漢家陵。", "城靜高崖樹，漏多幽沼冰。過聲沙島鷺，絕行石庵僧。", "豈謂舊廬在，誰言歸未曾。"]'),
('yuding-29','黃子陂上韓吏部','賈島','唐','御定全唐诗','yuding','','[]','石樓雲一別，二十二三春。相逐升堂者，幾為埋骨人。',96,'御定全唐詩/json/572.json','["石樓雲一別，二十二三春。相逐升堂者，幾為埋骨人。", "涕流聞度瘴，病起喜還秦。曾是令勤道，非惟恤在迍。", "疏衣蕉縷細，爽味茗芽新。鐘絕滴殘雨，螢多無近鄰。", "溪潭承到數，位秩見辭頻。若個山招隱，機忘任此身。"]'),
('yuding-30','投李益','賈島','唐','御定全唐诗','yuding','','[]','四十歸燕字，千年外始吟。已將書北嶽，不用比南金。',24,'御定全唐詩/json/572.json','["四十歸燕字，千年外始吟。已將書北嶽，不用比南金。"]'),
('yuding-31','吊孟協律','賈島','唐','御定全唐诗','yuding','','[]','才行古人齊，生前品位低。葬時貧賣馬，遠日哭惟妻。',48,'御定全唐詩/json/572.json','["才行古人齊，生前品位低。葬時貧賣馬，遠日哭惟妻。", "孤塚北邙外，空齋中嶽西。集詩應萬首，物象遍曾題。"]'),
('yuding-32','送人適越','賈島','唐','御定全唐诗','yuding','','[]','高城滿夕陽，何事欲沾裳。遷客蓬蒿暮，遊人道路長。',48,'御定全唐詩/json/572.json','["高城滿夕陽，何事欲沾裳。遷客蓬蒿暮，遊人道路長。", "晴湖勝鏡碧，寒柳似金黃。若有相思夢，殷勤載八行。"]'),
('yuding-33','送僧游衡岳','賈島','唐','御定全唐诗','yuding','','[]','心知衡岳路，不怕去人稀。船裏猶鳴磬，溪頭自曝衣。',48,'御定全唐詩/json/572.json','["心知衡岳路，不怕去人稀。船裏猶鳴磬，溪頭自曝衣。", "有家從小別，無寺不言歸。料得逢寒住，當禪雪滿扉。"]'),
('yuding-34','送路','賈島','唐','御定全唐诗','yuding','','[]','別我就蓬蒿，日斜飛伯勞。龍門流水急，嵩岳片雲高。',48,'御定全唐詩/json/572.json','["別我就蓬蒿，日斜飛伯勞。龍門流水急，嵩岳片雲高。", "歎命無知己，梳頭落白毛。從軍當此去，風起廣陵濤。"]'),
('yuding-35','洛陽道中寄弟','賈島','唐','御定全唐诗','yuding','','[]','趨走迫流年，慚經此路偏。密雲埋二室，積雪度三川。',48,'御定全唐詩/json/572.json','["趨走迫流年，慚經此路偏。密雲埋二室，積雪度三川。", "生類梗萍泛，悲無金石堅。翻鴻有歸翼，極目仰聯翩。"]'),
('yuding-36','登江亭晚望','賈島','唐','御定全唐诗','yuding','','[]','浩渺浸雲根，煙嵐沒遠村。鳥歸沙有跡，帆過浪無痕。',48,'御定全唐詩/json/572.json','["浩渺浸雲根，煙嵐沒遠村。鳥歸沙有跡，帆過浪無痕。", "望水知柔性，看山欲倦魂。縱情猶未已，回馬欲黃昏。"]'),
('yuding-37','送耿處士','賈島','唐','御定全唐诗','yuding','','[]','一瓶離別酒，未盡即言行。萬水千山路，孤舟幾月程。',48,'御定全唐詩/json/572.json','["一瓶離別酒，未盡即言行。萬水千山路，孤舟幾月程。", "川原秋色靜，蘆葦晚風鳴。迢遞不歸客，人傳虛隱名。"]'),
('yuding-38','過唐校書書齋','賈島','唐','御定全唐诗','yuding','','[]','池滿風吹竹，時時得爽神。聲齊雛鳥語，畫卷老僧真。',48,'御定全唐詩/json/572.json','["池滿風吹竹，時時得爽神。聲齊雛鳥語，畫卷老僧真。", "月出行幾步，花開到四鄰。江湖心自切，未可掛頭巾。"]'),
('yuding-39','送杜秀才東游','賈島','唐','御定全唐诗','yuding','','[]','東遊誰見待，盡室寄長安。別後葉頻落，去程山已寒。',48,'御定全唐詩/json/572.json','["東遊誰見待，盡室寄長安。別後葉頻落，去程山已寒。", "大河風色度，曠野燒煙殘。匣有青銅鏡，時將照鬢看。"]'),
('yuding-40','送天臺僧','賈島','唐','御定全唐诗','yuding','','[]','遠夢歸華頂，扁舟背岳陽。寒蔬修淨食，夜浪動禪床。',48,'御定全唐詩/json/572.json','["遠夢歸華頂，扁舟背岳陽。寒蔬修淨食，夜浪動禪床。", "雁過孤峰曉，猿啼一樹霜。身心無別念，餘習在詩章。"]'),
('yuding-41','懷紫閣隱者','賈島','唐','御定全唐诗','yuding','','[]','寂寥思隱者，孤燭坐秋霖。梨栗猿喜熟，雲山僧說深。',48,'御定全唐詩/json/572.json','["寂寥思隱者，孤燭坐秋霖。梨栗猿喜熟，雲山僧說深。", "寄書應不到，結伴擬同尋。廢寢方終夕，迢迢紫閣心。"]'),
('yuding-42','雨夜同厲玄懷皇甫荀','賈島','唐','御定全唐诗','yuding','','[]','桐竹繞庭匝，雨多風更吹。還如舊山夜，臥聽瀑泉時。',48,'御定全唐詩/json/572.json','["桐竹繞庭匝，雨多風更吹。還如舊山夜，臥聽瀑泉時。", "磧雁來期近，秋鐘到夢遲。溝西吟苦客，中夕話兼思。"]'),
('yuding-43','秋暮','賈島','唐','御定全唐诗','yuding','','[]','北門楊柳葉，不覺已繽紛。值鶴因臨水，迎僧忽背雲。',48,'御定全唐詩/json/572.json','["北門楊柳葉，不覺已繽紛。值鶴因臨水，迎僧忽背雲。", "白須相並出，清淚兩行分。默默空朝夕，苦吟誰喜聞。"]'),
('yuding-44','哭胡遇','賈島','唐','御定全唐诗','yuding','','[]','夭壽知齊理，何曾免歎嗟。祭回收朔雪，吊後折寒花。',48,'御定全唐詩/json/572.json','["夭壽知齊理，何曾免歎嗟。祭回收朔雪，吊後折寒花。", "野水秋吟斷，空山暮影斜。弟兄相識遍，猶得到君家。"]'),
('yuding-45','送丹師歸閩中','賈島','唐','御定全唐诗','yuding','','[]','波濤路杳然，衰柳落陽蟬。行李經雷電，禪前漱島泉。',48,'御定全唐詩/json/572.json','["波濤路杳然，衰柳落陽蟬。行李經雷電，禪前漱島泉。", "歸林久別寺，過越未離船。自說從今去，身應老海邊。"]'),
('yuding-46','送安南惟鑒法師','賈島','唐','御定全唐诗','yuding','','[]','講經春殿裏，花繞禦床飛。南海幾回渡，舊山臨老歸。',48,'御定全唐詩/json/572.json','["講經春殿裏，花繞禦床飛。南海幾回渡，舊山臨老歸。", "潮搖蠻草落，月濕島松微。空水既如彼，往來消息稀。"]'),
('yuding-47','題李凝幽居','賈島','唐','御定全唐诗','yuding','','[]','閒居少鄰並，草徑入荒園。鳥宿池邊樹，僧敲月下門。',48,'御定全唐詩/json/572.json','["閒居少鄰並，草徑入荒園。鳥宿池邊樹，僧敲月下門。", "過橋分野色，移石動雲根。暫去還來此，幽期不負言。"]'),
('yuding-48','送韓湘','賈島','唐','御定全唐诗','yuding','','[]','掛席從古路，長風起廣津。楚城花未發，上苑蝶來新。',72,'御定全唐詩/json/572.json','["掛席從古路，長風起廣津。楚城花未發，上苑蝶來新。", "半沒湖波月，初生島草春。孤霞臨石鏡，極浦映村神。", "細響吟幹葦，餘馨動遠蘋。欲憑將一劄，寄與沃洲人。"]'),
('yuding-49','寄董武','賈島','唐','御定全唐诗','yuding','','[]','雖同一城裏，少省得從容。門掩園林僻，日高巾幘慵。',48,'御定全唐詩/json/572.json','["雖同一城裏，少省得從容。門掩園林僻，日高巾幘慵。", "孤鴻來半夜，積雪在諸峰。正憶毗陵客，聲聲隔水鐘。"]'),
('yuding-50','宿贇上人房','賈島','唐','御定全唐诗','yuding','','[]','階前多是竹，閑地擬栽松。朱點草書疏，雪平麻履蹤。',48,'御定全唐詩/json/572.json','["階前多是竹，閑地擬栽松。朱點草書疏，雪平麻履蹤。", "禦溝寒夜雨，宮寺靜時鐘。此時無他事，來尋不厭重。"]'),
('yuding-51','訪李甘原居','賈島','唐','御定全唐诗','yuding','','[]','原西居處靜，門對曲江開。石縫銜枯草，查根上淨苔。',48,'御定全唐詩/json/572.json','["原西居處靜，門對曲江開。石縫銜枯草，查根上淨苔。", "翠微泉夜落，紫閣鳥時來。仍憶尋淇岸，同行采蕨回。"]'),
('yuding-52','題山寺井','賈島','唐','御定全唐诗','yuding','','[]','沉沉百尺餘，功就豈斯須。汲早僧出定，鑿新蟲自無。',48,'御定全唐詩/json/572.json','["沉沉百尺餘，功就豈斯須。汲早僧出定，鑿新蟲自無。", "藏源重嶂底，澄翳大空隅。此地如經劫，涼潭會共枯。"]'),
('yuding-53','僻居無可上人相訪','賈島','唐','御定全唐诗','yuding','','[]','自從居此地，少有事相關。積雨荒鄰圃，秋池照遠山。',48,'御定全唐詩/json/572.json','["自從居此地，少有事相關。積雨荒鄰圃，秋池照遠山。", "硯中枯葉落，枕上斷雲閑。野客將禪子，依依偏往還。"]'),
('yuding-54','送李餘及第歸蜀','賈島','唐','御定全唐诗','yuding','','[]','知音伸久屈，覲省去光輝。津渡逢清夜，途程盡翠微。',48,'御定全唐詩/json/572.json','["知音伸久屈，覲省去光輝。津渡逢清夜，途程盡翠微。", "雲當綿竹疊，鳥離錦江飛。肯寄書來否，原居出亦稀。"]'),
('yuding-55','荒齋','賈島','唐','御定全唐诗','yuding','','[]','草合徑微微，終南對掩扉。晚涼疏雨絕，初曉遠山稀。',48,'御定全唐詩/json/572.json','["草合徑微微，終南對掩扉。晚涼疏雨絕，初曉遠山稀。", "落葉無青地，閑身著白衣。朴愚猶本性，不是學忘機。"]'),
('yuding-56','夜喜賀蘭三見訪','賈島','唐','御定全唐诗','yuding','','[]','漏鐘仍夜淺，時節欲秋分。泉聒棲松鶴，風除翳月雲。',48,'御定全唐詩/json/572.json','["漏鐘仍夜淺，時節欲秋分。泉聒棲松鶴，風除翳月雲。", "踏苔行引興，枕石臥論文。即此尋常靜，來多只是君。"]'),
('yuding-57','題青龍寺鏡公房','賈島','唐','御定全唐诗','yuding','','[]','一夕曾留宿，終南搖落時。孤燈岡舍掩，殘磬雪風吹。',48,'御定全唐詩/json/572.json','["一夕曾留宿，終南搖落時。孤燈岡舍掩，殘磬雪風吹。", "樹老因寒折，泉深出井遲。疏慵豈有事，多失上方期。"]'),
('yuding-58','送陳判官赴綏德','賈島','唐','御定全唐诗','yuding','','[]','將軍邀入幕，束帶便離家。身暖蕉衣窄，天寒磧日斜。',48,'御定全唐詩/json/572.json','["將軍邀入幕，束帶便離家。身暖蕉衣窄，天寒磧日斜。", "火燒岡斷葦，風卷雪平沙。絲竹豐州有，春來隻欠花。"]'),
('yuding-59','送唐環歸敷水莊','賈島','唐','御定全唐诗','yuding','','[]','毛女峰當戶，日高頭未梳。地侵山影掃，葉帶露痕書。',48,'御定全唐詩/json/572.json','["毛女峰當戶，日高頭未梳。地侵山影掃，葉帶露痕書。", "松徑僧尋藥，沙泉鶴見魚。一川風景好，恨不有吾廬。"]'),
('yuding-60','原東居喜唐溫琪頻至','賈島','唐','御定全唐诗','yuding','','[]','曲江春草生，紫閣雪分明。汲井嘗泉味，聽鐘問寺名。',48,'御定全唐詩/json/572.json','["曲江春草生，紫閣雪分明。汲井嘗泉味，聽鐘問寺名。", "墨研秋日雨，茶試老僧鐺。地近勞頻訪，烏紗出送迎。"]'),
('yuding-61','送敡法師','賈島','唐','御定全唐诗','yuding','','[]','度歲不相見，嚴冬始出關。孤煙寒色樹，高雪夕陽山。',48,'御定全唐詩/json/572.json','["度歲不相見，嚴冬始出關。孤煙寒色樹，高雪夕陽山。", "瀑布寺應到，牡丹房甚閑。南朝遺跡在，此去幾時還。"]'),
('yuding-62','寄錢庶子','賈島','唐','御定全唐诗','yuding','','[]','曲江春水滿，北岸掩柴關。只有僧鄰舍，全無物映山。',48,'御定全唐詩/json/572.json','["曲江春水滿，北岸掩柴關。只有僧鄰舍，全無物映山。", "樹陰終日掃，藥債來年還。猶記聽琴夜，寒燈竹屋間。"]'),
('yuding-63','原上秋居','賈島','唐','御定全唐诗','yuding','','[]','關西又落木，心事複如何。歲月辭山久，秋霖入夜多。',48,'御定全唐詩/json/572.json','["關西又落木，心事複如何。歲月辭山久，秋霖入夜多。", "鳥從井口出，人自洛陽過。倚仗聊閑望，田家未剪禾。"]'),
('yuding-64','夏夜','賈島','唐','御定全唐诗','yuding','','[]','原寺偏鄰近，開門物景澄。磬通多葉罅，月離片雲棱。',48,'御定全唐詩/json/572.json','["原寺偏鄰近，開門物景澄。磬通多葉罅，月離片雲棱。", "寄宿山中鳥，相尋海畔僧。唯愁秋色至，乍可在炎蒸。"]'),
('yuding-65','冬夜','賈島','唐','御定全唐诗','yuding','','[]','羈旅複經冬，瓢空盎亦空。淚流寒枕上，跡絕舊山中。',48,'御定全唐詩/json/572.json','["羈旅複經冬，瓢空盎亦空。淚流寒枕上，跡絕舊山中。", "淩結浮萍水，雪和衰柳風。曙光雞未報，嘹唳兩三鴻。"]'),
('yuding-66','送厲宗上人','賈島','唐','御定全唐诗','yuding','','[]','擁策背岷峨，終南雨雪和。漱泉秋鶴至，禪樹夜猿過。',48,'御定全唐詩/json/572.json','["擁策背岷峨，終南雨雪和。漱泉秋鶴至，禪樹夜猿過。", "高頂白雲盡，前山黃葉多。曾吟廬嶽上，月動九江波。"]'),
('yuding-67','寄李存穆','賈島','唐','御定全唐诗','yuding','','[]','聞道船中病，似憂親弟兄。信來從水路，身去到柴城。',48,'御定全唐詩/json/572.json','["聞道船中病，似憂親弟兄。信來從水路，身去到柴城。", "久別長須鬢，相思書姓名。忽然消息絕，頻夢卻還京。"]'),
('yuding-68','贈無懷禪師','賈島','唐','御定全唐诗','yuding','','[]','身從劫劫修，果以此生周。禪定石床暖，月移山樹秋。',48,'御定全唐詩/json/572.json','["身從劫劫修，果以此生周。禪定石床暖，月移山樹秋。", "捧盂觀宿飯，敲磬過清流。不掩玄關路，教人問白頭。"]'),
('yuding-69','寄武功姚主簿','賈島','唐','御定全唐诗','yuding','','[]','居枕江沱北，情懸渭曲西。數宵曾夢見，幾處得書披。',120,'御定全唐詩/json/572.json','["居枕江沱北，情懸渭曲西。數宵曾夢見，幾處得書披。", "驛路穿荒阪，公田帶淤泥。靜棋功奧妙，閑作韻清淒。", "鋤草留叢藥，尋山上石梯。客回河水漲，風起夕陽低。", "空地苔連井，孤村火隔溪。捲簾黃葉落，鎖印子規啼。", "隴色澄秋月，邊聲入戰鼙。會須過縣去，況是屢招攜。"]'),
('yuding-70','題劉華書齋','賈島','唐','御定全唐诗','yuding','','[]','白石床無塵，青松樹有鱗。一鶯啼帶雨，兩樹合從春。',96,'御定全唐詩/json/572.json','["白石床無塵，青松樹有鱗。一鶯啼帶雨，兩樹合從春。", "荒榭苔膠砌，幽叢果墮榛。偶來疏或數，當暑夕勝晨。", "露滴星河水，巢重草木薪。終南同往意，趙北獨遊身。", "渡葉司天漏，驚蛩遠地人。機清公幹族，也莫臥漳濱。"]'),
('yuding-71','送盧秀才游潞府','賈島','唐','御定全唐诗','yuding','','[]','雨餘滋潤在，風不起塵沙。邊日寡文思，送君吟月華。',48,'御定全唐詩/json/572.json','["雨餘滋潤在，風不起塵沙。邊日寡文思，送君吟月華。", "過山幹相府，臨水宿僧家。能賦焉長屈，芳春宴杏花。"]'),
('yuding-72','送南康姚明府','賈島','唐','御定全唐诗','yuding','','[]','銅章美少年，小邑在南天。版籍多遷客，封疆接洞田。',48,'御定全唐詩/json/572.json','["銅章美少年，小邑在南天。版籍多遷客，封疆接洞田。", "靜江鳴野鼓，發纜帶村煙。卻笑陶元亮，何須憶醉眠。"]'),
('yuding-73','送友人棄官游江左','賈島','唐','御定全唐诗','yuding','','[]','羨君休作尉，萬事且全身。寰海多虞日，江湖獨往人。',48,'御定全唐詩/json/572.json','["羨君休作尉，萬事且全身。寰海多虞日，江湖獨往人。", "姓名何處變，鷗鳥幾時親。別後吳中使，應須訪子真。"]'),
('yuding-74','雨中懷友人','賈島','唐','御定全唐诗','yuding','','[]','對雨思君子，嘗茶近竹幽。儒家鄰古寺，不到又逢秋。',24,'御定全唐詩/json/572.json','["對雨思君子，嘗茶近竹幽。儒家鄰古寺，不到又逢秋。"]'),
('yuding-75','寄遠','賈島','唐','御定全唐诗','yuding','','[]','家住錦水上，身征遼海邊。十書九不到，一到忽經年。',24,'御定全唐詩/json/572.json','["家住錦水上，身征遼海邊。十書九不到，一到忽經年。"]'),
('yuding-76','南齋','賈島','唐','御定全唐诗','yuding','','[]','獨自南齋臥，神閑景亦空。有山來枕上，無事到心中。',48,'御定全唐詩/json/572.json','["獨自南齋臥，神閑景亦空。有山來枕上，無事到心中。", "簾卷侵床月，屏遮入座風。望春春未至，應在海門東。"]'),
('yuding-77','早春題友人湖上新居二首','賈島','唐','御定全唐诗','yuding','','[]','近得雲中路，門長侵早開。到時猶有雪，行處已無苔。',96,'御定全唐詩/json/572.json','["近得雲中路，門長侵早開。到時猶有雪，行處已無苔。", "勸酒客初醉，留茶僧未來。每逢晴暖日，惟見乞花栽。", "門不當官道，行人到亦稀。故從餐後出，多是夜深歸。", "開篋收詩卷，掃床移臥衣。幾時同買宅，相送有柴扉。"]'),
('yuding-78','送雍陶入蜀','賈島','唐','御定全唐诗','yuding','','[]','江山事若諳，那肯滯雲南。草色分危磴，杉陰近古潭。',48,'御定全唐詩/json/572.json','["江山事若諳，那肯滯雲南。草色分危磴，杉陰近古潭。", "日斜褒谷鳥，夏淺巂州蠶。吾自疑雙鬢，相逢更不堪。"]'),
('yuding-79','張郎中過原東居','賈島','唐','御定全唐诗','yuding','','[]','年長惟添懶，經旬止掩關。高人餐藥後，下馬此林間。',48,'御定全唐詩/json/572.json','["年長惟添懶，經旬止掩關。高人餐藥後，下馬此林間。", "對坐天將暮，同來客亦閑。幾時能重至，水味似深山。"]'),
('yuding-80','答王建秘書','賈島','唐','御定全唐诗','yuding','','[]','人皆聞蟋蟀，我獨恨蹉跎。白髮無心鑷，青山去意多。',48,'御定全唐詩/json/572.json','["人皆聞蟋蟀，我獨恨蹉跎。白髮無心鑷，青山去意多。", "信來漳浦岸，期負洞庭波。時掃高槐影，朝回或恐過。"]'),
('yuding-81','送李餘往湖南','賈島','唐','御定全唐诗','yuding','','[]','昔去候溫涼，秋山滿楚鄉。今來從辟命，春物遍涔陽。',48,'御定全唐詩/json/572.json','["昔去候溫涼，秋山滿楚鄉。今來從辟命，春物遍涔陽。", "岳石掛海雪，野楓堆渚檣。若尋吾祖宅，寂寞在瀟湘。"]'),
('yuding-82','偶作','賈島','唐','御定全唐诗','yuding','','[]','野步隨吾意，那知是與非。稔年時雨足，閏月暮蟬稀。',48,'御定全唐詩/json/572.json','["野步隨吾意，那知是與非。稔年時雨足，閏月暮蟬稀。", "獨樹依岡老，遙峰出草微。園林自有主，宿鳥且同歸。"]'),
('yuding-83','過雍秀才居','賈島','唐','御定全唐诗','yuding','','[]','夏木鳥巢邊，終南嶺色鮮。就涼安坐石，煮茗汲鄰泉。',48,'御定全唐詩/json/572.json','["夏木鳥巢邊，終南嶺色鮮。就涼安坐石，煮茗汲鄰泉。", "鐘遠清霄半，蜩稀暑雨前。幽齋如葺罷，約我一來眠。"]'),
('yuding-84','寄顧非熊','賈島','唐','御定全唐诗','yuding','','[]','知君歸有處，山水亦難齊。猶去瀟湘遠，不聞猿狖啼。',48,'御定全唐詩/json/572.json','["知君歸有處，山水亦難齊。猶去瀟湘遠，不聞猿狖啼。", "穴通茆嶺下，潮滿石頭西。獨立生遙思，秋原日漸低。"]'),
('yuding-85','送神邈法師','賈島','唐','御定全唐诗','yuding','','[]','柳絮落濛濛，西州道路中。相逢春忽盡，獨去講初終。',48,'御定全唐詩/json/572.json','["柳絮落濛濛，西州道路中。相逢春忽盡，獨去講初終。", "行疾遙山雨，眠遲後夜風。繞房三兩樹，回日葉應紅。"]'),
('yuding-86','送慈恩寺霄韻法師謁太原李司空','賈島','唐','御定全唐诗','yuding','','[]','何故謁司空，雲山知幾重。磧遙來雁盡，雪急去僧逢。',48,'御定全唐詩/json/572.json','["何故謁司空，雲山知幾重。磧遙來雁盡，雪急去僧逢。", "清磬先寒角，禪燈徹曉烽。舊房閑片石，倚著最高松。"]'),
('yuding-87','送知興上人','賈島','唐','御定全唐诗','yuding','','[]','久住巴興寺，如今始拂衣。欲臨秋水別，不向故園歸。',48,'御定全唐詩/json/572.json','["久住巴興寺，如今始拂衣。欲臨秋水別，不向故園歸。", "錫掛天涯樹，房開嶽頂扉。下看千里曉，霜海日生微。"]'),
('yuding-88','送惠雅法師歸玉泉','賈島','唐','御定全唐诗','yuding','','[]','只到瀟湘水，洞庭湖未遊。飲泉看月別，下峽聽猿愁。',48,'御定全唐詩/json/572.json','["只到瀟湘水，洞庭湖未遊。飲泉看月別，下峽聽猿愁。", "講不停雷雨，吟當近海流。降霜歸楚夕，星冷玉泉秋。"]'),
('yuding-89','憶江上吳處士','賈島','唐','御定全唐诗','yuding','','[]','閩國揚帆去，蟾蜍虧複團。秋風生渭水，落葉滿長安。',48,'御定全唐詩/json/572.json','["閩國揚帆去，蟾蜍虧複團。秋風生渭水，落葉滿長安。", "此地聚會夕，當時雷雨寒。蘭橈殊未返，消息海雲端。"]'),
('yuding-90','題張博士新居','賈島','唐','御定全唐诗','yuding','','[]','青楓何不種，林在洞庭村。應為三湘遠，難移萬雷根。',48,'御定全唐詩/json/572.json','["青楓何不種，林在洞庭村。應為三湘遠，難移萬雷根。", "鬥牛初過伏，菡萏欲香門。舊即湖山隱，新廬葺此原。"]'),
('yuding-91','石門陂留辭從叔謨','賈島','唐','御定全唐诗','yuding','','[]','幽鳥飛不遠，此行千里間。寒沖陂水霧，醉下菊花山。',48,'御定全唐詩/json/572.json','["幽鳥飛不遠，此行千里間。寒沖陂水霧，醉下菊花山。", "有恥長為客，無成又入關。何時臨澗柳，吾黨共來攀。"]'),
('yuding-92','送朱兵曹回越','賈島','唐','御定全唐诗','yuding','','[]','星彩練中見，澄江豈有泥。潮生垂釣罷，楚盡去檣西。',48,'御定全唐詩/json/572.json','["星彩練中見，澄江豈有泥。潮生垂釣罷，楚盡去檣西。", "磧鳥辭沙至，山鼯隔水啼。會稽半侵海，濤白禹祠溪。"]'),
('yuding-93','懷博陵故人','賈島','唐','御定全唐诗','yuding','','[]','孤城易水頭，不忘舊交遊。雪壓圍棋石，風吹飲酒樓。',48,'御定全唐詩/json/572.json','["孤城易水頭，不忘舊交遊。雪壓圍棋石，風吹飲酒樓。", "路遙千萬里，人別十三秋。吟苦相思處，天寒水急流。"]'),
('yuding-94','夕思','賈島','唐','御定全唐诗','yuding','','[]','秋宵已難曙，漏向二更分。我憶山水坐，蟲當寂寞聞。',48,'御定全唐詩/json/572.json','["秋宵已難曙，漏向二更分。我憶山水坐，蟲當寂寞聞。", "洞庭風落木，天姥月離雲。會自東浮去，將何欲致君。"]'),
('yuding-95','寄河中楊少尹','賈島','唐','御定全唐诗','yuding','','[]','非惟咎曩時，投刺詣門遲。悵望三秋後，參差萬里期。',48,'御定全唐詩/json/572.json','["非惟咎曩時，投刺詣門遲。悵望三秋後，參差萬里期。", "禹留疏鑿跡，舜在寂寥祠。此到杳難共，回風逐所思。"]'),
('yuding-96','孟融逸人','賈島','唐','御定全唐诗','yuding','','[]','孟君臨水居，不食水中魚。衣褐唯粗帛，筐箱只素書。',48,'御定全唐詩/json/572.json','["孟君臨水居，不食水中魚。衣褐唯粗帛，筐箱只素書。", "樹林幽鳥戀，世界此心疏。擬棹孤舟去，何峰又結廬。"]'),
('yuding-97','晚晴見終南諸峰','賈島','唐','御定全唐诗','yuding','','[]','秦分積多峰，連巴勢不窮。半旬藏雨裏，此日到窗中。',48,'御定全唐詩/json/572.json','["秦分積多峰，連巴勢不窮。半旬藏雨裏，此日到窗中。", "圓魄將升兔，高空欲叫鴻。故山思不見，碣石泬寥東。"]'),
('yuding-98','宿池上','賈島','唐','御定全唐诗','yuding','','[]','泉來從絕壑，亭敞在中流。竹密無空岸，松長可絆舟。',48,'御定全唐詩/json/572.json','["泉來從絕壑，亭敞在中流。竹密無空岸，松長可絆舟。", "蟪蛄潭上夜，河漢島前秋。異夕期深漲，攜琴卻此遊。"]'),
('yuding-99','喜姚郎中自杭州回','賈島','唐','御定全唐诗','yuding','','[]','路多楓樹林，累日泊清陰。來去泛流水，翛然適此心。',48,'御定全唐詩/json/572.json','["路多楓樹林，累日泊清陰。來去泛流水，翛然適此心。", "一披江上作，三起月中吟。東省期司諫，雲門悔不尋。"]'),
('yuding-100','送鄭長史之嶺南','賈島','唐','御定全唐诗','yuding','','[]','雲林頗重疊，岑渚複幽奇。汨水斜陽岸，騷人正則祠。',48,'御定全唐詩/json/572.json','["雲林頗重疊，岑渚複幽奇。汨水斜陽岸，騷人正則祠。", "蒼梧多蟋蟀，白露濕江蘺。擢第榮南去，晨昏近九疑。"]'),
('yuding-101','送李溟謁宥州李權使君','賈島','唐','御定全唐诗','yuding','','[]','英雄典宥州，迢遞苦吟遊。風宿驪山下，月斜灞水流。',48,'御定全唐詩/json/572.json','["英雄典宥州，迢遞苦吟遊。風宿驪山下，月斜灞水流。", "去時初落葉，回日定非秋。太守攜才子，看鵬百尺樓。"]'),
('yuding-102','永福湖和楊鄭州','賈島','唐','御定全唐诗','yuding','','[]','積水還平岸，春來引鄭溪。舊渠通郭下，新堰絕湖西。',48,'御定全唐詩/json/572.json','["積水還平岸，春來引鄭溪。舊渠通郭下，新堰絕湖西。", "嵩少分明對，瀟湘闊狹齊。客遊隨庶子，孤嶼草萋萋。"]'),
('yuding-103','題長江','賈島','唐','御定全唐诗','yuding','','[]','言心俱好靜，廨署落暉空。歸吏封宵鑰，行蛇入古桐。',48,'御定全唐詩/json/572.json','["言心俱好靜，廨署落暉空。歸吏封宵鑰，行蛇入古桐。", "長江頻雨後，明月眾星中。若任遷人去，西溪與剡通。"]'),
('yuding-104','泥陽館','賈島','唐','御定全唐诗','yuding','','[]','客愁何並起，暮送故人回。廢館秋螢出，空城寒雨來。',48,'御定全唐詩/json/572.json','["客愁何並起，暮送故人回。廢館秋螢出，空城寒雨來。", "夕陽飄白露，樹影掃青苔。獨坐離容慘，孤燈照不開。"]'),
('yuding-105','送徐員外赴河中','賈島','唐','御定全唐诗','yuding','','[]','原野正蕭瑟，中間分散情。吏從甘扈罷，詔許朔方行。',48,'御定全唐詩/json/572.json','["原野正蕭瑟，中間分散情。吏從甘扈罷，詔許朔方行。", "邊日沉殘角，河關截夜城。雲居閑獨往，長老出房迎。"]'),
('yuding-106','送賀蘭上人','賈島','唐','御定全唐诗','yuding','','[]','野僧來別我，略坐傍泉沙。遠道擎空缽，深山蹋落花。',48,'御定全唐詩/json/572.json','["野僧來別我，略坐傍泉沙。遠道擎空缽，深山蹋落花。", "無師禪自解，有格句堪誇。此去非緣事，孤雲不定家。"]'),
('yuding-0','送令狐綯相公','賈島','唐','御定全唐诗','yuding','','[]','梁園趨戟節，海草幾枯春。風水難遭便，差池未振鱗。',216,'御定全唐詩/json/573.json','["梁園趨戟節，海草幾枯春。風水難遭便，差池未振鱗。", "姓名猶語及，門館阻何因。苦擬修文卷，重擎獻匠人。", "吟看青島處，朝退赤墀晨。根愛杉栽活，枝憐雪霰新。", "綴篇嗟調逸，不和揣才貧。早晚還霖雨，滂沱洗月輪。", "揠苗方滅裂，成器待陶鈞。困阪思回顧，迷邦輒問津。", "數行望外劄，絕句握中珍。是日榮遊汴，當時怯往陳。", "鴻舂乖漢爵，楨病臥漳濱。嶽整五千仞，雲惟一片身。", "故山離未死，秋水宿經旬。下第能無恧，高科恐有神。", "罷耕田料廢，省釣岸應榛。慷慨知音在，誰能淚墮巾。"]'),
('yuding-1','寄滄州李尚書','賈島','唐','御定全唐诗','yuding','','[]','滄溟深絕闊，西岸郭東門。戈者羅夷鳥，桴人思嶠猿。',168,'御定全唐詩/json/573.json','["滄溟深絕闊，西岸郭東門。戈者羅夷鳥，桴人思嶠猿。", "威棱高臘冽，煦育極春溫。陂澱封疆內，蒹葭壁壘根。", "搖鞞邊地脈，愁箭虎狼魂。水縣賣紗市，鹽田煮海村。", "枝條分禦葉，家世食唐恩。武可縱橫講，功從戰伐論。", "天涯生月片，嶼頂湧泉源。非是泥池物，方因雷雨尊。", "沉謀藏未露，鄰境帖無喧。青塚驕回鶻，蕭關陷葉蕃。", "何時霖歲旱，早晚雪邦冤。迢遞瞻旌纛，浮陽寄詠言。"]'),
('yuding-2','逢舊識','賈島','唐','御定全唐诗','yuding','','[]','幾歲阻干戈，今朝勸酒歌。羨君無白髮，走馬過黃河。',48,'御定全唐詩/json/573.json','["幾歲阻干戈，今朝勸酒歌。羨君無白髮，走馬過黃河。", "舊宅兵燒盡，新宮日奏多。妖星還有角，數尺鐵重磨。"]'),
('yuding-3','崇聖寺斌公房','賈島','唐','御定全唐诗','yuding','','[]','近來惟一食，樹下掩禪扉。落日寒山磬，多年壞衲衣。',48,'御定全唐詩/json/573.json','["近來惟一食，樹下掩禪扉。落日寒山磬，多年壞衲衣。", "白須長更剃，青靄遠還歸。仍說遊南嶽，經行是息機。"]'),
('yuding-4','送李傅侍郎劍南行營','賈島','唐','御定全唐诗','yuding','','[]','走馬從邊事，新恩受外台。勇看雙節出，期破八蠻回。',72,'御定全唐詩/json/573.json','["走馬從邊事，新恩受外台。勇看雙節出，期破八蠻回。", "許國家無戀，盤江棧不摧。移軍刁鬥逐，報捷劍門開。", "角咽獼猴叫，鼙幹霹靂來。去年新甸邑，猶滯佐時才。"]'),
('yuding-5','別徐明府','賈島','唐','御定全唐诗','yuding','','[]','抱琴非本意，生事偶相縈。口尚袁安節，身無子賤名。',72,'御定全唐詩/json/573.json','["抱琴非本意，生事偶相縈。口尚袁安節，身無子賤名。", "地寒春雪盛，山淺夕風輕。百戰餘荒野，千夫漸耦耕。", "一杯宜獨夜，孤客戀交情。明日疲驂去，蕭條過古城。"]'),
('yuding-6','岐下送友人歸襄陽','賈島','唐','御定全唐诗','yuding','','[]','蹉跎隨泛梗，羈旅到西州。舉翮籠中鳥，知心海上鷗。',48,'御定全唐詩/json/573.json','["蹉跎隨泛梗，羈旅到西州。舉翮籠中鳥，知心海上鷗。", "山光分首暮，草色向家秋。若更登高峴，看碑定淚流。"]'),
('yuding-7','送友人游蜀','賈島','唐','御定全唐诗','yuding','','[]','萬岑深積翠，路向此中難。欲暮多羈思，因高莫遠看。',48,'御定全唐詩/json/573.json','["萬岑深積翠，路向此中難。欲暮多羈思，因高莫遠看。", "卓家人寂寞，揚子業凋殘。唯有岷江水，悠悠帶月寒。"]'),
('yuding-8','送鄭少府','賈島','唐','御定全唐诗','yuding','','[]','江岸一相見，空令惜此分。夕陽行帶月，酌水少留君。',48,'御定全唐詩/json/573.json','["江岸一相見，空令惜此分。夕陽行帶月，酌水少留君。", "野地初燒草，荒山過雪雲。明年還調集，蟬可在家聞。"]'),
('yuding-9','子規','賈島','唐','御定全唐诗','yuding','','[]','遊魂自相叫，寧複記前身。飛過鄰家月，聲連野路春。',48,'御定全唐詩/json/573.json','["遊魂自相叫，寧複記前身。飛過鄰家月，聲連野路春。", "夢邊催曉急，愁處送風頻。自有沾花血，相和雨滴新。"]'),
('yuding-10','送僧歸天臺','賈島','唐','御定全唐诗','yuding','','[]','辭秦經越過，歸寺海西峰。石澗雙流水，山門九裏松。',48,'御定全唐詩/json/573.json','["辭秦經越過，歸寺海西峰。石澗雙流水，山門九裏松。", "曾聞清禁漏，卻聽赤城鐘。妙宇研磨講，應齊智者蹤。"]'),
('yuding-11','讓糾曹上樂使君','賈島','唐','御定全唐诗','yuding','','[]','戰戰複兢兢，猶如履薄冰。雖然叨一掾，還似說三乘。',48,'御定全唐詩/json/573.json','["戰戰複兢兢，猶如履薄冰。雖然叨一掾，還似說三乘。", "瓶汲南溪水，書來北嶽僧。戇愚兼抱疾，權紀不相應。"]'),
('yuding-12','贈友人','賈島','唐','御定全唐诗','yuding','','[]','五字詩成卷，清新韻具偕。不同狂客醉，自伴律僧齋。',48,'御定全唐詩/json/573.json','["五字詩成卷，清新韻具偕。不同狂客醉，自伴律僧齋。", "春別和花樹，秋辭帶月淮。卻歸登第日，名近榜頭排。"]'),
('yuding-13','送雍陶及第歸成都甯親','賈島','唐','御定全唐诗','yuding','','[]','不唯詩著籍，兼又賦知名。議論於題稱，春秋對問精。',96,'御定全唐詩/json/573.json','["不唯詩著籍，兼又賦知名。議論於題稱，春秋對問精。", "半應陰騭與，全賴有司平。歸去峰巒眾，別來松桂生。", "漲江流水品，當道白雲坑。勿以攻文捷，而將學劍輕。", "制衣新濯錦，開醞舊燒罌。同日升科士，誰同膝下榮。"]'),
('yuding-14','謝令狐綯相公賜衣九事','賈島','唐','御定全唐诗','yuding','','[]','長江飛鳥外，主簿跨驢歸。逐客寒前夜，元戎予厚衣。',48,'御定全唐詩/json/573.json','["長江飛鳥外，主簿跨驢歸。逐客寒前夜，元戎予厚衣。", "雪來松更綠，霜降月彌輝。即日調殷鼎，朝分是與非。"]'),
('yuding-15','送金州鑒周上人','賈島','唐','御定全唐诗','yuding','','[]','地必尋天目，溪仍住若耶。帆隨風便發，月不要雲遮。',48,'御定全唐詩/json/573.json','["地必尋天目，溪仍住若耶。帆隨風便發，月不要雲遮。", "極浦浮霜雁，回潮落海查。峨嵋省春上，立雪指流沙。"]'),
('yuding-16','送譚遠上人','賈島','唐','御定全唐诗','yuding','','[]','下視白雲時，山房蓋樹皮。垂枝松落子，側頂鶴聽棋。',48,'御定全唐詩/json/573.json','["下視白雲時，山房蓋樹皮。垂枝松落子，側頂鶴聽棋。", "清淨從沙劫，中終未日欹。金光明本行，同侍出峨嵋。"]'),
('yuding-17','新年','賈島','唐','御定全唐诗','yuding','','[]','嗟以龍鍾身，如何歲複新。石門思隱久，銅鏡強窺頻。',48,'御定全唐詩/json/573.json','["嗟以龍鍾身，如何歲複新。石門思隱久，銅鏡強窺頻。", "花發新移樹，心知故國春。誰能平此恨，豈是北宗人。"]'),
('yuding-18','送僧','賈島','唐','御定全唐诗','yuding','','[]','出家從丱歲，解論造玄門。不惜揮談柄，誰能聽至言。',48,'御定全唐詩/json/573.json','["出家從丱歲，解論造玄門。不惜揮談柄，誰能聽至言。", "中時山果熟，後夏竹陰繁。此去逢何日，峨嵋曉複昏。"]'),
('yuding-19','送姚杭州','賈島','唐','御定全唐诗','yuding','','[]','白雲峰下城，日夕白雲生。人老江波釣，田侵海樹耕。',48,'御定全唐詩/json/573.json','["白雲峰下城，日夕白雲生。人老江波釣，田侵海樹耕。", "吳山鐘入越，蓮葉吹搖旌。詩異石門思，濤來向越迎。"]'),
('yuding-20','夜集田卿宅','賈島','唐','御定全唐诗','yuding','','[]','朗詠高齋下，如將古調彈。翻鴻向桂水，來雪渡桑幹。',48,'御定全唐詩/json/573.json','["朗詠高齋下，如將古調彈。翻鴻向桂水，來雪渡桑幹。", "滴滴玉漏曙，翛翛竹籟殘。曩年曾宿此，亦值五陵寒。"]'),
('yuding-21','寄山友長孫棲嶠','賈島','唐','御定全唐诗','yuding','','[]','此時氣蕭颯，琴院可應關。鶴似君無事，風吹雨遍山。',48,'御定全唐詩/json/573.json','["此時氣蕭颯，琴院可應關。鶴似君無事，風吹雨遍山。", "松生青石上，泉落白雲間。有徑連高頂，心期相與還。"]'),
('yuding-22','酬厲玄','賈島','唐','御定全唐诗','yuding','','[]','我來從北鄙，子省涉西陵。白髮初相識，秋山擬共登。',48,'御定全唐詩/json/573.json','["我來從北鄙，子省涉西陵。白髮初相識，秋山擬共登。", "鄰居帝城雨，會宿禦溝冰。未報見貽作，耿然中夜興。"]'),
('yuding-23','送劉式洛中覲省','賈島','唐','御定全唐诗','yuding','','[]','晴峰三十六，侍立上春台。同宿別離恨，共看星月回。',48,'御定全唐詩/json/573.json','["晴峰三十六，侍立上春台。同宿別離恨，共看星月回。", "野鶯臨苑語，河棹曆江來。便寄相思劄，緘封花下開。"]'),
('yuding-24','送空公往金州','賈島','唐','御定全唐诗','yuding','','[]','七百里山水，手中楖栗粗。松生師坐石，潭滌祖傳盂。',48,'御定全唐詩/json/573.json','["七百里山水，手中楖栗粗。松生師坐石，潭滌祖傳盂。", "長擬老嶽嶠，又聞思海湖。惠能同俗姓，不是嶺南盧。"]'),
('yuding-25','贈紹明上人','賈島','唐','御定全唐诗','yuding','','[]','未住青雲室，中秋獨往年。上方嵩若寺，下視雨和煙。',48,'御定全唐詩/json/573.json','["未住青雲室，中秋獨往年。上方嵩若寺，下視雨和煙。", "祖豈無言去，心因斷臂傳。不知能已後，更有幾燈然。"]'),
('yuding-26','贈弘泉上人','賈島','唐','御定全唐诗','yuding','','[]','洗足下藍嶺，古師精進同。心知溪卉長，居此玉林空。',48,'御定全唐詩/json/573.json','["洗足下藍嶺，古師精進同。心知溪卉長，居此玉林空。", "西殿宵燈磬，東林曙雨風。舊峰鄰太白，石座雨苔蒙。"]'),
('yuding-27','送宣皎上人游太白','賈島','唐','御定全唐诗','yuding','','[]','剃髮鬢無雪，去年三十三。山過春草寺，磬度落花潭。',48,'御定全唐詩/json/573.json','["剃髮鬢無雪，去年三十三。山過春草寺，磬度落花潭。", "得句才鄰約，論宗意在南。峰靈疑懶下，蒼翠太虛參。"]'),
('yuding-28','病起','賈島','唐','御定全唐诗','yuding','','[]','高丘歸未得，空自責遲回。身事豈能遂，蘭花又已開。',48,'御定全唐詩/json/573.json','["高丘歸未得，空自責遲回。身事豈能遂，蘭花又已開。", "病令新作少，雨阻故人來。燈下南華卷，袪愁當酒杯。"]'),
('yuding-29','送殷侍禦赴同州','賈島','唐','御定全唐诗','yuding','','[]','馮翊蒲西郡，沙岡擁地形。中條全離嶽，清渭半和涇。',48,'御定全唐詩/json/573.json','["馮翊蒲西郡，沙岡擁地形。中條全離嶽，清渭半和涇。", "夜暮眠明月，秋深至洞庭。猶來交辟士，事別偃林扃。"]'),
('yuding-30','送沈鶴','賈島','唐','御定全唐诗','yuding','','[]','家楚婿于秦，攜妻雲養親。陸行千裏外，風卷一帆新。',48,'御定全唐詩/json/573.json','["家楚婿于秦，攜妻雲養親。陸行千裏外，風卷一帆新。", "夜泊疏山雨，秋吟搗藥輪。蕪城登眺作，才動廣陵人。"]'),
('yuding-31','秋夜仰懷錢孟二公琴客會','賈島','唐','御定全唐诗','yuding','','[]','月色四時好，秋光君子知。南山昨夜雨，為我寫清規。',48,'御定全唐詩/json/573.json','["月色四時好，秋光君子知。南山昨夜雨，為我寫清規。", "獨鶴聳寒骨，高杉韻細颸。仙家縹緲弄，仿佛此中期。"]'),
('yuding-32','贈李金州','賈島','唐','御定全唐诗','yuding','','[]','綺裏祠前後，山程踐白雲。溯流隨大旆，登岸見全軍。',48,'御定全唐詩/json/573.json','["綺裏祠前後，山程踐白雲。溯流隨大旆，登岸見全軍。", "曉角吹人夢，秋風卷雁群。霧開方露日，漢水底沙分。"]'),
('yuding-33','酬姚合校書','賈島','唐','御定全唐诗','yuding','','[]','因貧行遠道，得見舊交遊。美酒易傾盡，好詩難卒酬。',48,'御定全唐詩/json/573.json','["因貧行遠道，得見舊交遊。美酒易傾盡，好詩難卒酬。", "公堂朝共到，私第夜相留。不覺入關晚，別來林木秋。"]'),
('yuding-34','送獨孤馬二秀才居明月山讀書','賈島','唐','御定全唐诗','yuding','','[]','濯志俱高潔，儒科慕冉顏。家辭臨水郡，雨到讀書山。',48,'御定全唐詩/json/573.json','["濯志俱高潔，儒科慕冉顏。家辭臨水郡，雨到讀書山。", "棲鳥棕花上，聲鐘礫閣間。寂寥窗戶外，時見一舟還。"]'),
('yuding-35','病蟬','賈島','唐','御定全唐诗','yuding','','[]','病蟬飛不得，向我掌中行。拆翼猶能薄，酸吟尚極清。',48,'御定全唐詩/json/573.json','["病蟬飛不得，向我掌中行。拆翼猶能薄，酸吟尚極清。", "露華凝在腹，塵點誤侵睛。黃雀並鳶鳥，俱懷害爾情。"]'),
('yuding-36','青門裏作','賈島','唐','御定全唐诗','yuding','','[]','燕存鴻已過，海內幾人愁。欲問南宗理，將歸北嶽修。',48,'御定全唐詩/json/573.json','["燕存鴻已過，海內幾人愁。欲問南宗理，將歸北嶽修。", "若無攀桂分，只是臥雲休。泉樹一為別，依稀三十秋。"]'),
('yuding-37','盧秀才南台','賈島','唐','御定全唐诗','yuding','','[]','居在青門裏，台當千萬岑。下因岡助勢，上有樹交陰。',48,'御定全唐詩/json/573.json','["居在青門裏，台當千萬岑。下因岡助勢，上有樹交陰。", "陵遠根才近，空長畔可尋。新晴登嘯處，驚起宿枝禽。"]'),
('yuding-38','寄李輈侍郎','賈島','唐','御定全唐诗','yuding','','[]','終過盟津書，分明夢不虛。人從清渭別，地隔太行餘。',144,'御定全唐詩/json/573.json','["終過盟津書，分明夢不虛。人從清渭別，地隔太行餘。", "賓幕誰嫌靜，公門但晏如。櫑鞞幹霹靂，斜漢濕蟾蜍。", "追琢垂今後，敦龐得古初。井臺憐操築，漳岸想丕疏。", "亦翼鏗瑉佩，終當直石渠。此身多抱疾，幽裏近營居。", "憶漱蘇門澗，經浮楚澤瀦。松栽侵古影，葷斷尚芹菹。", "語嘿曾延接，心源離滓淤。誰言姓琴氏，獨跨角生魚。"]'),
('yuding-39','寄令狐綯相公','賈島','唐','御定全唐诗','yuding','','[]','驢駿勝羸馬，東川路匪賒。一緘論賈誼，三蜀寄嚴家。',144,'御定全唐詩/json/573.json','["驢駿勝羸馬，東川路匪賒。一緘論賈誼，三蜀寄嚴家。", "澄澈霜江水，分明露石沙。話言聲及政，棧閣穀離斜。", "自著衣偏暖，誰憂雪六花。裹裳留闊襆，防患與通茶。", "山館中宵起，星河殘月華。雙僮前日雇，數口向天涯。", "良樂知騏驥，張雷驗鏌鋣。謙光賢將相，別紙聖龍蛇。", "豈有斯言玷，應無白璧瑕。不妨圓魄裏，人亦指蝦蟆。"]'),
('yuding-40','再投李益常侍','賈島','唐','御定全唐诗','yuding','','[]','何處初投刺，當時赴尹京。淹留花柳變，然諾肺腸傾。',72,'御定全唐詩/json/573.json','["何處初投刺，當時赴尹京。淹留花柳變，然諾肺腸傾。", "避暑蟬移樹，高眠雁過城。人家嵩嶽色，公府洛河聲。", "聯句逢秋盡，嘗茶見月生。新衣裁白苧，思從曲江行。"]'),
('yuding-41','積雪','賈島','唐','御定全唐诗','yuding','','[]','昔屬時霖滯，今逢臘雪多。南猜飄桂渚，北訝雨交河。',84,'御定全唐詩/json/573.json','["昔屬時霖滯，今逢臘雪多。南猜飄桂渚，北訝雨交河。", "盡滅平蕪色，彌重古木柯。空中離白氣，島外下滄波。", "隱者迷樵道，朝人冷玉珂。夕繁仍晝密，漏間複鐘和。", "想積高嵩頂，新秋皎月過。"]'),
('yuding-42','過楊道士居','賈島','唐','御定全唐诗','yuding','','[]','先生修道處，茆屋遠囂氛。叩齒坐明月，支頤望白雲。',48,'御定全唐詩/json/573.json','["先生修道處，茆屋遠囂氛。叩齒坐明月，支頤望白雲。", "精神含藥色，衣服帶霞紋。無話瀛洲路，多年別少君。"]'),
('yuding-43','贈僧','賈島','唐','御定全唐诗','yuding','','[]','亂山秋木穴，裏有靈蛇藏。鐵錫掛臨海，石樓聞異香。',48,'御定全唐詩/json/573.json','["亂山秋木穴，裏有靈蛇藏。鐵錫掛臨海，石樓聞異香。", "出塵頭未白，入定衲凝霜。莫話五湖事，令人心欲狂。"]'),
('yuding-44','送友人游塞','賈島','唐','御定全唐诗','yuding','','[]','飄蓬多塞下，君見益潸然。迥磧沙銜日，長河水接天。',48,'御定全唐詩/json/573.json','["飄蓬多塞下，君見益潸然。迥磧沙銜日，長河水接天。", "夜泉行客火，曉戍向京煙。少結相思恨，佳期芳草前。"]'),
('yuding-45','思游邊友人','賈島','唐','御定全唐诗','yuding','','[]','凝愁對孤燭，昨日飲離杯。葉下故人去，天中新雁來。',48,'御定全唐詩/json/573.json','["凝愁對孤燭，昨日飲離杯。葉下故人去，天中新雁來。", "連沙秋草薄，帶雪暮山開。苑北紅塵道，何時見遠回。"]'),
('yuding-46','秋暮寄友人','賈島','唐','御定全唐诗','yuding','','[]','寥落關河暮，霜風樹葉低。遠天垂地外，寒日下峰西。',48,'御定全唐詩/json/573.json','["寥落關河暮，霜風樹葉低。遠天垂地外，寒日下峰西。", "有志煙霞切，無家歲月迷。清宵話白閣，已負十年棲。"]'),
('yuding-47','寄令狐綯相公','賈島','唐','御定全唐诗','yuding','','[]','官高頻敕授，老免把犁鋤。一主長江印，三封東省書。',48,'御定全唐詩/json/573.json','["官高頻敕授，老免把犁鋤。一主長江印，三封東省書。", "不無濠上思，唯食圃中蔬。夢幻將泡影，浮生事只如。"]'),
('yuding-48','和孟逸人林下道情','賈島','唐','御定全唐诗','yuding','','[]','四氣相陶鑄，中庸道豈銷。夏雲生此日，春色盡今朝。',48,'御定全唐詩/json/573.json','["四氣相陶鑄，中庸道豈銷。夏雲生此日，春色盡今朝。", "陋巷貧無悶，毗耶疾未調。已栽天末柏，合抱豈非遙。"]'),
('yuding-49','宿姚少府北齋','賈島','唐','御定全唐诗','yuding','','[]','石溪同夜泛，複此北齋期。鳥絕吏歸後，蛩鳴客臥時。',48,'御定全唐詩/json/573.json','["石溪同夜泛，複此北齋期。鳥絕吏歸後，蛩鳴客臥時。", "鎖城涼雨細，開印曙鐘遲。憶此漳川岸，如今是別離。"]'),
('yuding-50','雪晴晚望','賈島','唐','御定全唐诗','yuding','','[]','倚杖望晴雪，溪雲幾萬重。樵人歸白屋，寒日下危峰。',48,'御定全唐詩/json/573.json','["倚杖望晴雪，溪雲幾萬重。樵人歸白屋，寒日下危峰。", "野火燒岡草，斷煙生石鬆。卻回山寺路，聞打暮天鐘。"]'),
('yuding-51','送崔嶠遊瀟湘','賈島','唐','御定全唐诗','yuding','','[]','功烈尚書孫，琢磨風雅言。渡河山鑿處，陟峴漢灘喧。',48,'御定全唐詩/json/573.json','["功烈尚書孫，琢磨風雅言。渡河山鑿處，陟峴漢灘喧。", "夢想吟天目，宵同話石門。楓林葉欲下，極浦月清暾。"]'),
('yuding-52','寄朱錫珪','賈島','唐','御定全唐诗','yuding','','[]','遠泊與誰同，來從古木中。長江人釣月，曠野火燒風。',48,'御定全唐詩/json/573.json','["遠泊與誰同，來從古木中。長江人釣月，曠野火燒風。", "夢澤吞楚大，閩山厄海叢。此時檣底水，濤起屈原通。"]'),
('yuding-53','馬戴居華山因寄','賈島','唐','御定全唐诗','yuding','','[]','玉女洗頭盆，孤高不可言。瀑流蓮嶽頂，河注華山根。',48,'御定全唐詩/json/573.json','["玉女洗頭盆，孤高不可言。瀑流蓮嶽頂，河注華山根。", "絕雀林藏鶻，無人境有猿。秋蟾才過雨，石上古松門。"]'),
('yuding-54','寄胡遇','賈島','唐','御定全唐诗','yuding','','[]','一自殘春別，經炎複到涼。螢從枯樹出，蛩入破階藏。',48,'御定全唐詩/json/573.json','["一自殘春別，經炎複到涼。螢從枯樹出，蛩入破階藏。", "落葉書勝紙，閑砧坐當床。東門因送客，相訪也何妨。"]'),
('yuding-55','送李戎扶侍往壽安','賈島','唐','御定全唐诗','yuding','','[]','二千餘裏路，一半是波濤。未曉著衣起，出城逢日高。',48,'御定全唐詩/json/573.json','["二千餘裏路，一半是波濤。未曉著衣起，出城逢日高。", "關山多寇盜，扶侍帶弓刀。臨別不揮淚，誰知心郁陶。"]'),
('yuding-56','送孫逸人','賈島','唐','御定全唐诗','yuding','','[]','衣屢猶同俗，妻兒亦宛然。不餐能累月，無病已多年。',48,'御定全唐詩/json/573.json','["衣屢猶同俗，妻兒亦宛然。不餐能累月，無病已多年。", "是藥皆諳性，令人漸信仙。杖頭書數卷，荷入翠微煙。"]'),
('yuding-57','寄華山僧','賈島','唐','御定全唐诗','yuding','','[]','遙知白石室，松柏隱朦朧。月落看心次，雲生閉目中。',48,'御定全唐詩/json/573.json','["遙知白石室，松柏隱朦朧。月落看心次，雲生閉目中。", "五更鐘隔岳，萬尺水懸空。苔蘚嵌岩所，依稀有徑通。"]'),
('yuding-58','送李登少府','賈島','唐','御定全唐诗','yuding','','[]','伊陽耽酒尉，朗詠醉醒新。應見嵩山裏，明年躑躅春。',48,'御定全唐詩/json/573.json','["伊陽耽酒尉，朗詠醉醒新。應見嵩山裏，明年躑躅春。", "一千尋樹直，三十六峰鄰。流水潺潺處，堅貞玉澗瑉。"]'),
('yuding-59','易州過郝逸人居','賈島','唐','御定全唐诗','yuding','','[]','每逢詞翰客，邀我共尋君。果見閒居賦，未曾流俗聞。',48,'御定全唐詩/json/573.json','["每逢詞翰客，邀我共尋君。果見閒居賦，未曾流俗聞。", "也知鄰市井，宛似出囂氛。卻笑巢由輩，何須隱白雲。"]'),
('yuding-60','酬鄠縣李廓少府見寄','賈島','唐','御定全唐诗','yuding','','[]','稍憐公事退，複遇夕陽時。北朔霜凝竹，南山水入籬。',48,'御定全唐詩/json/573.json','["稍憐公事退，複遇夕陽時。北朔霜凝竹，南山水入籬。", "吟懷滄海侶，空問白雲師。恨不相從去，心惟野鶴知。"]'),
('yuding-61','淨業寺與前鄠縣李廓少府同宿','賈島','唐','御定全唐诗','yuding','','[]','來從城上峰，京寺暮相逢。往往語複默，微微雨灑松。',48,'御定全唐詩/json/573.json','["來從城上峰，京寺暮相逢。往往語複默，微微雨灑松。", "家貧初罷吏，年長畏聞蛩。前日猶拘束，披衣起曉鐘。"]'),
('yuding-62','送南卓歸京','賈島','唐','御定全唐诗','yuding','','[]','殘春別鏡陂，罷郡未霜髭。行李逢炎暑，山泉滿路岐。',72,'御定全唐詩/json/573.json','["殘春別鏡陂，罷郡未霜髭。行李逢炎暑，山泉滿路岐。", "雲藏巢鶴樹，風觸囀鶯枝。三省同虛位，雙旌帶去思。", "入城宵夢後，待漏月沉時。長策並忠告，從容寫玉墀。"]'),
('yuding-63','臥疾走筆酬韓愈書問','賈島','唐','御定全唐诗','yuding','','[]','一臥三四旬，數書惟獨君。願為出海月，不作歸山雲。',48,'御定全唐詩/json/573.json','["一臥三四旬，數書惟獨君。願為出海月，不作歸山雲。", "身上衣頻寄，甌中物亦分。欲知強健否，病鶴未離群。"]'),
('yuding-64','長孫霞李溟自紫閣白閣二峰見訪','賈島','唐','御定全唐诗','yuding','','[]','寂寞吾廬貧，同來二閣人。所論唯野事，招作住雲鄰。',48,'御定全唐詩/json/573.json','["寂寞吾廬貧，同來二閣人。所論唯野事，招作住雲鄰。", "古寺期秋宿，平林散早春。漱流今已矣，巢許豈堯臣。"]'),
('yuding-65','送惟一遊清涼寺','賈島','唐','御定全唐诗','yuding','','[]','去有巡台侶，荒溪眾樹分。瓶殘秦地水，錫入晉山雲。',48,'御定全唐詩/json/573.json','["去有巡台侶，荒溪眾樹分。瓶殘秦地水，錫入晉山雲。", "秋月離喧見，寒泉出定聞。人間臨欲別，旬日雨紛紛。"]'),
('yuding-66','鄭尚書新開涪江二首','賈島','唐','御定全唐诗','yuding','','[]','岸鑿青山破，江開白浪寒。日沉源出海，春至草生灘。',96,'御定全唐詩/json/573.json','["岸鑿青山破，江開白浪寒。日沉源出海，春至草生灘。", "梓匠防波溢，蓬仙畏水幹。從今疏決後，任雨滯峰巒。", "不侵南畝務，已拔北江流。涪水方移岸，潯陽有到舟。", "潭澄初搗藥，波動乍垂鉤。山可疏三裏，從知曆億秋。"]'),
('yuding-67','寄喬侍郎','賈島','唐','御定全唐诗','yuding','','[]','大寧猶未到，曾渡北浮橋。曉出爬船寺，手擎紫栗條。',48,'御定全唐詩/json/573.json','["大寧猶未到，曾渡北浮橋。曉出爬船寺，手擎紫栗條。", "差池不相見，悵望至今朝。近日營家計，繩懸一小瓢。"]'),
('yuding-68','送去華法師','賈島','唐','御定全唐诗','yuding','','[]','在越居何寺，東南水路歸。秋江洗一缽，寒日曬三衣。',48,'御定全唐詩/json/573.json','["在越居何寺，東南水路歸。秋江洗一缽，寒日曬三衣。", "默聽鴻聲盡，行看葉影飛。囊中無寶貨，船戶夜扃稀。"]'),
('yuding-69','送蔡京','賈島','唐','御定全唐诗','yuding','','[]','躍蹄歸魯日，帶漏別秦星。易折芳條桂，難窮邃義經。',48,'御定全唐詩/json/573.json','["躍蹄歸魯日，帶漏別秦星。易折芳條桂，難窮邃義經。", "登封多泰嶽，巡狩遍滄溟。家在何林下，梁山翠滿庭。"]'),
('yuding-70','慈恩寺上座院','賈島','唐','御定全唐诗','yuding','','[]','未委衡山色，何如對塔峰。曩宵曾宿此，今夕值秋濃。',48,'御定全唐詩/json/573.json','["未委衡山色，何如對塔峰。曩宵曾宿此，今夕值秋濃。", "羽族棲煙竹，寒流帶月鐘。井甘源起異，泉湧漬苔封。"]'),
('yuding-71','題朱慶餘所居','賈島','唐','御定全唐诗','yuding','','[]','天寒吟竟曉，古屋瓦生松。寄信船一隻，隔鄉山萬重。',48,'御定全唐詩/json/573.json','["天寒吟竟曉，古屋瓦生松。寄信船一隻，隔鄉山萬重。", "樹來沙岸鳥，窗度雪樓鐘。每憶江中嶼，更看城上峰。"]'),
('yuding-72','送黃知新歸安南','賈島','唐','御定全唐诗','yuding','','[]','池亭沉飲遍，非獨曲江花。地遠路穿海，春歸冬到家。',48,'御定全唐詩/json/573.json','["池亭沉飲遍，非獨曲江花。地遠路穿海，春歸冬到家。", "火山難下雪，瘴土不生茶。知決移來計，相逢期尚賒。"]'),
('yuding-73','贈胡禪歸','賈島','唐','御定全唐诗','yuding','','[]','自是根機鈍，非關夏臘深。秋來江上寺，夜坐嶺南心。',48,'御定全唐詩/json/573.json','["自是根機鈍，非關夏臘深。秋來江上寺，夜坐嶺南心。", "井鑿山含月，風吹磬出林。祖師攜只履，去路杳難尋。"]'),
('yuding-74','元日女道士受籙','賈島','唐','御定全唐诗','yuding','','[]','元日更新夜，齋身稱淨衣。數星連鬥出，萬里斷雲飛。',48,'御定全唐詩/json/573.json','["元日更新夜，齋身稱淨衣。數星連鬥出，萬里斷雲飛。", "霜下磬聲在，月高壇影微。立聽師語了，左肘系符歸。"]'),
('yuding-75','重與彭兵曹','賈島','唐','御定全唐诗','yuding','','[]','故人在城裏，休寄海邊書。漸去老不遠，別來情豈疏。',48,'御定全唐詩/json/573.json','["故人在城裏，休寄海邊書。漸去老不遠，別來情豈疏。", "硯冰催臘日，山雀到貧居。每有平戎計，官家別敕除。"]'),
('yuding-76','贈莊上人','賈島','唐','御定全唐诗','yuding','','[]','不語焚香坐，心知道已成。流年衰此世，定力見他生。',48,'御定全唐詩/json/573.json','["不語焚香坐，心知道已成。流年衰此世，定力見他生。", "暮雪餘春冷，寒燈續晝明。尋常五侯至，敢望下階迎。"]'),
('yuding-77','落第東歸逢僧伯陽','賈島','唐','御定全唐诗','yuding','','[]','相逢須語笑，人世別離頻。曉至長侵月，思鄉動隔春。',96,'御定全唐詩/json/573.json','["相逢須語笑，人世別離頻。曉至長侵月，思鄉動隔春。", "見僧心暫靜，從俗事多迍。宇宙詩名小，山河客路新。", "翠桐猶入爨，清鏡未辭塵。逸足思奔驥，隨群且退鱗。", "宴乖紅杏寺，愁在綠楊津。老病難為樂，開眉賴故人。"]'),
('yuding-78','皇甫主簿期遊山不及赴','賈島','唐','御定全唐诗','yuding','','[]','休官匹馬在，新意入山中。更住應難遂，前期恨不同。',48,'御定全唐詩/json/573.json','["休官匹馬在，新意入山中。更住應難遂，前期恨不同。", "集蟬苔樹僻，留客雨堂空。深夜誰相訪，惟當清淨翁。"]'),
('yuding-79','宿成湘林下','賈島','唐','御定全唐诗','yuding','','[]','相訪夕陽時，千株木未衰。石泉流出穀，山雨滴棲鴟。',48,'御定全唐詩/json/573.json','["相訪夕陽時，千株木未衰。石泉流出穀，山雨滴棲鴟。", "漏向燈聽數，酒因客寢遲。今宵不盡興，更有月明期。"]'),
('yuding-80','喜雍陶至','賈島','唐','御定全唐诗','yuding','','[]','今朝笑語同，幾日百憂中。鳥度劍門靜，蠻歸瀘水空。',48,'御定全唐詩/json/573.json','["今朝笑語同，幾日百憂中。鳥度劍門靜，蠻歸瀘水空。", "步霜吟菊畔，待月坐林東。且莫孤此興，勿論窮與通。"]'),
('yuding-81','酬胡遇','賈島','唐','御定全唐诗','yuding','','[]','麗句傳人口，科名立可圖。移居見山燒，買樹帶巢烏。',48,'御定全唐詩/json/573.json','["麗句傳人口，科名立可圖。移居見山燒，買樹帶巢烏。", "遊遠風濤急，吟清雪月孤。卻思初識面，仍未有多須。"]'),
('yuding-82','宿慈恩寺郁公房','賈島','唐','御定全唐诗','yuding','','[]','病身來寄宿，自掃一床閑。反照臨江磬，新秋過雨山。',48,'御定全唐詩/json/573.json','["病身來寄宿，自掃一床閑。反照臨江磬，新秋過雨山。", "竹陰移冷月，荷氣帶禪關。獨住天臺意，方從內請還。"]'),
('yuding-83','送褚山人歸日本','賈島','唐','御定全唐诗','yuding','','[]','懸帆待秋水，去入杳冥間。東海幾年別，中華此日還。',48,'御定全唐詩/json/573.json','["懸帆待秋水，去入杳冥間。東海幾年別，中華此日還。", "岸遙生白髮，波盡露青山。隔水相思在，無書也是閑。"]'),
('yuding-84','寄韓湘','賈島','唐','御定全唐诗','yuding','','[]','過嶺行多少，潮州漲滿川。花開南去後，水凍北歸前。',48,'御定全唐詩/json/573.json','["過嶺行多少，潮州漲滿川。花開南去後，水凍北歸前。", "望鷺吟登閣，聽猿淚滴船。相思堪面話，不著尺書傳。"]'),
('yuding-85','雨夜寄馬戴','賈島','唐','御定全唐诗','yuding','','[]','芳林杏花樹，花落子西東。今夕曲江雨，寒催朔北風。',48,'御定全唐詩/json/573.json','["芳林杏花樹，花落子西東。今夕曲江雨，寒催朔北風。", "鄉書滄海絕，隱路翠微通。寂寂相思際，孤釭殘漏中。"]'),
('yuding-86','喜無可上人遊山回','賈島','唐','御定全唐诗','yuding','','[]','一食複何如，尋山無定居。相逢新夏滿，不見半年餘。',48,'御定全唐詩/json/573.json','["一食複何如，尋山無定居。相逢新夏滿，不見半年餘。", "聽話龍潭雪，休傳鳥道書。別來還似舊，白髮日高梳。"]'),
('yuding-87','寄毗陵徹公','賈島','唐','御定全唐诗','yuding','','[]','身依吳寺老，黃葉幾回看。早講林霜在，孤禪隙月殘。',48,'御定全唐詩/json/573.json','["身依吳寺老，黃葉幾回看。早講林霜在，孤禪隙月殘。", "井通潮浪遠，鐘與角聲寒。已有南遊約，誰言禮謁難。"]'),
('yuding-88','送韋瓊校書','賈島','唐','御定全唐诗','yuding','','[]','賓佐兼歸覲，此行江漢心。別離從闕下，道路向山陰。',48,'御定全唐詩/json/573.json','["賓佐兼歸覲，此行江漢心。別離從闕下，道路向山陰。", "孤嶼消寒沫，空城滴夜霖。若邪溪畔寺，秋色共誰尋。"]'),
('yuding-89','寄劉侍禦','賈島','唐','御定全唐诗','yuding','','[]','衣多苔蘚痕，猶擬更趨門。自夏雖無病，經秋不過原。',48,'御定全唐詩/json/573.json','["衣多苔蘚痕，猶擬更趨門。自夏雖無病，經秋不過原。", "積泉留岱鳥，疊岫隔巴猿。琴月西齋集，如今豈複言。"]'),
('yuding-90','送穆少府知眉州','賈島','唐','御定全唐诗','yuding','','[]','劍門倚青漢，君昔未曾過。日暮行人少，山深異鳥多。',48,'御定全唐詩/json/573.json','["劍門倚青漢，君昔未曾過。日暮行人少，山深異鳥多。", "猿啼和峽雨，棧盡到江波。一路白雲裏，飛泉灑薜蘿。"]'),
('yuding-91','二月晦日留別鄠中友人','賈島','唐','御定全唐诗','yuding','','[]','立馬柳花裏，別君當酒酣。春風漸向北，雲雁不飛南。',48,'御定全唐詩/json/573.json','["立馬柳花裏，別君當酒酣。春風漸向北，雲雁不飛南。", "明曉日初一，今年月又三。鞭羸去暮色，遠嶽起煙嵐。"]'),
('yuding-92','送李校書赴吉期','賈島','唐','御定全唐诗','yuding','','[]','筮算重重吉，良期詎可遷。不同牛女夜，是配鳳凰年。',48,'御定全唐詩/json/573.json','["筮算重重吉，良期詎可遷。不同牛女夜，是配鳳凰年。", "佩玉春風裏，題章蠟燭前。詩書與箴訓，夫哲又妻賢。"]'),
('yuding-93','宿孤館','賈島','唐','御定全唐诗','yuding','','[]','落日投村戍，愁生為客途。寒山晴後綠，秋月夜來孤。',48,'御定全唐詩/json/573.json','["落日投村戍，愁生為客途。寒山晴後綠，秋月夜來孤。", "橘樹千株在，漁家一半無。自知風水靜，舟系岸邊蘆。"]'),
('yuding-94','哭宗密禪師','賈島','唐','御定全唐诗','yuding','','[]','鳥道雪岑巔，師亡誰去禪。幾塵增滅後，樹色改生前。',48,'御定全唐詩/json/573.json','["鳥道雪岑巔，師亡誰去禪。幾塵增滅後，樹色改生前。", "層塔當松吹，殘蹤傍野泉。唯嗟聽經虎，時到壞庵邊。"]'),
('yuding-95','宿山寺','賈島','唐','御定全唐诗','yuding','','[]','眾岫聳寒色，精廬向此分。流星透疏木，走月逆行雲。',48,'御定全唐詩/json/573.json','["眾岫聳寒色，精廬向此分。流星透疏木，走月逆行雲。", "絕頂人來少，高松鶴不群。一僧年八十，世事未曾聞。"]'),
('yuding-96','送友人如邊','賈島','唐','御定全唐诗','yuding','','[]','去日重陽後，前程菊正芳。行車輾秋嶽，落葉墜寒霜。',48,'御定全唐詩/json/573.json','["去日重陽後，前程菊正芳。行車輾秋嶽，落葉墜寒霜。", "雲入漢天白，風高磧色黃。蒲輪待恐晚，求薦向諸方。"]'),
('yuding-97','題竹谷上人院','賈島','唐','御定全唐诗','yuding','','[]','禪庭高鳥道，回望極川原。樵徑連峰頂，石泉通竹根。',48,'御定全唐詩/json/573.json','["禪庭高鳥道，回望極川原。樵徑連峰頂，石泉通竹根。", "木深猶積雪，山淺未聞猿。欲別塵中苦，願師貽一言。"]'),
('yuding-98','京北原作','賈島','唐','御定全唐诗','yuding','','[]','登原見城闕，策蹇思炎天。日午路中客，槐花風處蟬。',48,'御定全唐詩/json/573.json','["登原見城闕，策蹇思炎天。日午路中客，槐花風處蟬。", "遠山秦木上，清渭漢陵前。何事居人世，皆從名利牽。"]'),
('yuding-99','寄江上人','賈島','唐','御定全唐诗','yuding','','[]','紫閣舊房在，新家中嶽東。煙波千里隔，消息一朝通。',48,'御定全唐詩/json/573.json','["紫閣舊房在，新家中嶽東。煙波千里隔，消息一朝通。", "寒日汀洲路，秋晴島嶼風。分明杜陵葉，別後兩經紅。"]'),
('yuding-100','送僧歸太白山','賈島','唐','御定全唐诗','yuding','','[]','堅冰連夏處，太白接青天。雲塞石房路，峰明雨外巔。',48,'御定全唐詩/json/573.json','["堅冰連夏處，太白接青天。雲塞石房路，峰明雨外巔。", "夜禪臨虎穴，寒漱撇龍泉。後會不期日，相逢應信緣。"]'),
('yuding-101','暮過山村','賈島','唐','御定全唐诗','yuding','','[]','數裏聞寒水，山家少四鄰。怪禽啼曠野，落日恐行人。',48,'御定全唐詩/json/573.json','["數裏聞寒水，山家少四鄰。怪禽啼曠野，落日恐行人。", "初月未終夕，邊烽不過秦。蕭條桑柘外，煙火漸相親。"]'),
('yuding-102','鷺鷥','賈島','唐','御定全唐诗','yuding','','[]','求魚未得食，沙岸往來行。島月獨棲影，暮天寒過聲。',48,'御定全唐詩/json/573.json','["求魚未得食，沙岸往來行。島月獨棲影，暮天寒過聲。", "墮巢因木折，失侶遇弦驚。頻向煙霄望，吾知爾去程。"]'),
('yuding-103','內道場僧弘紹','賈島','唐','御定全唐诗','yuding','','[]','麟德燃香請，長安春幾回。夜閑同像寂，晝定為吾開。',48,'御定全唐詩/json/573.json','["麟德燃香請，長安春幾回。夜閑同像寂，晝定為吾開。", "講罷松根老，經浮海水來。六年雙足履，只步院中苔。"]'),
('yuding-104','蔣亭和蔡湘州','賈島','唐','御定全唐诗','yuding','','[]','蔣宅為亭榭，蔡城東郭門。潭連秦相井，松老漢朝根。',48,'御定全唐詩/json/573.json','["蔣宅為亭榭，蔡城東郭門。潭連秦相井，松老漢朝根。", "已積蒼苔遍，何曾舊徑存。高齋無事後，時複一攜尊。"]'),
('yuding-105','光州王建使君水亭作','賈島','唐','御定全唐诗','yuding','','[]','楚水臨軒積，澄鮮一畝餘。柳根連岸盡，荷葉出萍初。',48,'御定全唐詩/json/573.json','["楚水臨軒積，澄鮮一畝餘。柳根連岸盡，荷葉出萍初。", "極浦清相似，幽禽到不虛。夕陽庭際眺，槐雨滴疏疏。"]'),
('yuding-106','留別光州王使君建','賈島','唐','御定全唐诗','yuding','','[]','杜陵千裏外，期在末秋歸。既見林花落，須防木葉飛。',48,'御定全唐詩/json/573.json','["杜陵千裏外，期在末秋歸。既見林花落，須防木葉飛。", "楚從何地盡，淮隔數峰微。回首餘霞失，斜陽照客衣。"]'),
('yuding-107','宿姚合宅寄張司業籍','賈島','唐','御定全唐诗','yuding','','[]','閑宵因集會，柱史話先生。身愛無一事，心期往四明。',48,'御定全唐詩/json/573.json','["閑宵因集會，柱史話先生。身愛無一事，心期往四明。", "松枝影搖動，石磬響寒清。誰伴南齋宿，月高霜滿城。"]'),
('yuding-108','哭張籍','賈島','唐','御定全唐诗','yuding','','[]','精靈歸恍惚，石磬韻曾聞。即日是前古，誰人耕此墳。',48,'御定全唐詩/json/573.json','["精靈歸恍惚，石磬韻曾聞。即日是前古，誰人耕此墳。", "舊遊孤棹遠，故域九江分。本欲蓬瀛去，餐芝禦白雲。"]'),
('yuding-109','靈准上人院','賈島','唐','御定全唐诗','yuding','','[]','掩扉當太白，臘數等松椿。禁漏來遙夜，山泉落近鄰。',48,'御定全唐詩/json/573.json','["掩扉當太白，臘數等松椿。禁漏來遙夜，山泉落近鄰。", "經聲終卷曉，草色幾芽春。海內知名士，交遊准上人。"]'),
('yuding-110','寄柳舍人宗元','賈島','唐','御定全唐诗','yuding','','[]','格與功俱造，何人意不降。一宵三夢柳，孤泊九秋江。',48,'御定全唐詩/json/573.json','["格與功俱造，何人意不降。一宵三夢柳，孤泊九秋江。", "擢第名重列，沖天字幾雙。誓為仙者僕，側執馭風幢。"]'),
('yuding-111','送玄岩上人歸西蜀','賈島','唐','御定全唐诗','yuding','','[]','玉壘山中寺，幽深勝概多。藥成彭祖搗，頂受七輪摩。',48,'御定全唐詩/json/573.json','["玉壘山中寺，幽深勝概多。藥成彭祖搗，頂受七輪摩。", "去臘催今夏，流光等逝波。會當依糞掃，五嶽遍頭陀。"]'),
('yuding-112','寄宋州田中丞','賈島','唐','御定全唐诗','yuding','','[]','古郡近南徐，關河萬里餘。相思深夜後，未答去秋書。',48,'御定全唐詩/json/573.json','["古郡近南徐，關河萬里餘。相思深夜後，未答去秋書。", "自別知音少，難忘識面初。舊山期已久，門掩數畦蔬。"]'),
('yuding-113','送朱休歸劍南','賈島','唐','御定全唐诗','yuding','','[]','劍南歸受賀，太學賦聲雄。山路長江岸，朝陽十月中。',48,'御定全唐詩/json/573.json','["劍南歸受賀，太學賦聲雄。山路長江岸，朝陽十月中。", "芽新抽雪茗，枝重集猿楓。卓氏琴台廢，深蕪想徑通。"]'),
('yuding-114','寄長武朱尚書','賈島','唐','御定全唐诗','yuding','','[]','不日即登壇，槍旗一萬竿。角吹邊月沒，鼓絕爆雷殘。',48,'御定全唐詩/json/573.json','["不日即登壇，槍旗一萬竿。角吹邊月沒，鼓絕爆雷殘。", "中國今如此，西荒可取難。白衣思請謁，徒步在長安。"]'),
('yuding-115','送皇甫侍禦','賈島','唐','御定全唐诗','yuding','','[]','曉鐘催早期，自是赴嘉招。舟泊湘江闊，田收楚澤遙。',48,'御定全唐詩/json/573.json','["曉鐘催早期，自是赴嘉招。舟泊湘江闊，田收楚澤遙。", "雁驚起衰草，猿渴下寒條。來使黔南日，時應問寂寥。"]'),
('yuding-116','郊居即事','賈島','唐','御定全唐诗','yuding','','[]','住此園林久，其如未是家。葉書傳野意，簷溜煮胡茶。',48,'御定全唐詩/json/573.json','["住此園林久，其如未是家。葉書傳野意，簷溜煮胡茶。", "雨後逢行鷺，更深聽遠蛙。自然還往裏，多是愛煙霞。"]'),
('yuding-117','夜集姚合宅期可公不至','賈島','唐','御定全唐诗','yuding','','[]','公堂秋雨夜，已是念園林。何事疾病日，重論山水心。',48,'御定全唐詩/json/573.json','["公堂秋雨夜，已是念園林。何事疾病日，重論山水心。", "孤燈明臘後，微雪下更深。釋子乖來約，泉西寒磬音。"]'),
('yuding-118','喜李餘自蜀至','賈島','唐','御定全唐诗','yuding','','[]','迢遞岷峨外，西南驛路高。幾程尋嶮棧，獨宿聽寒濤。',48,'御定全唐詩/json/573.json','["迢遞岷峨外，西南驛路高。幾程尋嶮棧，獨宿聽寒濤。", "白鳥飛還立，青猿斷更號。往來從此過，詞體近風騷。"]'),
('yuding-119','王侍禦南原莊','賈島','唐','御定全唐诗','yuding','','[]','買得足雲地，新栽藥數窠。峰頭盤一徑，原下注雙河。',48,'御定全唐詩/json/573.json','["買得足雲地，新栽藥數窠。峰頭盤一徑，原下注雙河。", "春寺閑眠久，晴台獨上多。南齋宿雨後，仍許重來麼。"]'),
('yuding-120','送康秀才','賈島','唐','御定全唐诗','yuding','','[]','俱為落第年，相識落花前。酒瀉兩三盞，詩吟十數篇。',48,'御定全唐詩/json/573.json','["俱為落第年，相識落花前。酒瀉兩三盞，詩吟十數篇。", "行岐逢塞雨，嘶馬上津船。樹影高堂下，回時應有蟬。"]');
